-- Poems batch 333
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1711665f-24db-41fb-86fd-48b8302abda7','竹枝詞二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','三峽猿聲淚欲流，夔州竹枝解人愁。',32,'全唐诗/poet.song.57000.json','["三峽猿聲淚欲流，夔州竹枝解人愁。", "渠儂自有回天力，不學垂楊繞指柔。"]'),
('89373aa2-26fa-4d99-8411-67c426a2af2f','竹枝詞二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','塞上柳枝且莫歌，夔州竹枝奈愁何。',32,'全唐诗/poet.song.57000.json','["塞上柳枝且莫歌，夔州竹枝奈愁何。", "虛心相待莫相誤，歲寒望君一來過。"]'),
('7462e76e-65dc-441c-81e1-44da8644a2c9','詠子舟小山叢竹','黄庭堅','宋','宋诗','song-poetry','','[]','病竹猶能冠叢，夏篁解籜匆匆。',28,'全唐诗/poet.song.57000.json','["病竹猶能冠叢，夏篁解籜匆匆。", "細草因依岑寂，小山紫翠嵌空。"]'),
('e08630b4-6fd9-4bcb-8066-0706a394b67d','次韵斌老冬至書懷示子舟篇末見及之作因以贈子舟歸','黄庭堅','宋','宋诗','song-poetry','','[]','二宗性清真，俱抱歲寒節。',180,'全唐诗/poet.song.57000.json','["二宗性清真，俱抱歲寒節。", "常思風雲會，爲國奮忠烈。", "道方滄波穨，位有豺虎竊。", "夫婦相魚肉，關中一丈雪。", "北風夜涔涔，竹枯松栢折。", "泰來拔茅連，井收寒泉冽。", "天地復其所，我輩皆慰愜。", "何爲對樽壺，似見小敵怯。", "大宗垂紫髯，貴氣已森列。", "小宗新換骨，健啗頗腴悅。", "昨宵連環夢，秣馬待明發。", "寒日一線長，把酒相喻說。", "人生但安樂，逢世無巧拙。", "斑衣戲親庭，不作經年別。", "猶有未歸心，遠寄丁香結。"]'),
('89a9a21f-2b65-4f8a-9f1a-3ed039865158','戲題斌老所作兩竹梢','黄庭堅','宋','宋诗','song-poetry','','[]','老竹帖妥不作奇，嫩篁翹翹動風枝。',32,'全唐诗/poet.song.57000.json','["老竹帖妥不作奇，嫩篁翹翹動風枝。", "是中有目世不知，吾宗落筆風煙隨。"]'),
('89b598e6-13bb-4751-8ea0-9906d3d5b2df','奉次斌老送癭木棋局八韵','黄庭堅','宋','宋诗','song-poetry','','[]','竘工運斤斧，蟠木破權奇。',96,'全唐诗/poet.song.57000.json','["竘工運斤斧，蟠木破權奇。", "離離稻田畦，日靜波文稀。", "居然有心作，箇是偶爾爲。", "正當合戰地，仍有曳尾龜。", "膠漆與顔色，金銅利關機。", "抱器心自許，成功世乃知。", "吾宗爲湔祓，枯木更生輝。", "背城儻借一，觀我凱旋歸。"]'),
('ef3e1eff-68c7-4524-b94e-9829e30933ce','題石恪畫機織圖','黄庭堅','宋','宋诗','song-poetry','','[]','荷鋤郎在田，行餉兒未返。',24,'全唐诗/poet.song.57000.json','["荷鋤郎在田，行餉兒未返。", "終日弄鳴機，恤緯不思遠。"]'),
('33e1e9c8-12c1-431e-a899-aadc715da022','以皮鞋底贈石推官三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','道人不凋琢，萬鏡自明己。',24,'全唐诗/poet.song.57000.json','["道人不凋琢，萬鏡自明己。", "願公勤此履，深徹法源底。"]'),
('9771953a-692a-4fe3-9c91-8ff0f8c71169','以皮鞋底贈石推官三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','毗盧足趺光，照耀世界海。',24,'全唐诗/poet.song.57000.json','["毗盧足趺光，照耀世界海。", "旋嵐黑風起，到岸得自在。"]'),
('1aad77e7-b5ce-49a7-80e2-5cbb52d59ffd','以皮鞋底贈石推官三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','鼻孔隨人走，日中忽見斗。',24,'全唐诗/poet.song.57000.json','["鼻孔隨人走，日中忽見斗。", "踏定太衝脈，壁上挂着口。"]'),
('6008c52c-7d7f-442a-b106-c902cbf81c3c','次韵錢德循鹿苑灘艤舟有作','黄庭堅','宋','宋诗','song-poetry','','[]','鹿苑灘頭秋月明，使君輟棹愛江清。',32,'全唐诗/poet.song.57000.json','["鹿苑灘頭秋月明，使君輟棹愛江清。", "塵埃一段思歸路，已聽荆州漁鼓鳴。"]'),
('a609f42a-2b93-44ba-8827-81ab77288f6e','范德孺須筆裒諸工佳者共成十枝分送','黄庭堅','宋','宋诗','song-poetry','','[]','臨池聞道學書成，已許家雞勝伯英。',32,'全唐诗/poet.song.57000.json','["臨池聞道學書成，已許家雞勝伯英。", "雪竹霜毛分一束，開包何異五侯鯖。"]'),
('176d3655-6301-49bb-81d8-bf2801f506d4','予去歲在長沙數與處度元實相從把酒自過嶺來不復有此樂感歎之餘戲成一絕','黄庭堅','宋','宋诗','song-poetry','','[]','玄霜搗盡音塵絕，去作湖南萬里春。',32,'全唐诗/poet.song.57000.json','["玄霜搗盡音塵絕，去作湖南萬里春。", "想見山川佳絕地，落花飛絮轉愁人。"]'),
('555c1592-4e63-4a18-812e-8e5eb09a4ef2','江氏家藏仁宗皇帝墨蹟贊','黄庭堅','宋','宋诗','song-poetry','','[]','昭陵仁聖，與天同功。',80,'全唐诗/poet.song.57000.json','["昭陵仁聖，與天同功。", "不刻不雕，萬國文明。", "日月照臨，無有隠側。", "一滴之雨，澤及萬物。", "簡言易從，易言易知。", "皇祖有訓，信如四時。", "雷聲不作，天地淵默。", "遺黎懷仁，霣泣翰墨。"]'),
('0d9b84c5-8364-42ae-a716-afda33ffbd1f','錢忠懿王畫像贊','黄庭堅','宋','宋诗','song-poetry','','[]','文武忠懿，堂堂如春。',71,'全唐诗/poet.song.57000.json','["文武忠懿，堂堂如春。", "中有樗里，不以示人。", "雷行八區，震驚聽聞。", "提十五州，共爲帝民。", "送君者自崖而反，以安樂其子孫。", "九萬里則風斯在下，眇大物而成仁。"]'),
('82dc1c8c-de58-4908-8451-21ef54a30c40','王元之真贊','黄庭堅','宋','宋诗','song-poetry','','[]','天賜王公，佐我太宗。',140,'全唐诗/poet.song.57000.json','["天賜王公，佐我太宗。", "學問文章，致于匪躬。", "四方來庭，上稍宴衎。", "公舍瓦石，責君堯舜。", "采芝商山，以切直去。", "惟是文章，許以獨步。", "白髮還朝，泣思軒轅。", "雞犬舔鼎，群飛上天。", "真宗好文，且大用公。", "太阿出柙，公挺其鋒。", "龍怒鱗逆，在廷岌岌。", "萬物並流，砥柱中立。", "古之遺直，叔向以之。", "嗚呼王公，其尚似之。"]'),
('baabd049-f24b-4240-8545-3ba3707e2757','東坡先生真贊三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','子瞻堂堂，出於峨眉，司馬班揚。',202,'全唐诗/poet.song.57000.json','["子瞻堂堂，出於峨眉，司馬班揚。", "金馬石渠，閱士如牆。", "上前論事，釋之馮唐。", "言語以爲階，而投諸雲夢之黄。", "東坡之酒，赤壁之笛。", "嬉笑怒駡，皆成文章。", "解羈而歸，紫微玉堂。", "子瞻之德，未變於初爾。", "而名之曰元祐之黨，放之珠厓儋耳。", "方其金馬石渠，不自知其東坡赤壁也。", "及其東坡赤壁，不自意其紫微玉堂也。", "及其紫微玉堂，不自知其珠厓儋耳也。", "九州四海，知有東坡。", "東坡歸矣，民笑且歌。", "一日不朝，其間容戈。", "至其一丘一壑，則無如此道人何。"]'),
('799b384d-fb0f-420b-bdcc-fca3a7dd0190','東坡先生真贊三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','岌岌堂堂，如山如河。',104,'全唐诗/poet.song.57000.json','["岌岌堂堂，如山如河。", "其愛之也，引之上西掖鑾坡。", "是亦一東坡，非亦一東坡。", "槁項黄馘，觸時干戈。", "其惡之也，投之於鯤鯨之波。", "是亦一東坡，非亦一東坡。", "計東坡之在天下，如太倉之一稊米。", "至於臨大節而不可奪，則與天地相終始。"]'),
('d25b757f-ced2-4e6d-ba8e-910835626e74','東坡先生真贊三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','眉目雲開月靜，文章豹蔚虎炳。',28,'全唐诗/poet.song.57000.json','["眉目雲開月靜，文章豹蔚虎炳。", "逢世愛憎怡怡，五朝公忠炯炯。"]'),
('54f7e2d8-7858-48d5-bddf-96dbaa0df25d','寫真自贊五首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','飲不過一瓢，食不過一簞。',164,'全唐诗/poet.song.57000.json','["飲不過一瓢，食不過一簞。", "田夫亦不改其樂，而夫子不謂之能賢，何也。", "顔淵當首出萬物，而奉以四海九州。", "而享之若是，故曰人不堪其憂。", "若余之於山澤，魚在深藻。", "鹿得豐草，伊其野性則然。", "蓋非抱陸沈之屈，懷迷邦之寶。", "既不能詩成無色之畫，畫出無聲之詩。", "又白首而不聞道，則奚取於似摩詰爲。", "若乃登山臨水，喜見清揚。", "豈以優孟爲孫叔敖，虎賁似蔡中郎者耶。"]'),
('6d9d4cc9-c0ad-469c-9a3f-5f9686fad587','寫真自贊五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','吏能精密，里行婣卹。',110,'全唐诗/poet.song.57000.json','["吏能精密，里行婣卹。", "則不如兄元明，而無元明憂疑萬事之敝。", "斟酌世故，銓品人物。", "則不如其弟知命，而無知命强項好勝之累。", "蓋元明以寡過，而知命以傲世。", "如魯直者，欲寡過而未能，以傲世則不敢。", "自江南乘一虛舟，又安知乘流之與遇坎者哉。"]'),
('73ab0c06-584d-4222-839e-9136ba6cf14b','寫真自贊五首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','或問魯直似不似，似與不似，是何等語。',171,'全唐诗/poet.song.57000.json','["或問魯直似不似，似與不似，是何等語。", "前乎魯直，若甲若乙，不可勝紀。", "後乎魯直，若甲若乙，不可勝紀。", "此一時也，則魯直而已矣。", "一以我爲牛，予因以渡河而徹源底。", "一以我爲馬，予因以日千里計。", "魯直之在萬化，何翅太倉之一稊米。", "吏能不如趙張三王，文章不如司馬班揚。", "頎頎以富貴酖毒，而酖毒不能入其城府。", "投之以世故豺虎，而豺虎無所措其爪角。", "則於數子，有一日之長。"]'),
('66d8a1ed-d3f0-4477-b996-4b0dc5422c52','寫真自贊五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','道是魯直亦得，道不是魯直亦得。',46,'全唐诗/poet.song.57000.json','["道是魯直亦得，道不是魯直亦得。", "是與不是，且置勿道。", "喚那箇作魯直，若要斬截一句，藏頭白海頭黑。"]'),
('4bb5f650-6f7f-4943-9417-23b6613f32d2','寫真自贊五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','似僧有髮，似俗無塵。',20,'全唐诗/poet.song.57000.json','["似僧有髮，似俗無塵。", "作夢中夢，見身外身。"]'),
('05b8d8a4-8031-42cb-abfe-6854ba3df436','張大同寫予真請自贊','黄庭堅','宋','宋诗','song-poetry','','[]','秀眉廣宇，不如魯山。',60,'全唐诗/poet.song.57000.json','["秀眉廣宇，不如魯山。", "槁項黄馘，不如漆園。", "韜光匿名，將在雙井。", "談玄說妙，熱謾兩川。", "枯木突兀，死灰不然。", "虛舟送物，成百漏船。"]'),
('1dbd238b-35d0-4845-b815-37b5f36b99b3','張子謙寫予真請自贊','黄庭堅','宋','宋诗','song-poetry','','[]','見人金玉滿堂而不貪，看人鳳閣鸞臺而不妬。',38,'全唐诗/poet.song.57000.json','["見人金玉滿堂而不貪，看人鳳閣鸞臺而不妬。", "自疑是南岳懶瓚師，人言是前身黄叔度。"]'),
('0240dec9-cdec-49cb-8373-8396cb2dd4db','故僰道廖君畫像贊','黄庭堅','宋','宋诗','song-poetry','','[]','廖君樸遬，卒享五福。',81,'全唐诗/poet.song.57000.json','["廖君樸遬，卒享五福。", "其艱其勤，天畀戩穀。", "治生之材，可以治邦。", "知子之智，可以使能。", "耋老于鄉，以福孫曾。", "在爾後人，思其艱勤。", "思其好賢，維衣食之源。", "瞻像思孝，勿墮其教。"]'),
('258ff61f-e619-49f3-8818-6c75002e3523','故江陽楊君畫像贊','黄庭堅','宋','宋诗','song-poetry','','[]','顯允臨邛，吏師文宗。',105,'全唐诗/poet.song.57000.json','["顯允臨邛，吏師文宗。", "能者述之，德宇恢恢。", "疏而不失，有物實之。", "於義當然，确乎不奪。", "强者屈之，愛民如子。", "曰予用威，誰其卹之。", "圖像如生，雖不能言，誰敢忽之。", "其事在人，歲月其逝，勿墜失之。", "後有南董，詢事考言，尚其筆之。"]'),
('5bc89cbe-58a6-4106-b3eb-d825657683d3','故陳氏畫像贊','黄庭堅','宋','宋诗','song-poetry','','[]','女歸能婦，義止宜家。',80,'全唐诗/poet.song.57000.json','["女歸能婦，義止宜家。", "誰其向道，探深見遐。", "入古人室，立妙法句。", "自履實地，告人悟處。", "忽爾心疾，累歲狂癡。", "爲忘我難，使人厭之。", "迨其解化，莊語告戒。", "堂堂夫人，凌鄭同派。"]'),
('7f02bee0-7af4-416a-9638-3e836a02942e','喬令真贊','黄庭堅','宋','宋诗','song-poetry','','[]','抱璞而居，其誰別玉。',68,'全唐诗/poet.song.57000.json','["抱璞而居，其誰別玉。", "喬君不獻，自尊兩足。", "窺其獄戶，視其邑庭。", "吏無重糈，民有頌聲。", "提平如砥，持廉如水。", "觀其中，公清有餘。", "相其貌，固凡人耳。"]'),
('96d1fdb7-7c59-464e-ac6c-1bab2e97c1f7','文勛真贊','黄庭堅','宋','宋诗','song-poetry','','[]','榮如辱如，誰喪誰得。',78,'全唐诗/poet.song.57000.json','["榮如辱如，誰喪誰得。", "萃如嗟如，不見聲色。", "爲吏不殘，去其敗羣。", "好賢喜士，黽勉而勤。", "子克家，吾稅駕。", "舍幾而寢，漠然即化。", "眉目在圖，慰爾時思。", "藹然粹溫，似無恙時。"]'),
('2e63cb6c-dffa-471b-a16d-dfa99947e5c9','李沖元真贊','黄庭堅','宋','宋诗','song-poetry','','[]','冶百鍊之金，而中黄鐘之宮。',70,'全唐诗/poet.song.57000.json','["冶百鍊之金，而中黄鐘之宮。", "琢無瑕之玉，而成夜光之璧。", "可用饗帝，可用活國。", "師曠不世而無聞，韞櫝藏之而無悶。", "士亦何得於山林，元勛而藎穀也故肥遯。"]'),
('ca784b48-991f-49de-9027-39456d4417da','宋喬年真贊','黄庭堅','宋','宋诗','song-poetry','','[]','士之坎壈，以其智多。',67,'全唐诗/poet.song.57000.json','["士之坎壈，以其智多。", "因坎壈以爲師，用其多以見己。", "相遭於功名之會，圖像麒麟。", "獨行於寂寞之濱，照影溪壑。", "大者四時爾，小者風雨爾，豈真我哉。"]'),
('1b13a720-94db-4256-a9d6-2b5431dd773e','宋宗儒真贊','黄庭堅','宋','宋诗','song-poetry','','[]','宋子勃窣，心有古鏡。',100,'全唐诗/poet.song.57000.json','["宋子勃窣，心有古鏡。", "朝四暮三，爲笑不競。", "放一捻一，猶著禪病。", "探丸起死，味藥知性。", "憂患不入乎盃中，抱胡琴而風聽。", "若乃脫冠袒裼，捫蝨應客。", "目如愁胡，拊髀而呼。", "是必追橡栗於雲杪，探水月於江湖，然後怏於心與。"]'),
('d5fb0764-cf86-46d1-8219-e6d2e32337a0','陶兀居士贊','黄庭堅','宋','宋诗','song-poetry','','[]','兀兀陶陶，借書借不得。',44,'全唐诗/poet.song.57000.json','["兀兀陶陶，借書借不得。", "陶陶兀兀，問字問不得。", "是醒是醉，佛也會不得。", "布衣簪紱，有人扶便得。"]'),
('e678b729-7e02-4d39-ad16-c768482b2fda','史應之贊','黄庭堅','宋','宋诗','song-poetry','','[]','眉山史應之，愛酒而滑稽。',84,'全唐诗/poet.song.57000.json','["眉山史應之，愛酒而滑稽。", "對鄙不肖，醉眼一笑。", "司馬德操，萬事但好。", "東方戲嘲，驚動漢朝。", "窮則德操，達則方朔。", "天地一壺，不膠者卓。", "應之老矣，似愚不愚。", "江安食不足，江陽酒有餘。"]'),
('e942265d-0e9b-478c-af50-f72678b65f91','麟趾贊','黄庭堅','宋','宋诗','song-poetry','','[]','麟有趾而不踶，仁哉麟哉。',64,'全唐诗/poet.song.57000.json','["麟有趾而不踶，仁哉麟哉。", "有定而不抵，仁哉麟哉。", "有角而不觸，仁哉麟哉。", "今之人，一朝之忿以觸人，滅身辱親。", "嗚呼，人中有獸，獸中有人。"]'),
('26d81201-de6e-42fb-9c4c-f11aa7d3fe5b','筇竹杖贊','黄庭堅','宋','宋诗','song-poetry','','[]','厲廉隅而不劌，故竊比於彭耽之壽。',90,'全唐诗/poet.song.57000.json','["厲廉隅而不劌，故竊比於彭耽之壽。", "屈曲而有直體，能獨立於雪霜之後。", "伯夷食薇而清，陳仲嚥李而瘦。", "涪翁晝寢，蒼龍掛壁。", "涪翁履危，心如鐵石。", "窮山獨行，解兩虎爭。", "終不使卞莊乘間，而孺子成名。"]'),
('de0e691c-6e5a-4ee7-acf2-a08cdbf8bd04','義松贊','黄庭堅','宋','宋诗','song-poetry','','[]','西山之松，有歲寒之質。',80,'全唐诗/poet.song.57000.json','["西山之松，有歲寒之質。", "懷其同氣耶，既分矣復合而爲一。", "涔露雲雨，老大霜雪。", "匠石輟斤，樵夫歎息。", "人之同氣，去本未遠。", "宰上之杞，蔽芾成陰。", "有其干戈日尋，余不知其何心。"]'),
('a0ddae24-25d1-44db-a404-80beab0bd5eb','三笑圖贊','黄庭堅','宋','宋诗','song-poetry','','[]','二豪之所爭，不滿三隠之一笑。',47,'全唐诗/poet.song.57000.json','["二豪之所爭，不滿三隠之一笑。", "三隠之所笑，不解耶舍之顔。", "耶舍之印，霧鎖雲埋。", "九年面壁，此印方開。"]'),
('310931eb-2889-44d0-aa89-630858922069','倦鶴圖贊','黄庭堅','宋','宋诗','song-poetry','','[]','偉萬里之仙驥，羾九關而天翱。',61,'全唐诗/poet.song.57000.json','["偉萬里之仙驥，羾九關而天翱。", "亦倦飛而歸止，矧人生之嗟勞。", "饑食北山之薇蕨，寒緝江南之落毛。", "安能作河中之桴木，寧爲籬落之繫匏。"]'),
('10ebb969-fe82-410b-8faa-765ff0f830f1','席子澤槃礴圖贊','黄庭堅','宋','宋诗','song-poetry','','[]','百遇毒而成醫，九折臂而信道。',215,'全唐诗/poet.song.57000.json','["百遇毒而成醫，九折臂而信道。", "慈子而長人之幼，愛親而壽人之老。", "蓋嘗飲長桑之丸，而得耆域之草。", "此天地之仁氣也，而席子以遊方之內。", "知萬化之如今，忘一世之遺我。", "臨流濯足，脫帽箕坐。", "寄槁竹以孤唳，哂秋葉之驚墮。", "此天地之義氣也，而席子以遊方之外。", "觀壑若陵，對卿若兵。", "客或箴之曰：俯仰之間，禍之橐也。", "虎不可暴，河不可乘。", "席子笑而應之曰：此天地之强陽氣也，誰能以久生於是方。", "噓竹莩，緻膜眼。", "吟弄風月，使客忘返。", "吾但怪其多能不窮，不知去方朔之近遠。"]'),
('c6be9be8-b23a-4f25-a49d-956624eb381a','趙景仁彈琴舞鶴圖贊','黄庭堅','宋','宋诗','song-poetry','','[]','無山而隠，不褐而禪。',53,'全唐诗/poet.song.57000.json','["無山而隠，不褐而禪。", "聽松風以度曲，按舞鶴而忘年。", "鏗爾舍琴而對吏，忽坌入而來前。", "察朱墨之如蟻，初不病其超然。"]'),
('914a073a-bc68-43bb-813a-c05222f6fd5e','胡逸老吳生畫屏贊','黄庭堅','宋','宋诗','song-poetry','','[]','兩虎戲搏文章露，千林號風雷欲雨。',32,'全唐诗/poet.song.57000.json','["兩虎戲搏文章露，千林號風雷欲雨。", "慎勿私鬭傷爪距，豺狼野子即當路。"]'),
('e631d04c-b1ba-4ee0-8db0-886addc120ca','易生畫麞猿猴貛贊','黄庭堅','宋','宋诗','song-poetry','','[]','穴居木處，相安以飲食生。',98,'全唐诗/poet.song.57000.json','["穴居木處，相安以飲食生。", "渴饑愛憎，無師而自能。", "其皮之美也，自立辟。", "其肉之肴也，故多兵。", "風林露壑，伐木丁丁。", "雄雌同聲，去之遠而猶鳴。", "彼其不同臭味，故眴目而相驚。", "惟蟲能蟲，惟蟲能天。", "余是以觀萬物之情。"]'),
('fb10d9b2-7044-4a54-be74-979e7d0a4371','畫墨竹贊','黄庭堅','宋','宋诗','song-poetry','','[]','人有歲寒心，乃有歲寒節。',24,'全唐诗/poet.song.57000.json','["人有歲寒心，乃有歲寒節。", "何能貌不枯，虛心聽霜雪。"]'),
('baaeec35-3aff-4b2c-9a59-4cad09770f6c','畫牧牛贊','黄庭堅','宋','宋诗','song-poetry','','[]','鼻之柔也，以繩牧之。',34,'全唐诗/poet.song.57000.json','["鼻之柔也，以繩牧之。", "心之柔也，以道牧之。", "縱而不蹊人之田，其誰早服之。"]'),
('24db5506-9435-498d-bc4b-a2d106896d79','畫馬贊','黄庭堅','宋','宋诗','song-poetry','','[]','御與馬相得，維予止作，萬里不日而復。',43,'全唐诗/poet.song.57000.json','["御與馬相得，維予止作，萬里不日而復。", "士志於學，則亦無息。", "以師友爲轡策，及其至焉維爾力。"]'),
('70a5bb0a-12e9-4eab-84d0-24862a48ffaf','黄庭畫贊','黄庭堅','宋','宋诗','song-poetry','','[]','君誦黄庭內外篇，本欲洗心不求仙。',104,'全唐诗/poet.song.57000.json','["君誦黄庭內外篇，本欲洗心不求仙。", "夜眎片月墮我前，黑氣剝盡朝日鮮。", "一暑一寒久自堅，體中風行上通天，亭亭孤立孰旁緣。", "至哉道師昔云然，既已得之戒不傳。", "知我此心未虧騫，指我嬰兒藏谷淵。", "言未絕口行已旋，我記其言夜不眠。"]'),
('1cd92470-e770-4c4f-ad30-16c7b7011bf7','觀世音贊六首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','海岸孤絕補陀巖，有一衆生圓正覺。',112,'全唐诗/poet.song.57000.json','["海岸孤絕補陀巖，有一衆生圓正覺。", "八萬四千清浄眼，見塵勞中華藏海。", "八萬四千母陀臂，接引有情到彼岸。", "涅槃生死不二見，是則名爲施無畏。", "八風吹播老病死，無一衆生得安穩。", "心華照了十方空，即見觀世音慈眼。", "設欲真見觀世音，金沙灘頭馬郎婦。"]'),
('be1518bb-d5f9-4ca0-a12a-89989b705151','觀世音贊六首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','自心海岸孤絕處，戒定慧香補陀伽。',64,'全唐诗/poet.song.57000.json','["自心海岸孤絕處，戒定慧香補陀伽。", "觀身實相浄聖果，自度衆生大悲願。", "一一浮漚鏡本空，八萬四千垂手處。", "夢時捉得水中月，親與獼猴觀古鏡。"]'),
('8c5470aa-71db-44b2-a970-f483317a39a4','觀世音贊六首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','聖慈悲願觀自在，海岸孤絕補陀巖。',64,'全唐诗/poet.song.57000.json','["聖慈悲願觀自在，海岸孤絕補陀巖。", "貫花纓絡普莊嚴，度生如幻現微笑。", "有一衆生起圓覺，即現三十二應身。", "壁立千仞無依倚，住空還以自念力。"]'),
('bb200a31-72ca-41e4-a3a3-986074f75b8f','觀世音贊六首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','以法界印，印諸善根。',68,'全唐诗/poet.song.57000.json','["以法界印，印諸善根。", "以平等印，普印諸業。", "八萬四千母陀臂，諸佛承我稱提力。", "八萬四千清浄眼，衆生依我成正覺。", "補陀巖下白花風，月照海漩三昧底。"]'),
('946bf4a0-5997-44a4-853e-00e204e2ab27','觀世音贊六首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','聖慈悲願觀自在，小白花山住道場。',64,'全唐诗/poet.song.57000.json','["聖慈悲願觀自在，小白花山住道場。", "海漩三昧覺澄圓，三十二應施無畏。", "有一衆生發大心，願度我身及舍識。", "萬仞峰前撒手過，觀音豈復異人乎。"]'),
('5713322a-da3c-46c0-87dd-977a30f97c51','觀世音贊六首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','敬禮補陀，巖下水邊。',40,'全唐诗/poet.song.57000.json','["敬禮補陀，巖下水邊。", "十方三世，無不現前。", "願我亦證，空覺極圓。", "處處悲救，火中生蓮。"]'),
('cabd0d80-f615-4dbe-9e76-8dcc56761b7a','江南李後主夢觀世音像贊','黄庭堅','宋','宋诗','song-poetry','','[]','補陀巖中大慈聖，滄浪石上觀生死。',64,'全唐诗/poet.song.57000.json','["補陀巖中大慈聖，滄浪石上觀生死。", "南州麽聖師子王，感夢白衣施無畏。", "夢回洒筆具光相，照鏡還與我面同。", "當時若會照鏡句，放下江南作閒客。"]'),
('8e9e9065-fc7c-4c27-84f1-ad33b5228d87','了觀師繡觀音贊','黄庭堅','宋','宋诗','song-poetry','','[]','六合內外，若有不觀音處。',60,'全唐诗/poet.song.57000.json','["六合內外，若有不觀音處。", "則此絲縷，不能堅固。", "橫此三十二應，共此一光明聚。", "了觀觀音，自知金針落處。", "知落處，女媧補天夜夜雨。"]'),
('5aac52b1-0634-498d-b5ec-1e631ecf7458','龐道者繡觀音贊','黄庭堅','宋','宋诗','song-poetry','','[]','八萬四千唯兩臂，三十二應無來往。',64,'全唐诗/poet.song.57000.json','["八萬四千唯兩臂，三十二應無來往。", "悲觀一切造諸業，慈觀諸業熾然住。", "清浄觀時無本根，幻影重重蒙古佛。", "有能出世自觀音，即受老翁無畏施。"]'),
('bd5dcaf0-b6b5-42cf-a0d6-e0e3f8b5b468','南山羅漢贊十六首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','大阿羅漢賓度羅，奉持末後如來印。',64,'全唐诗/poet.song.57000.json','["大阿羅漢賓度羅，奉持末後如來印。", "日中一鉢千家飯，處處作佛事饒益。", "以我身心五分香，作光明雲雨大千。", "取火燃香世界主，能遍法界唯心辦。"]'),
('0fb383e7-c19a-446a-b83c-956d919c9194','南山羅漢贊十六首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','佛記一切賢聖衆，皆以無爲有差別。',64,'全唐诗/poet.song.57000.json','["佛記一切賢聖衆，皆以無爲有差別。", "如來乃至阿羅漢，同入涅槃三昧海。", "二乘設不見此理，是則波旬顛倒想。", "稽首迦諾迦伐蹉，看花結印同無相。"]'),
('b52b326f-0e38-42f0-ade0-fdaa51f7fb50','南山羅漢贊十六首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','駕羊超出風火宅，跨兔求度生死河。',64,'全唐诗/poet.song.57000.json','["駕羊超出風火宅，跨兔求度生死河。", "者乘如來初方便，自徹海漩三昧底。", "三乘如來悲願力，身如光影現十方。", "持經不染文字相，是名第一離欲者。"]'),
('494857ee-6f3a-443f-98d0-a3f767f0c0f4','南山羅漢贊十六首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','斑斑之獸本山林，升堂入室作輿衛。',64,'全唐诗/poet.song.57000.json','["斑斑之獸本山林，升堂入室作輿衛。", "小僧奉施軍持水，弭耳來受救渴供。", "胸中猛虎自調服，是故異物成一家。", "我觀閻浮提衆生，同牀猜忌若冰炭。"]'),
('9a5d2dd7-1c8e-43e0-ab09-0641745229c5','南山羅漢贊十六首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','稽首具六波羅密，稽首得無生法忍。',64,'全唐诗/poet.song.57000.json','["稽首具六波羅密，稽首得無生法忍。", "稽首佛敕久住世，稽首救世不倦者。", "天上人間福田施，心無高下依佛慧。", "遍與有情作功德，故受孔雀墮尾供。"]'),
('9eaacbe2-2037-4590-8c2a-496796f17de8','南山羅漢贊十六首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','能以一切聲聞佛，能以法忍出世法。',64,'全唐诗/poet.song.57000.json','["能以一切聲聞佛，能以法忍出世法。", "宴坐分身應十方，不取涅槃自饒益。", "伏住泥沙觀止水，中有菩薩清凉月。", "無明風起作浪波，方會如來同覺海。"]'),
('f8186a43-9f00-4fb8-9c7a-4fa596537ae3','南山羅漢贊十六首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','佛光影中大杜多，八萬細行滅塵勞。',64,'全唐诗/poet.song.57000.json','["佛光影中大杜多，八萬細行滅塵勞。", "愛護有情如眼目，胡奴來供濾水囊。", "手持白拂起清風，奉持所聞佛直指。", "小根魔子欲橫戈，弓折箭盡皆消霣。"]'),
('070e8dad-06f8-43a0-9c89-c7bfd5c02522','南山羅漢贊十六首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','百和香中本無我，光透塵勞一一法。',64,'全唐诗/poet.song.57000.json','["百和香中本無我，光透塵勞一一法。", "佛法本從空處起，炳然字義照太空。", "以此一香應發心，東方出日西方雨。", "我今稽首伐闍羅，是真離欲阿羅漢。"]'),
('1ea85188-27f4-46ff-9cdd-02c05ad2e6c9','南山羅漢贊十六首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','香醉山中夏木陰，來禽磊磊承風霧。',64,'全唐诗/poet.song.57000.json','["香醉山中夏木陰，來禽磊磊承風霧。", "山鳥衝飛墮聖前，小僧澡雪羞時供。", "胡奴知是說法時，故奉金爐聽時事。", "有說法相無言說，無說無聞是真說。"]'),
('85e73d7b-0dc2-4187-aba9-72c74e58f561','南山羅漢贊十六首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','龐眉寂默坐空禪，萬年一念無緣促。',64,'全唐诗/poet.song.57000.json','["龐眉寂默坐空禪，萬年一念無緣促。", "手珠猶作奢摩他，寄迹普賢修萬行。", "梵天來獻瑜伽具，問人親見世尊來。", "撥開眉目示梵王，諸天皆得法眼浄。"]'),
('cac12540-4bbb-4360-a8e7-27d0eafff8d8','南山羅漢贊十六首  其一一','黄庭堅','宋','宋诗','song-poetry','','[]','一身入定多身出，屈申臂頃四天下。',64,'全唐诗/poet.song.57000.json','["一身入定多身出，屈申臂頃四天下。", "如世篋藏諸有物，及以絲縷舞工木。", "小兒贊歎或恐怖，耆老智者但袖手。", "佛說神通方便力，度脫衆生具功德。"]'),
('57fec91d-861f-4d30-9bb8-e86bbd20f740','南山羅漢贊十六首  其一二','黄庭堅','宋','宋诗','song-poetry','','[]','四十九年大教主，波旬請故入涅槃。',64,'全唐诗/poet.song.57000.json','["四十九年大教主，波旬請故入涅槃。", "佛身常尋法界住，非其境界故不見。", "未法衆生尠福田，衆魔染衣汗戒律。", "稽首那迦住世間，令我常生遇佛想。"]'),
('6e0fb0cd-227e-435d-bab0-4a463bcca247','南山羅漢贊十六首  其一三','黄庭堅','宋','宋诗','song-poetry','','[]','如來寶仗降魔相，慈悲威怒震十方。',64,'全唐诗/poet.song.57000.json','["如來寶仗降魔相，慈悲威怒震十方。", "毒龍帖耳收雷霆，逆鱗可摩若家狗。", "我法未嘗惱衆生，不令肆毒生恐怖。", "但以本來悲願力，情與無情共一家。"]'),
('928129c4-a0f9-4da1-913c-187f5907827f','南山羅漢贊十六首  其一四','黄庭堅','宋','宋诗','song-poetry','','[]','八萬四千寶浮圖，不如一念心清浄。',64,'全唐诗/poet.song.57000.json','["八萬四千寶浮圖，不如一念心清浄。", "惟此有相擅施福，三塗八難所依怙。", "佛以一花示迦葉，笑中有刀世不解。", "而以法盡付諸人，深藏寶骨待梅里。"]'),
('97868678-1c62-442e-bc36-722f629f74cd','南山羅漢贊十六首  其一五','黄庭堅','宋','宋诗','song-poetry','','[]','萬山相倚碧巑岏，靈鷲一峰聖賢宅。',64,'全唐诗/poet.song.57000.json','["萬山相倚碧巑岏，靈鷲一峰聖賢宅。", "如來往昔經行處，林泉鳥獸皆逆向。", "清浄眷屬千五百，無日不聞鐘磬音。", "閻浮提中大福田，蓮花會上菩提記。"]'),
('b93af2a2-90e6-4a7c-b31c-79b90ede3cb4','南山羅漢贊十六首  其一六','黄庭堅','宋','宋诗','song-poetry','','[]','持軸山中大慈聖，普應諸供作佛事。',64,'全唐诗/poet.song.57000.json','["持軸山中大慈聖，普應諸供作佛事。", "雖設大鈴金剛杵，如世休馬櫜弓矢。", "龍女來獻九淵珠，無心奉施無心受。", "清浄之衆見尋常，相視還如土木偶。"]'),
('e82b14ea-64dc-4b9b-9f6c-68404712b977','見翰林蘇公馬祖龐翁贊戲書','黄庭堅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一口吸盡西江水，磨却馬師三尺觜。',52,'全唐诗/poet.song.57000.json','["一口吸盡西江水，磨却馬師三尺觜。", "馬駒蹋殺天下人，驚雷破浪非凡鱗。", "馬祖龐公，水泄不通。", "游鯈方樂，科斗生角。"]'),
('e0bc60bb-4774-41ab-8159-ecd6f1da5a1b','清凉國師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','寶月清凉，寂照法界。',80,'全唐诗/poet.song.57000.json','["寶月清凉，寂照法界。", "以沙門相，藏世間解。", "谷響入耳，性不可爲。", "青蓮出水，深不可窺。", "萬象紛披，花開古錦。", "啟迫羣氓，與甘露飲。", "哲人去矣，資何所參。", "即事之理，塔鎖終南。"]'),
('36fd96cf-06b3-4a3f-8505-44b11eb0dd0c','木平和尚真贊','黄庭堅','宋','宋诗','song-poetry','','[]','一尺三寸汗脚，草鞋掛龍牀角。',42,'全唐诗/poet.song.57000.json','["一尺三寸汗脚，草鞋掛龍牀角。", "他日清凉半座，果然未忘禮樂。", "一一漚裏木平，稽首一漚前覺。"]'),
('d8f150a6-0f96-40d9-892f-024b6d08f815','南安巖主大嚴禪師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','石出山而韵自丘壑，松不春而骨立冰霜。',73,'全唐诗/poet.song.57000.json','["石出山而韵自丘壑，松不春而骨立冰霜。", "今得雲門柱杖，打破鬼窟靈牀。", "其石也，將能萬里出雲雨。", "其松也，欲與三界作陰凉。", "此似昔人非昔人也，山中故友任商量。"]'),
('72bad30f-e9d9-482f-8cb9-2fbdbc6bbce0','南安巖主定應大師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','定光古佛，不顯其光。',181,'全唐诗/poet.song.57000.json','["定光古佛，不顯其光。", "古錐透穿，大千以爲囊。", "卧像出家，西峰參道。", "亦俗亦真，一體三寶。", "彼逆我順，彼順我逆。", "過即追求，虛空鳥迹。", "驅使草木，教誨蛇虎。", "愁霖出日，枯旱下雨。", "無男得男，無女得女。", "法法如是，誰奪誰予。", "令君威怒，免我伽梨。", "既而釋之，遂終白衣。", "白帽素履，須髮皤皤。", "壽八十二，與世同波。", "窮巖草木，枯腊風雨。", "七閩香光，家以爲祖。", "薩埵御天，宋有萬姓。", "乃錫象服，名曰定應。"]'),
('2c3fcbcc-79f7-404c-be42-10003977daaf','黄龍南禪師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','我手何似佛手，日中見斗。',160,'全唐诗/poet.song.57000.json','["我手何似佛手，日中見斗。", "我脚何似馿脚，鎖却狗口。", "生緣在甚麽處，黄茆裏走。", "乃有北溟之鯤，揭海生塵。", "以長觜鳥啄其心肝肺，乃退藏於密。", "待其化而爲鵬，與之羽翼，九萬里則風斯在下矣。", "自爲鑪而鎔凡聖之銅，乃將圖南也。", "道不虛行，是謂無功之功。", "徧得其道者，一子一孫而已矣。", "得其一者，皆爲萬物之宗。", "工以丹墨，得皮得骨。", "我以無舌，贊水中月。"]'),
('762c76a9-9170-482a-a44b-12dc5f768aa9','大溈喆禪師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','即邪是正，即藥是病。',113,'全唐诗/poet.song.57000.json','["即邪是正，即藥是病。", "乞水指井，乞飯與甑。", "殺人如麻，出邪命定。", "而得正命，尸羅清浄。", "而八萬四千清浄，是謂毗盧遮那正法眼藏。", "以平等印封之，以僧伽梨蒙之。", "無心者來，彈指門開。", "聖凡不盡，金鎖生苔。", "丹青回互，南北呈露。", "影落千江，誰知月處。"]'),
('e4555385-86f9-4133-ad2d-93ad6184b2d0','五祖演禪師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','問道白雲端，蹋著自家底。',60,'全唐诗/poet.song.57000.json','["問道白雲端，蹋著自家底。", "無心萬事禪，一月千江水。", "路逢摩登伽，石上漫澆水。", "赤土畫簸箕，也有第一義。", "誰言川藞䕢，具相三十二。"]'),
('65d23cf6-2156-472a-8f08-3febcf995ef7','慧林中禪師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','廓然豁爾，師不自知。',65,'全唐诗/poet.song.57000.json','["廓然豁爾，師不自知。", "工何能寫，晬然衎爾。", "工以爲真，師不謂之假。", "金然玉爾，物自賓之。", "木然石爾，孰能親之。", "維丹青不能新之，其孰能陳之。"]'),
('f19e382a-0790-4bb9-ad04-88f5b466bc13','法雲秀禪師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','法雲大士，天骨巖巖。',103,'全唐诗/poet.song.57000.json','["法雲大士，天骨巖巖。", "如來津梁，我實荷擔。", "手捉日月，斷取莊嚴。", "國士入此佛土，位置城南。", "有目無目，疑聖疑凡。", "擊大雷霆，布灑甘露。", "大圓鏡中，慈悲威怒。", "維此象法，依正法住。", "後五百歲，亦莫予敢侮。", "誰爲請主，世界主女。"]'),
('17a97980-5835-402c-9c90-ddf05c1a4179','泐潭乾和尚真贊','黄庭堅','宋','宋诗','song-poetry','','[]','平常心是道，南泉只眨得眼，菴內人不見菴外事。',81,'全唐诗/poet.song.57000.json','["平常心是道，南泉只眨得眼，菴內人不見菴外事。", "趙州猶是擔扳，秋毫不穩。", "方丈前萬仞深坑，但到牢關柱杖子。", "天下橫行，平如鏡面，實如石師子。", "借問是誰，泐潭道人，萍鄉老子。"]'),
('a4a17d70-64c4-40cc-abc5-e012e31d7a68','泐潭我和尚真贊','黄庭堅','宋','宋诗','song-poetry','','[]','枯木突兀，傲睨萬物。',20,'全唐诗/poet.song.57000.json','["枯木突兀，傲睨萬物。", "頂門上眼，正法中骨。"]'),
('941c9496-b6cd-4900-a3c8-5e99dc4c6b34','長蘆夫和尚真贊','黄庭堅','宋','宋诗','song-poetry','','[]','松枯竹瘦，是其歲寒也。',92,'全唐诗/poet.song.57000.json','["松枯竹瘦，是其歲寒也。", "山高水深，不可犯干也。", "取多國士，莊嚴此土，如陶家手也。", "拂除方丈，置榻而坐，一不受也。", "首出萬物，淵默雷吼，寂寥者之參也。", "若夫以法界印，印毛印海，則驚僧繇而走巫咸也。"]'),
('cae5b856-1198-47c7-9018-ff85d92257f1','雲蓋智和尚真贊','黄庭堅','宋','宋诗','song-poetry','','[]','哆哆啝啝，搭猱左科。',62,'全唐诗/poet.song.57000.json','["哆哆啝啝，搭猱左科。", "喫十方飯，唱快活歌。", "任疏慵，沒禮數。", "趕則去，招則住。", "住似著衫，去如脫袴。", "禪徒苦口勸和光，捏聚虛空要泊路。"]'),
('a748d3fd-0c81-4954-bf38-a572caf5dc23','仰山簡和尚真贊','黄庭堅','宋','宋诗','song-poetry','','[]','不戒而六和恭敬，不禪而十方清浄。',112,'全唐诗/poet.song.57000.json','["不戒而六和恭敬，不禪而十方清浄。", "不學而文理井井，不吏而施於有政。", "壽八十餘，閱人三世。", "孝於塔廟，勤力勤禮。", "百室崇成，檀者亹亹。", "齊始如終，薪窮於指。", "耋老而精明，豐肉而神清。", "和同而不濁，退屈而不陵。", "是謂大雅之士，惜乎其不發諸朝廷。"]'),
('833ec042-32ad-42d8-afc1-2687f38698cf','黄龍清和尚真贊','黄庭堅','宋','宋诗','song-poetry','','[]','黄河徹底凍，白髮通心白。',24,'全唐诗/poet.song.57000.json','["黄河徹底凍，白髮通心白。", "雖有顧陸手，百巧畫不得。"]'),
('d7babe48-059c-4dd4-89c9-1767b745d7b0','大通禪師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','前波法涌，後波大通。',94,'全唐诗/poet.song.57000.json','["前波法涌，後波大通。", "大通法涌，徹底澄空。", "圓照願海，千漚一實。", "圓通法流，滔天沃日。", "三世一念，十方見前。", "銅崖鐵壁，不可攀緣。", "見即彈指，蹉過萬千。", "大則偏圓異位，通則真假同源。", "觀者著眼，是傳非傳。"]'),
('d3322769-9590-4142-929b-1cb797f0cac0','寶梵大師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','穆然而肅，毗尼藏也。',160,'全唐诗/poet.song.57000.json','["穆然而肅，毗尼藏也。", "熙然而溫，同塵相也。", "默然而說，法中龍象也。", "知文知武，染衣將相也。", "淵然而深，飽儒術也。", "悠然而思，入詩律也。", "鉢囊如空，不受實也。", "室中生光，無長物也。", "十有七年，爲法城塹也。", "五十八夏，圭璋無玷也。", "斬然而秀，出火宅也。", "漻然而化，薪火息也。", "子孫繩繩，奉承丹青。", "眸子睟明，吾觀其役物之智。", "袖手微笑，人挹其臨財之清。"]'),
('925aa3c2-b60f-442a-8000-695aacffc60c','具茨頌','黄庭堅','宋','宋诗','song-poetry','','[]','帝省具茨，在國南屏。',249,'全唐诗/poet.song.57000.json','["帝省具茨，在國南屏。", "篤生韓公，補天子聖。", "文武韓公，其德庭方。", "靡職不宜，乃宣力四方。", "四方維則，歸補我衮職。", "西羌不庭，王師濯濯。", "奏功不時，公請命行。", "公出撫師，王師矯矯。", "羌戎震驚，其藪澤是狩。", "復我王土，將築於河之滸。", "人亦有言，功不在初，其潰於成。", "陰有齒牙，以猾覆城。", "天子聖神，知我公孔武。", "公雖歸止，四方以無侮。", "京師之屏，公曰維許樂土。", "赫赫王命，北門是處。", "公治北門，有條有葉。", "夷根披節，蟊賊是伐。", "惠及鰥寡，日用飲酒。", "萬有千載，樂公壽考。", "公御宴喜，樂酒溫克。", "賓秩醉飽，柔嘉維則。", "維公之德，萬有千歲。", "畀公遐福。"]'),
('ff2c4b8c-0ae2-4b57-8003-fadb5bfa7465','曹侯善政頌','黄庭堅','宋','宋诗','song-poetry','','[]','曹侯輟耕，學于上國。',110,'全唐诗/poet.song.57000.json','["曹侯輟耕，學于上國。", "進士起家，爲吏有績。", "雖窶人子，孔武且碩。", "我惠我威，養我如子。", "我勤我暇，不借吏史。", "虎暴人境，肆作機穽。", "侯曰徹之，病在乎政。", "惟此戾蟲，迺與政通。", "風林岑蔚，征夫不逢。", "我作頌聲，與民歌之。", "不誣方將，俾勿磨之。"]'),
('2070931f-2acf-4756-b47b-5e38ce55b40c','清閑處士頌','黄庭堅','宋','宋诗','song-poetry','','[]','至樂山中，嘉木之樾。',343,'全唐诗/poet.song.57000.json','["至樂山中，嘉木之樾。", "有人天游，風雲爲馬，鷗鷺爲舟。", "有詩客李發，字之曰清閒處士。", "而蜀有豪士王當，以爲蓋謝敷之流。", "其清也不登市井之隴，其閒也不齅王公之鈎。", "傲睨萬物，逍遙一丘。", "身與長松共老，名與北斗俱休。", "涪翁曰名之不稱實也久矣，吾子何以是爲哉。", "書潞則失涿，謂鷹則化鳩。", "故一以我爲馬，一以我爲牛。", "蓋有有其實而不受，亦有無其實而固求者也。", "常試爲吾子道清閒之致乎。", "水之爲物，甚寒而極清。", "鬰爲堅冰，得溫而釋，遍利諸生。", "雲之爲物，無心而出岫穴。", "風休雨息，反一無跡。", "我觀古人，以是爲則。", "若夫汙泥濁水，與蛙同生，不溷其清。", "自操井臼，日耕荒徼，未嘗不閒。", "惟有道者能藏於天，吾子何處焉。", "清閒曰我無所用於世，而從所好。", "惟水雲與之忘老，何敢以爲有道。", "涪翁曰舐痔十乘，曹商自優，非君清流。", "商財計得白圭，擬國以閒爲慝。"]'),
('c3b2de54-fe68-4824-8be5-37b91bac4bdd','王厚頌二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','八風動摇人不閑，五羖自鬻鬢毛斑。',32,'全唐诗/poet.song.57000.json','["八風動摇人不閑，五羖自鬻鬢毛斑。", "文章書畫當富貴，惟有如今至樂山。"]'),
('5a774a61-856d-4503-81bd-7cb9b57975c9','王厚頌二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','夕陽盡處望清閑，想見千巖細菊斑。',32,'全唐诗/poet.song.57000.json','["夕陽盡處望清閑，想見千巖細菊斑。", "人得交游是風月，天開圖畫即江山。"]'),
('d3921914-7e80-4c26-a7a9-756c2d359a26','答楊明叔送米頌','黄庭堅','宋','宋诗','song-poetry','','[]','買竹爲我打籬，更送米來作飯。',42,'全唐诗/poet.song.57000.json','["買竹爲我打籬，更送米來作飯。", "用此回光反照，佛事一時成辦。", "不須天下求佛，問取弄臭脚漢。"]'),
('11e0c8ea-f708-435a-808e-c2c9a565df9b','謝張寬夫送椶耳頌','黄庭堅','宋','宋诗','song-poetry','','[]','菜茹之品椶耳君，乖龍割耳鼈脫裙。',48,'全唐诗/poet.song.57000.json','["菜茹之品椶耳君，乖龍割耳鼈脫裙。", "張子羞我助貧餐，桑鵝楮雞不足云。", "曲肱一飽南風薰，萬事於我如浮雲。"]'),
('5c470e90-7a69-4f21-878c-ba37938e6c5e','乞笋於廖宣叔頌','黄庭堅','宋','宋诗','song-poetry','','[]','龍蛻骨，掉蒼尾。',40,'全唐诗/poet.song.57000.json','["龍蛻骨，掉蒼尾。", "餘戢戢，漫蛇虺。", "棄雨中，心爛死。", "携長鑱，戴篢子。", "可盡髠，馘左耳。"]'),
('79a8cd57-354a-4f96-8e45-9706f688247b','奉約宣叔頌','黄庭堅','宋','宋诗','song-poetry','','[]','貴魁梧，賤瑣尾。',40,'全唐诗/poet.song.57000.json','["貴魁梧，賤瑣尾。", "强分別，蚿憐虺。", "雨新霽，月未死。", "欲循城，將數子。", "煩置酒，摘蒼耳。"]'),
('1e39d852-f3b6-4832-98a0-352ffaf6686d','戲答宣叔頌','黄庭堅','宋','宋诗','song-poetry','','[]','探龍淵，履虎尾。',40,'全唐诗/poet.song.57000.json','["探龍淵，履虎尾。", "別狐貉，辨蚖虺。", "頭雪白，心灰死。", "老斲輪，不教子。", "君聞此，當洗耳。"]'),
('39270aa3-f97e-427e-a1ab-557c9fb499fb','清醇酒頌','黄庭堅','宋','宋诗','song-poetry','','[]','清如秋江寒月，風休波靜而無雲。',58,'全唐诗/poet.song.57000.json','["清如秋江寒月，風休波靜而無雲。", "醇如春江永日，游絲落花之困人。", "借之以涪翁清閒，鑒此杯面淥。", "本之以李叟孝友，成此甕中春。"]'),
('61c24f76-c41a-460f-8083-c02bab253aba','醇碧頌','黄庭堅','宋','宋诗','song-poetry','','[]','田子綠麴，妙在蒸蓼。',80,'全唐诗/poet.song.57000.json','["田子綠麴，妙在蒸蓼。", "女酒兀者，美生其手。", "挹彼而清，注茲無聲。", "其香馥郁，悅可飲者。", "如春霢霂，清不病醨。", "多不疾人，誰其吐之。", "百室之醅，醇碧惟師。", "老夫不飲，評以鼻慧。"]'),
('329c0a3c-0e44-4d79-872b-e6537752daa2','安樂泉頌','黄庭堅','宋','宋诗','song-poetry','','[]','姚子雪麴，杯色爭玉。',60,'全唐诗/poet.song.57000.json','["姚子雪麴，杯色爭玉。", "得湯郁郁，白雲生谷。", "清而不薄，厚而不濁。", "甘而不噦，辛而不螫。", "老夫手風，須此晨藥。", "眼花作頌，顛倒淡墨。"]'),
('1528a17f-1182-4991-ab20-3a63230b3fc7','玉醴頌','黄庭堅','宋','宋诗','song-poetry','','[]','北郭子，竹林居。',56,'全唐诗/poet.song.57000.json','["北郭子，竹林居。", "醖玉醴，撥浮蛆。", "味橘露，色鵝雛。", "春盎盎，想可𣂏。", "魚枕蕉，正闕渠。", "來問字，儻借書。", "掃三徑，待雙魚。"]'),
('b3ffccab-2221-463d-9d32-a81b9e2a76a7','荔支綠頌','黄庭堅','宋','宋诗','song-poetry','','[]','王牆東之美酒，得妙用於六物。',84,'全唐诗/poet.song.57000.json','["王牆東之美酒，得妙用於六物。", "三危露以爲味，荔支綠以爲色。", "哀白頭而投裔，每傾家以繼酌。", "忘螭鬽之躨觸，見醉鄉之城郭。", "揚大夫之拓落，陶徵君之寂寞。", "惜此士之殊時，常生塵於尊勺。"]'),
('25879a42-0c07-479e-834d-ad83454441e5','筇竹頌','黄庭堅','宋','宋诗','song-poetry','','[]','偉邛崍之美竹，初發跡於䍧牱。',120,'全唐诗/poet.song.57000.json','["偉邛崍之美竹，初發跡於䍧牱。", "有山而不險，有水而無波。", "金聲而玉節，故貫四時而不改其柯。", "郭子遺我，扶余澗阿。", "坐則倚胡牀棐几，行則隨青笠綠蓑。", "吾衰也久矣，視爾畏友。", "予琢予磨，百世以俟聖人而不惑，則涪皤不負筇竹。", "危而不扶，顛而不持，惟筇竹之負涪皤。"]'),
('ded16481-6e6c-4a18-aa00-6f2be9bbef26','澄心亭頌','黄庭堅','宋','宋诗','song-poetry','','[]','菩薩清凉月，游於畢究空。',72,'全唐诗/poet.song.57000.json','["菩薩清凉月，游於畢究空。", "衆生心水浄，菩提影現中。", "忍觀伏塵勞，波澄泥著底。", "八風動地來，塵勞還復起。", "覺海性澄圓，浪時無不渾。", "即渾即澄徹，箇是涅槃門。"]'),
('7ff2076d-3486-40d5-8e18-4fa56449c124','白蓮庵頌','黄庭堅','宋','宋诗','song-poetry','','[]','入泥出泥聖功，香光透塵透風。',28,'全唐诗/poet.song.57000.json','["入泥出泥聖功，香光透塵透風。", "君看根元種性，六窗九竅玲瓏。"]'),
('a9a12ed1-53fc-4bfb-a1c1-ee12c739c48f','了了菴頌','黄庭堅','宋','宋诗','song-poetry','','[]','方廣菴名了了，了了更著菴遮。',42,'全唐诗/poet.song.57000.json','["方廣菴名了了，了了更著菴遮。", "又要涪翁作頌，且圖錦上添花。", "若問只今了未，更須侍者煎茶。"]'),
('43b1c887-6e9d-46c8-9b08-7fa3621e3794','休堂頌','黄庭堅','宋','宋诗','song-poetry','','[]','頭上安頭，如何得休。',60,'全唐诗/poet.song.57000.json','["頭上安頭，如何得休。", "殺佛殺祖，方得按堵。", "北鬰單越，西瞿耶尼。", "事同一家，喫飯著衣。", "向上一路，千聖眨眼。", "韓信打關，張良燒棧。"]'),
('247ef31e-f004-42f5-93da-7cdda83a6279','退堂頌','黄庭堅','宋','宋诗','song-poetry','','[]','愚者日進，智士日退。',42,'全唐诗/poet.song.57000.json','["愚者日進，智士日退。", "象蹋恒河徹底過，大千世界百雜碎。", "愚人尋文弄章句，更覓中間及內外。"]'),
('bdf97bc5-df4f-4d46-b911-ac18ac4a0ac6','拙軒頌','黄庭堅','宋','宋诗','song-poetry','','[]','覓巧了不可，得拙從何來。',60,'全唐诗/poet.song.57000.json','["覓巧了不可，得拙從何來。", "打破沙盆一問，狂子因此眼開。", "弄巧成拙，爲蛇畫足。", "何况頭上安頭，屋下蓋屋。", "畢竟巧者有餘，拙者不足。"]'),
('8434eb65-67ea-46bd-a8c9-23595fb0411d','贈嗣直弟頌十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','饑渴隨時用，悲歡觸事真。',24,'全唐诗/poet.song.57000.json','["饑渴隨時用，悲歡觸事真。", "十方無壁落，中有昔怨人。"]'),
('79bfd269-1baf-4474-9641-7ec0291bfb52','贈嗣直弟頌十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','去日撒手去，來時無與偕。',24,'全唐诗/poet.song.57000.json','["去日撒手去，來時無與偕。", "若將來去看，還似不曾齋。"]'),
('a2d8562a-1c6f-4397-9171-0a46be5f0c6d','贈嗣直弟頌十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','正觀心地時，絲髮亦無有。',24,'全唐诗/poet.song.57000.json','["正觀心地時，絲髮亦無有。", "却來觀世間，冬後數九九。"]'),
('7b826822-917f-4aa1-9e5b-e4c9d4638c9d','贈嗣直弟頌十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','涪陵薩埵子，且道也旁行。',24,'全唐诗/poet.song.57000.json','["涪陵薩埵子，且道也旁行。", "亦嚼橫陳蠟，不愛孔方兄。"]'),
('131bebc9-b608-42a0-a766-9419dc93ebd7','贈嗣直弟頌十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','江南鴻雁行，人言好兄弟。',24,'全唐诗/poet.song.57000.json','["江南鴻雁行，人言好兄弟。", "無端風忽起，縱橫不成字。"]'),
('32200f0d-1e94-4693-b3a7-e1d4235adae5','贈嗣直弟頌十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','萬里唯將我，回觀更有誰。',24,'全唐诗/poet.song.57000.json','["萬里唯將我，回觀更有誰。", "初無卓錐地，今日更無錐。"]'),
('811b1494-1ee4-411b-8fde-96df3a81d646','贈嗣直弟頌十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','江南十兄弟，長被時一共。',24,'全唐诗/poet.song.57000.json','["江南十兄弟，長被時一共。", "夢時各自境，獨與君同夢。"]'),
('0b0f9a91-ddb8-411b-b3bd-23a981ab1cb2','贈嗣直弟頌十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','雖受然燈記，不從然燈得。',24,'全唐诗/poet.song.57000.json','["雖受然燈記，不從然燈得。", "若會翻身句，彌勒真彌勒。"]'),
('530ff4b7-6d89-41b5-91a4-a4e88c1c8cc7','贈嗣直弟頌十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','向上關捩子，未曾說似人。',24,'全唐诗/poet.song.57000.json','["向上關捩子，未曾說似人。", "困來一覺睡，妙絕更通神。"]'),
('6d920e27-432f-4d75-8386-878771dfc6e5','贈嗣直弟頌十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','往日非今日，今年似去年。',24,'全唐诗/poet.song.57000.json','["往日非今日，今年似去年。", "九關多虎豹，聊作地行仙。"]'),
('b8795b1f-04ab-4d88-90d3-411ce56e8b9a','和程德裕頌五首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','貧子還家作富兒，糞箕苕帚未曾遺。',32,'全唐诗/poet.song.57000.json','["貧子還家作富兒，糞箕苕帚未曾遺。", "人人欲問草書意，懷素從來自不知。"]'),
('0d407915-8a5c-47c2-9255-bc7e6802ec47','和程德裕頌五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','鵬飛逼塞滿空虛，蚊睫安巢却有餘。',32,'全唐诗/poet.song.57000.json','["鵬飛逼塞滿空虛，蚊睫安巢却有餘。", "臘月火燒三界盡，從來灰裏撥真如。"]'),
('f2d69142-3e0f-4905-bb48-0f1e14a31de5','和程德裕頌五首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','山河大地目前機，橫按吹毛更不疑。',32,'全唐诗/poet.song.57000.json','["山河大地目前機，橫按吹毛更不疑。", "萬里無人無寸草，凍山亭上與誰欺。"]'),
('cb9e84f3-a710-4274-9c90-8f910f0cd279','和程德裕頌五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','如來剎剎與塵塵，北斗南箕透法身。',32,'全唐诗/poet.song.57000.json','["如來剎剎與塵塵，北斗南箕透法身。", "金粟默然軻好辯，唱歌須是帝鄉人。"]'),
('7790f62d-3d99-45df-8412-c3048ae6c2af','和程德裕頌五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','石田耕種難成稻，荼蓼栽來只苦辛。',32,'全唐诗/poet.song.57000.json','["石田耕種難成稻，荼蓼栽來只苦辛。", "萬物一家真富貴，使君見後却清貧。"]'),
('53975699-19de-4b9a-8c82-2742ebb1e681','贈劉靜翁頌四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','念念皆空更莫疑，心王本自絕多知。',32,'全唐诗/poet.song.57000.json','["念念皆空更莫疑，心王本自絕多知。", "艱勤長向途中覓，掉却甜桃摘醋梨。"]'),
('88450773-537f-4b79-b24c-1087fd5c58eb','贈劉靜翁頌四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','一瓶一鉢非難辦，住得山時更莫來。',32,'全唐诗/poet.song.57000.json','["一瓶一鉢非難辦，住得山時更莫來。", "千年糞掃堆頭物，優鉢羅花特地開。"]'),
('04cdbbf1-3a24-4630-ada8-f3b5d2fb20c0','贈劉靜翁頌四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','萬緣空處真如佛，八面風中不動尊。',32,'全唐诗/poet.song.57000.json','["萬緣空處真如佛，八面風中不動尊。", "困便橫眠饑喫飯，十方無壁又無門。"]'),
('198ab3a8-d240-4d6f-8fe6-4207a28619b3','贈劉靜翁頌四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','浄名龐老摠垂鬚，君幸元無免破除。',32,'全唐诗/poet.song.57000.json','["浄名龐老摠垂鬚，君幸元無免破除。", "心若出家身若住，何須更覓剃頭書。"]'),
('ad3accf4-d348-4bd1-8fbb-c67ca2ca6dc1','再答靜翁并以筇竹一枝贈行四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','南鴻北雁年年客，有箇生涯主不知。',32,'全唐诗/poet.song.57000.json','["南鴻北雁年年客，有箇生涯主不知。", "撼動從來憂樂事，夜窗風葉響棠梨。"]'),
('9ea85dea-9f36-4b28-a474-45a4cddb5328','再答靜翁并以筇竹一枝贈行四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','栽松道者身先老，放下鋤頭好再來。',32,'全唐诗/poet.song.57000.json','["栽松道者身先老，放下鋤頭好再來。", "八萬四千關捩子，與公一箇鎖匙開。"]'),
('7d3fcc7f-c834-4682-9086-81e22d3cb9cc','再答靜翁并以筇竹一枝贈行四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','一筇九節添行李，用得人間處處尊。',32,'全唐诗/poet.song.57000.json','["一筇九節添行李，用得人間處處尊。", "只要上山行飽飯，莫將風雪打人門。"]'),
('0e1de6d4-5fd1-40da-83fc-0ed5dc677276','再答靜翁并以筇竹一枝贈行四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','萬事實頭方穩當，十分足陌莫蹺除。',32,'全唐诗/poet.song.57000.json','["萬事實頭方穩當，十分足陌莫蹺除。", "困來展席日裏睡，讀盡空中鳥跡書。"]'),
('b61ad823-f0a6-4cc4-96fc-825b128b69dc','再答并簡康國兄弟四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','瞿曇不解祖師機，却許貍奴白牯知。',32,'全唐诗/poet.song.57000.json','["瞿曇不解祖師機，却許貍奴白牯知。", "道人只要貧到骨，沈却黄金賣笊離。"]'),
('f3a65b35-9c85-4a3c-9235-f90a3b65ad1e','再答并簡康國兄弟四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','妙舌寒山一居士，浄居金粟幾如來。',32,'全唐诗/poet.song.57000.json','["妙舌寒山一居士，浄居金粟幾如來。", "玄關無鍵直須透，不得春風花不開。"]'),
('8d8caca1-767e-40d3-9b61-8cdfb7a089c7','再答并簡康國兄弟四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','須彌椎打虛空鼓，撼得毗盧海月昏。',32,'全唐诗/poet.song.57000.json','["須彌椎打虛空鼓，撼得毗盧海月昏。", "四海無波安樂住，陳家松下小柴門。"]'),
('5a159ec7-f03f-400e-a674-9c6091d3fb12','再答并簡康國兄弟四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','日中一飯蒙頭睡，黄葉堆門莫掃除。',32,'全唐诗/poet.song.57000.json','["日中一飯蒙頭睡，黄葉堆門莫掃除。", "夜半枕前師子吼，起來燒却野狐書。"]'),
('381911ae-0fef-405c-b682-4b181181f6b8','曉賢師續佛壽頌','黄庭堅','宋','宋诗','song-poetry','','[]','養子續佛壽，非爲養色身。',72,'全唐诗/poet.song.57000.json','["養子續佛壽，非爲養色身。", "棒打石師子，只要實頭人。", "出家無正因，不得正命食。", "是真出家兒，不費秋毫力。", "講得天雨花，說得石點頭。", "人人是檀越，負命者上鉤。"]'),
('7b08cbb3-0f2e-46f5-9b59-6516efc4a169','覺範師種竹頌','黄庭堅','宋','宋诗','song-poetry','','[]','往在江南住竹山，道人兩歲三來訪。',64,'全唐诗/poet.song.57000.json','["往在江南住竹山，道人兩歲三來訪。", "聽風聽雨看成龍，牛羊折角入朝餉。", "簡州城東刮地寒，手種檀欒三兩竿。", "竹成要作無孔笛，若有靈龜一任鑽。"]'),
('fffcd399-1309-40ba-8fab-4c1062219e6a','答雍熙光老頌','黄庭堅','宋','宋诗','song-poetry','','[]','獨弄參軍無鼓笛，右軍池裏泛漁舟。',32,'全唐诗/poet.song.57000.json','["獨弄參軍無鼓笛，右軍池裏泛漁舟。", "豈知劍外雍熙老，收得黄巢折劍頭。"]'),
('6db52fe2-f66f-4e11-8812-a1ae562467e8','又答寄糖霜頌','黄庭堅','宋','宋诗','song-poetry','','[]','遠寄蔗霜知有味，勝於崔浩水精鹽。',32,'全唐诗/poet.song.57000.json','["遠寄蔗霜知有味，勝於崔浩水精鹽。", "正宗掃地從誰說，我舌猶能及鼻尖。"]'),
('e47b0590-c9ba-4a34-a080-54b0e45ce93a','沙彌文信大悲頌','黄庭堅','宋','宋诗','song-poetry','','[]','通身是眼，不見自己。',60,'全唐诗/poet.song.57000.json','["通身是眼，不見自己。", "欲見自己，頻掣馿耳。", "通身是手，不解著鞭。", "白牛懶惰，空打車轅。", "通身是佛，頂戴彌陀。", "頭上安頭，笑殺涪皤。"]'),
('e65f3a70-b59b-4927-b8f0-99ba59f83989','鐵羅漢頌','黄庭堅','宋','宋诗','song-poetry','','[]','人言怖魔像，非金亦非鐵。',156,'全唐诗/poet.song.57000.json','["人言怖魔像，非金亦非鐵。", "若作世金鐵，開士亦不現。", "禪坐應念往，一鉢千家供。", "順佛遺敕故，不宣示神通。", "有爲中無爲，火聚開蓮花。", "無爲中有爲，甘露破諸熱。", "魔子目怖畏，我無怖畏想。", "或欲坯鎔之，爲己富貴梯。", "頼世主慈觀，虎兕失爪角。", "或得野狐書，有字不可讀。", "狐涎著其心，字義皆炳然。", "却來觀六經，全是顛倒想。", "今世青雲士，慎莫作此解。"]'),
('29ccccd8-863e-4610-b10a-9a32faad8131','枯骨頌','黄庭堅','宋','宋诗','song-poetry','','[]','清揚巧笑傾人城，驕氣矜色增我慢。',64,'全唐诗/poet.song.57000.json','["清揚巧笑傾人城，驕氣矜色增我慢。", "無始時來生死趣，八萬苦業所依止。", "皮膚落盡露拴索，一切虛誑法現前。", "不見全牛可下刀，無垢光明本三昧。"]'),
('90812b02-6616-4015-8006-38ab142bb179','髑髏頌','黄庭堅','宋','宋诗','song-poetry','','[]','黄沙枯髑髏，本是桃李面。',48,'全唐诗/poet.song.57000.json','["黄沙枯髑髏，本是桃李面。", "如今不忍看，當時恨不見。", "業風相鼓擊，美目巧笑倩。", "無脚又無眼，著便成一片。"]'),
('cd378163-871e-49e2-9462-37d837fa192b','葫蘆頌','黄庭堅','宋','宋诗','song-poetry','','[]','大葫蘆乾枯，小葫蘆行酤。',48,'全唐诗/poet.song.57000.json','["大葫蘆乾枯，小葫蘆行酤。", "一居金仙宅，一往黄公壚。", "有此通大道，無此令人老。", "不問惡與好，兩葫蘆俱倒。"]'),
('b92c3e87-d111-4594-808d-9f07e0bf2bec','缺月鏡頌','黄庭堅','宋','宋诗','song-poetry','','[]','月墜鏡中，無滅無生。',20,'全唐诗/poet.song.57000.json','["月墜鏡中，無滅無生。", "月雖缺半，影像圓成。"]'),
('399e198c-b27e-4ffb-a9aa-3fca07d66594','還神岡圓首座戒刀頌','黄庭堅','宋','宋诗','song-poetry','','[]','平生受用，三尺吹毛。',40,'全唐诗/poet.song.57000.json','["平生受用，三尺吹毛。", "歡喜斬新，拾得孟勞。", "夢中喚起，猶自忉忉。", "我王庫中，無如是刀。"]'),
('77375962-7137-486c-bdac-9c3506b0c282','題永首座庵頌','黄庭堅','宋','宋诗','song-poetry','','[]','奪得胡兒馬便休，休嗟李廣不封侯。',32,'全唐诗/poet.song.57000.json','["奪得胡兒馬便休，休嗟李廣不封侯。", "分明射得南山虎，子細看來是石頭。"]'),
('524660e0-da7b-43eb-a45b-1c5264f9cb85','勸石洞道真師染袈裟頌','黄庭堅','宋','宋诗','song-poetry','','[]','丈夫出家，當被壞色衣。',43,'全唐诗/poet.song.57000.json','["丈夫出家，當被壞色衣。", "蜀僧袈裟，多似苾蒭。", "輕羅縐縠，染成春柳絲。", "撩蜂引蝶，唯欠遠山眉。"]'),
('c5834c05-6ea7-413d-aa22-19eb828cc624','贈成都六祖沙彌文信頌','黄庭堅','宋','宋诗','song-poetry','','[]','塵是文信，界是沙彌。',58,'全唐诗/poet.song.57000.json','["塵是文信，界是沙彌。", "積塵成世界，析界作微塵。", "界喻人天果，塵爲有漏因。", "塵因因不實，界果果非真。", "因果皆如幻，堂堂出世人。"]'),
('5701c686-802a-464e-b447-bee365a2aa0c','寄六祖範和尚頌','黄庭堅','宋','宋诗','song-poetry','','[]','範公頭上著枷，涪翁脚上著杻。',28,'全唐诗/poet.song.57000.json','["範公頭上著枷，涪翁脚上著杻。", "且共彌勒過冬，閒坐地爐數九。"]'),
('b15931e6-a98d-4c93-a442-de178eb96261','羅漢南公升堂頌二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','寶積拾得漏貫錢，古佛堂前狗尿天。',32,'全唐诗/poet.song.57000.json','["寶積拾得漏貫錢，古佛堂前狗尿天。", "東山日出西山雨，露柱搥胸哭破船。"]'),
('8d71ef48-86fe-4cdb-bf30-64a04d71f6c1','羅漢南公升堂頌二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','黑蟻旋磨千里錯，巴蛇吞象三年覺。',32,'全唐诗/poet.song.57000.json','["黑蟻旋磨千里錯，巴蛇吞象三年覺。", "日光天子轉須彌，失眼衆生問演若。"]'),
('5fd18a3a-56ec-44e1-95e7-609e95849d20','羅漢南公塔頌','黄庭堅','宋','宋诗','song-poetry','','[]','一點墨漆，元無縫罅。',61,'全唐诗/poet.song.57000.json','["一點墨漆，元無縫罅。", "羅漢雲居，天上天下。", "出入奮迅，三界無家。", "以除惱禪，打鼓弄琵琶。", "沈却法船，留下戽斗。", "欲得不沈，戽乾劄漏。"]'),
('6b734c68-4ab9-499a-9e0b-cc7cd866b8c1','和朱宏夫真妄頌','黄庭堅','宋','宋诗','song-poetry','','[]','須彌說法大海聽，南箕吹折北斗柄。',32,'全唐诗/poet.song.57000.json','["須彌說法大海聽，南箕吹折北斗柄。", "蟭螟千眼照世間，保君通達真妄竟。"]'),
('836a9f6f-fb81-426c-bdcc-17424f7b44aa','答檀君送含笑花頌','黄庭堅','宋','宋诗','song-poetry','','[]','檀郎惠我花含笑，借問凝情笑阿誰。',32,'全唐诗/poet.song.57000.json','["檀郎惠我花含笑，借問凝情笑阿誰。", "一世茫茫走聲利，閻公捉定始應知。"]'),
('49470a9b-7a1f-4cc5-82b7-14dc127f4fb1','戲答寶勝甫長老頌','黄庭堅','宋','宋诗','song-poetry','','[]','易拔蒼龍角，難參寶勝禪。',72,'全唐诗/poet.song.57000.json','["易拔蒼龍角，難參寶勝禪。", "林泉飽枯澀，煙月唱清綿。", "笑出黄龍手，慵扶阿卯肩。", "持刀欺寡婦，盜佛鑄私錢。", "月黑踰城夜，風高放火天。", "解嗤招覺老，擔屎汙心田。"]'),
('81f53624-c2ef-4252-b89c-59b945cf15f7','和斌老悟道頌','黄庭堅','宋','宋诗','song-poetry','','[]','終日忙忙本圓覺，只爲魔强令法弱。',64,'全唐诗/poet.song.57000.json','["終日忙忙本圓覺，只爲魔强令法弱。", "不疑更問决疑龜，無病還求除病藥。", "昔人夢中見捕逐，兩手無繩元自縛。", "黄鸝臨夢啼一聲，白日當窗始知錯。"]'),
('54fd2543-85b7-4825-b2e4-04177161a0db','送賢師往瀘州爲兩驅烏乞度牒錢頌','黄庭堅','宋','宋诗','song-poetry','','[]','一鳳將兩雛，往乞五色羽。',48,'全唐诗/poet.song.57000.json','["一鳳將兩雛，往乞五色羽。", "誰有大勢力，成此拮据心。", "若無出家心，勤苦難成就。", "但令發弘誓，誰不起慈悲。"]'),
('67959436-04d6-4bb3-9eb8-43558bfe7174','解瞌睡頌','黄庭堅','宋','宋诗','song-poetry','','[]','文殊吐酒卧，觀音被杻械。',36,'全唐诗/poet.song.57000.json','["文殊吐酒卧，觀音被杻械。", "普賢盜鑄錢，釋迦扇鑪韝。", "範上座殺牛，黄魯直害癩。"]'),
('09658fe0-94f1-4675-a504-4deaf1a218f8','字頌','黄庭堅','宋','宋诗','song-poetry','','[]','齋餘睡兀兀，占盡簷前日。',24,'全唐诗/poet.song.57000.json','["齋餘睡兀兀，占盡簷前日。", "不與一甌茶，眼前黑如漆。"]'),
('d8c6ba4e-c4ad-4f75-83bc-c08383dfad65','爲慧林沖禪師燒香頌三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','昨夜三更狗吠雪，東家閉門推出月。',32,'全唐诗/poet.song.57000.json','["昨夜三更狗吠雪，東家閉門推出月。", "是渠覺海性澄圓，衲子殺人須見血。"]'),
('babde684-7286-4e18-b6f5-872c156218e7','爲慧林沖禪師燒香頌三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','多年破衲不勝針，一曲胡笳無古今。',32,'全唐诗/poet.song.57000.json','["多年破衲不勝針，一曲胡笳無古今。", "往日聞韶獨忘味，守株人在月西沈。"]'),
('2ed7560a-5c1f-45f5-a26e-038601818b5a','爲慧林沖禪師燒香頌三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','西瞿耶尼開靜，北鬰單越受粥。',30,'全唐诗/poet.song.57000.json','["西瞿耶尼開靜，北鬰單越受粥。", "慧林也唱雲門曲，去年臘月六十六。"]'),
('3a3f6405-438d-48bc-95e4-60cf01583f81','爲黄龍心禪師燒香頌三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','老師身今七十六，老師心亦七十六。',32,'全唐诗/poet.song.57000.json','["老師身今七十六，老師心亦七十六。", "夢中沈却大法船，文殊頓足普賢哭。"]'),
('c1354a02-b079-4f2e-bbf7-97a5ba4a72a5','爲黄龍心禪師燒香頌三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','一拳打破鬼門關，一笑吐却野狐涎。',32,'全唐诗/poet.song.57000.json','["一拳打破鬼門關，一笑吐却野狐涎。", "四海崢嶸龍象衆，鼻頭只用短繩牽。"]'),
('556ed841-a86b-4c8a-82b0-5424f7300e93','爲黄龍心禪師燒香頌三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','海風吹落楞伽山，四海山徒著眼看。',32,'全唐诗/poet.song.57000.json','["海風吹落楞伽山，四海山徒著眼看。", "一把柳絲收不得，和風搭在玉闌干。"]'),
('adb1c3b1-cc7f-4e66-8fca-d671307504b7','雨花巖頌彭澤三巖','黄庭堅','宋','宋诗','song-poetry','','[]','孤峰中流分江南，馬當大雷無一帆。',32,'全唐诗/poet.song.57000.json','["孤峰中流分江南，馬當大雷無一帆。", "波濤掀空鳥不度，天花雨我讀書巖。"]'),
('4332caea-39ba-49a4-8377-c8a0354c451c','伏仙巖頌','黄庭堅','宋','宋诗','song-poetry','','[]','生死浪中涅槃宅，與人同黑非同白。',32,'全唐诗/poet.song.57000.json','["生死浪中涅槃宅，與人同黑非同白。", "誰令避世作聾盲，獨來寒巖伏石壁。"]'),
('6d0d3a4f-ad30-4eaf-bb36-7fa799d9293a','補陀巖頌','黄庭堅','宋','宋诗','song-poetry','','[]','脩羅身量等須彌，入藕絲孔逃追北。',32,'全唐诗/poet.song.57000.json','["脩羅身量等須彌，入藕絲孔逃追北。", "補陀巖下不戰人，八萬魔軍皆解甲。"]'),
('05b55f1b-f3eb-4ef8-8ad8-95d647fdf7ea','題高節亭頌','黄庭堅','宋','宋诗','song-poetry','','[]','松風竹雨共談空，樓閣參差古疊重。',32,'全唐诗/poet.song.57000.json','["松風竹雨共談空，樓閣參差古疊重。", "急水灘頭道人住，亦如前佛在因中。"]'),
('2a28be2b-5eff-4267-9b8b-7854a2a59de2','彭女禮北斗圖頌','黄庭堅','宋','宋诗','song-poetry','','[]','白足禮江沙，七星在雲表。',24,'全唐诗/poet.song.57000.json','["白足禮江沙，七星在雲表。", "洗心無一塵，缺月西南曉。"]'),
('d8040a60-767e-4eb7-b716-6007f49badc5','頌取之左右逢其原','黄庭堅','宋','宋诗','song-poetry','','[]','取之左右逢其原，香嚴臘月火燒山。',32,'全唐诗/poet.song.57000.json','["取之左右逢其原，香嚴臘月火燒山。", "對面謾人猶佇思，打得香嚴也是閒。"]'),
('a72888bf-afb6-4625-a9e1-ae797140190b','書蔡秀才屏風頌四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','武寧縣中蔡老子，能棋能酒又能詩。',32,'全唐诗/poet.song.57000.json','["武寧縣中蔡老子，能棋能酒又能詩。", "胸中百萬多羅藏，不向人間說是非。"]'),
('e3a8412c-3843-4264-9035-99cd5fd72876','書蔡秀才屏風頌四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','接人高下但唯唯，笑語相隨不作難。',32,'全唐诗/poet.song.57000.json','["接人高下但唯唯，笑語相隨不作難。", "此翁胸次有涇渭，事不可處執如山。"]'),
('90c46667-73e6-4fbe-94c2-f3fc55500010','書蔡秀才屏風頌四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','此翁家世印纍纍，平生俯視造物兒。',32,'全唐诗/poet.song.57000.json','["此翁家世印纍纍，平生俯視造物兒。", "堪笑癡人不省悞，猶說此翁真箇癡。"]'),
('cf7e3436-d7f5-45bd-9b02-5282a26b746e','書蔡秀才屏風頌四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','讀經一字禮一拜，瘦骨稜稜心苦辛。',32,'全唐诗/poet.song.57000.json','["讀經一字禮一拜，瘦骨稜稜心苦辛。", "看伊冷淡教人笑，定作閻浮百歲人。"]'),
('7104cb4c-c02d-4455-add1-e1981805bbe9','龍眠操三章贈李元中  其一','黄庭堅','宋','宋诗','song-poetry','','[]','吾其行乎，道渺渺兮驂弱，石巖巖兮川橫。',98,'全唐诗/poet.song.57000.json','["吾其行乎，道渺渺兮驂弱，石巖巖兮川橫。", "日月兮在上，風吹雨兮晝冥。", "吾其止乎，曲者如几，直者如矢。", "我爲直兮棘余趾，我爲曲兮不如其已。", "吾耕石田兮爲芝，乃三歲兮報我饑。", "嗣茲穡兮則以稼，從子于耜兮龍眠之下。"]'),
('980b57f4-af6f-40e0-b58d-c4bb000faa8d','龍眠操三章贈李元中  其二','黄庭堅','宋','宋诗','song-poetry','','[]','螳臂美兮當車，蟹螯强兮鬭虎。',117,'全唐诗/poet.song.57000.json','["螳臂美兮當車，蟹螯强兮鬭虎。", "我觀兮上下四方，或錫予兮以大武。", "金石兮水波，松栢兮雨霜。", "有時女兮不春，我欲筮兮同牀。", "筮告予以不好，予與居兮甚娬。", "秦人同炙兮徒欺予，予和羹兮衆吐之。", "南山霧兮楚氛，其在茲兮斗日月。", "揚湯兮救暍，從子休兮龍眠之樾。"]'),
('ea071627-9a76-484a-8e8d-5cd0aa4511ea','龍眠操三章贈李元中  其三','黄庭堅','宋','宋诗','song-poetry','','[]','朝百牢兮九飯，藜羹不糝兮共槃而笑。',122,'全唐诗/poet.song.57000.json','["朝百牢兮九飯，藜羹不糝兮共槃而笑。", "狐白裘兮豹袪，縕袍無裏兮亦見春。", "予何喜兮安樂此，曰有嘉人兮遺予履。", "發十襲兮示予，與予武兮合度。", "使羿兮隅立，使離朱兮詔之。", "若人兮無鵠，離朱茫然兮羿韔弓。", "牧牛兮于鼻，牧羊兮不歧。", "有若人兮可與歸，因子問塗兮龍眠之蹊。"]'),
('779cbb0f-cc67-4c0a-966a-0f22f1fe951d','王聖涂二亭歌','黄庭堅','宋','宋诗','song-poetry','','[]','營丘之下，有宅有田。',294,'全唐诗/poet.song.57000.json','["營丘之下，有宅有田。", "梨棗兮觴豆，耘耔兮爲年。", "鷄栖塒兮羊豕在牧，課兒子兮蓺松菊。", "炙背兮牆東，夢覆舟兮濤且風。", "洋之回兮可以駕，孫甥扶輿兮父老同社。", "洋之水兮可以舟入，鷗鳥兮與之游。", "一世兮蜉蟻，桑榆兮憖可收。", "從此休兮，公誰黄髮之休。", "偉長松兮卧龍蛇，閱千歲兮不改其柯。", "震雷不驚兮，誰欲休之以蜩蛭。", "下有錦石兮可用杯勺，雲月供帳兮萬籟奏樂。", "石子磊磊兮澗谷縱橫，春月桃李兮士女傾城。", "時雨霖兮忽若海潦收，無事兮我以觀萬物之情。", "兒時所蓺兮桃李纖纖，隨世風波兮吹而北南。", "昔去兮拱把，今歸兮與天參。", "與古人兮合契，樹如此兮我何以堪。", "鴻雁嗸兮或在洲渚，有心於粒兮弋者所取。", "飛冥冥兮渺萬里而絕，去藪澤之羅者兮官予落羽。"]'),
('cfcbe509-ede7-4bcc-be77-e9c2677d25e7','木之彬彬','黄庭堅','宋','宋诗','song-poetry','','[]','木之彬彬，非取異於人。',261,'全唐诗/poet.song.57000.json','["木之彬彬，非取異於人。", "可宮室則斬則伐，可籩豆則捋則擷。", "草之茸茸，非求顯於世。", "中芻牧則刈則鉏，中醫和則剝則枯。", "非以其材故耶，是非之歧，利害薰蒸。", "嗟人道之多患，彼草木尚無情。", "吾嘗觀於若人矣，巧於辨人，拙於自辨。", "好動乎天機，不周乎時變。", "罪莫慘於德有心，禍莫深於心有見。", "罪不在德，心其蟊賊，禍不在心。", "見其髠箝之人也，皦皦自鮮，行於衆汙之前。", "嶢嶢不讓，立乎衆埤之上。", "積小不當，是以亡其大當。", "悲夫！羿注矢以當物，十嘗中其七八。", "引鏌鋣以自殘，駭兕虎之竊發。", "禍集於所忽，怨棲於榮名。", "易其言則害智，用其智則害明。", "爲君子則奈何，獨見曉於冥冥。"]'),
('9c47c9de-0d16-4b9f-b2a5-f9135ac06791','予欲金玉汝贈黄從善','黄庭堅','宋','宋诗','song-poetry','','[]','江山複重兮朋友失，長處幽篁兮隔離天日。',276,'全唐诗/poet.song.57000.json','["江山複重兮朋友失，長處幽篁兮隔離天日。", "鳥聲無人兮我友來即，久矣不聞德人之言兮，爲余發藥。", "嘉若人兮甚好修，蘭薰而時發兮，水剛德而用柔。", "有璞連城，方謨匠兮，忍其與斗筲議之。", "螫吾手而不砭兮，舉百體而棄之。", "爲民父母兮，灼子之膚，何能忍。", "顧白日臨辰兮，臣何愛不與俱來。", "古之人償責言兮，雖九死其猶未悔。", "虹氣貫斗牛兮，豈用俗人之町畦。", "予愛蘭而莫與予佩兮，曰斯其不情。", "帝關九牡兮，照下土孔明。", "予將觀東海兮，蛙說予以坎井。", "盍嘗視吾寶兮，茲有重於岑鼎。", "予欲金玉汝兮，汝既金玉。", "揭日月以適四方兮，殆而按劍以爲戮。", "雁以不鳴烹，木以材而斲。", "天下皆羿兮，矢來無鄉，惟應以無名之樸。"]'),
('7f18787c-1527-4037-82db-790a62fdc854','明月篇贈張文潛','黄庭堅','宋','宋诗','song-poetry','','[]','天地具美兮生此明月，陞白虹兮貫朝日。',172,'全唐诗/poet.song.57000.json','["天地具美兮生此明月，陞白虹兮貫朝日。", "工師告余曰斯不可以爲珮，棄捐櫝中兮三歲不會。", "霜露下兮百草休，抱此耿耿兮與日星遊。", "山中人兮招招，耕而食兮無卹。", "榛艾蓁蓁前吾牛兮，疻不可更扶。", "淺耕兮病歲，深耕兮石嬰耜。", "登山兮臨川，雉得意兮魚樂。", "小風兮吹波，從其友兮尾尾。", "日下兮川逝，射雉兮喪余一矢。", "佳人兮潔齊，悵何所兮行媒。", "南山有葛兮葛有本，我羞餔兮以君之鉏來。"]'),
('07fd0cf5-adb8-4af5-91fd-260a492b264b','悲秋','黄庭堅','宋','宋诗','song-poetry','','[]','有美一人兮，臨清秋而太息。',364,'全唐诗/poet.song.57000.json','["有美一人兮，臨清秋而太息。", "傷天形之缺然兮，與有足者同堂而並席。", "儻嘗獲罪於天兮，使而至於斯極。", "夫陰凝而陽化兮，沖氣飪而爲和。", "駢拇所以爲少，枝指所以爲多。", "謂天任汝以道兮，曾是形畸而貌獨。", "天厭棄汝兮，修汝德而謂何。", "中無所考此耿耿兮，獨遡風而浩歌。", "歌曰父耶母耶，人乎天乎。", "才之爲祥，固不若不才之全乎。", "非天地之私兮，又非父母之願也。", "慨伏思而不得兮，夢漂漂而行遠。", "逆真人於軒臺兮，請端策而徵衍。", "遇水盈之坎坎兮，得山麓而爲蹇。", "雖御良而馬服兮，猶往蹇而來連。", "艮之初六來告休兮，艮其趾而无咎。", "如風日之過河兮，人謂守水而爲耗。", "知水性之循環兮，曾何損益之足道。", "蚿百足之狂攘兮，夔踸踔以行地。", "蛇虺蔓延不自好兮，謂風蓬蓬而無似物。", "憐物之無窮兮，目尚爲心之僕隸。", "夫精於形器之表兮，視四體百骸其在外。", "予將執汝手兮，游乎浩蕩之會。", "憑天津而濯髮兮，攬日月以爲珮。"]'),
('fd0b7781-70b8-49ef-8605-0bffd1a0f000','至樂詞寄黄幾復','黄庭堅','宋','宋诗','song-poetry','','[]','余汎觀於天下兮，何者樂而誰者足憂。',208,'全唐诗/poet.song.57000.json','["余汎觀於天下兮，何者樂而誰者足憂。", "憂於窘窘不得兮，樂盡萬物而無求。", "翫聲色而弊形性兮，維造化之螟蠹。", "將逍遙鑪錘之外兮，尚何俛首而嬰此細故。", "百年存亡得失兮，吾既視奕棋與摴蒲。", "寒暑蚤夜極則遷兮，有滿則有虛。", "應龍之不拘繫乎，寧與羸馬帖耳而求芻。", "雲升雨降兮，上下有無。", "入與神會兮，出與化俱。", "無對於天下兮，制命在予。", "賈羣囂而我靜兮，豈其跨一世以求直。", "乃有德人相與友兮，忘我於忘言之域。", "廓宇宙以爲量兮，奚自適而不通，遂風休而水釋。"]'),
('96e7d257-b37b-4e7d-aa41-cb2899573512','錄夢篇  其一','黄庭堅','宋','宋诗','song-poetry','','[]','春風亂思兮吹管絃，春日醉人兮昏欲眠。',264,'全唐诗/poet.song.57000.json','["春風亂思兮吹管絃，春日醉人兮昏欲眠。", "却萬物而觀性兮，如處幽篁之不見天。", "試縱神而不御兮，如有順心之洒然。", "委蜩甲而去化，乘白雲而上仙。", "因天倪而造適，觀衆妙之玄玄。", "風門閶闔而進予，帝示予以化物之甄。", "予撼玄關而去牡，帝宴笑以忘言。", "吾見萬靈朝明庭兮，冠佩如雲烟。", "名聲毀譽之觀兮，差無以異乎人間。", "息心於慕羶之蟻，會理於止水之淵。", "與我游物之初兮，曰是可以解而縣。", "不知其所以得兮，而冷然似有所存。", "歸占夢靈兮，蓋天振吾過。", "矯心以循理兮，殆其沃水而勝火。", "故喜曲轅之櫟以得祥，驚主人之雁以近禍。", "離水火而天兮，迺得使實自我。", "蕩然肆志兮，又烏知可乎不可。"]'),
('25ff1417-053d-4837-9008-a5908e2f9abc','錄夢篇  其二','黄庭堅','宋','宋诗','song-poetry','','[]','亂曰：芻狗萬物兮，天地不仁。',136,'全唐诗/poet.song.57000.json','["亂曰：芻狗萬物兮，天地不仁。", "體止而用無窮兮，播生者於迷津。", "有形而致用者之謂器，無形而用道者之謂神。", "背昭昭而起見兮，聚墨墨而生身。", "犯有形而遺大觀兮，動細習於游塵。", "彼至人而神凝兮，同予夢而先覺。", "顧天下孰不學兮，迺會歸於無學。", "予心之不能忘兮，將波流風靡而奈何，唯鎮之以無名之樸。"]'),
('4102ccc4-8ba5-4c0a-b1a4-b7a15645a418','秋思','黄庭堅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','柴門扃兮，牛羊下來其已久。',368,'全唐诗/poet.song.57000.json','["柴門扃兮，牛羊下來其已久。", "四壁立兮，蛩螿太息不可聽。", "夜冉冉兮斗魁委柄若授人，天寥寥兮河漢風浪西南傾。", "山川悠遠兮，誰獨不共此明月。", "維德人不見兮，采薇蕨于江之南。", "風露寒兮，薇蕨既老而苦澀。", "江道險難兮，不知先生之何食。", "往予窺道而見兮，俯甘井以解渴。", "天地施我生兮，先生厚我德。", "水波無津兮，既拯我舟杭。", "路微徑絕兮，又翦我荆棘。", "秉道要而置對兮，一與而九奪。", "曾不更刀兮，破肯綮於胸中。", "湛湛兮如長江之吐月，霏霏兮若旋盤之落屑。", "會鉏鋙於一堂兮，曾不侮予以色辭。", "星翻翻其爭光兮，觀北斗之運四時。", "維回首之日淺兮，又穿鼻而伏皂。", "乘流下兮，忽不自識其闕遺。", "悲去日之既往兮，愛是日之方來。", "有玉於橐兮，師以爲王所之□□□□不謨獻之，維令之莫予琢之。", "起望天極南兮，□□□□予馬。", "恐蓍龜之遠兮，入鮑肆不知其化。", "子歌犁□□余心兮，爲而三歎其一和。", "微子之昌言兮，殆莫振余過。"]'),
('9acb253c-07d9-4e14-817c-44dbedfe6785','悼往','黄庭堅','宋','宋诗','song-poetry','','[]','西風悲兮敗葉索索，照陳根兮秋日將落。',396,'全唐诗/poet.song.57000.json','["西風悲兮敗葉索索，照陳根兮秋日將落。", "彷彿兮夢與神遇，顧瞻九泉兮豈其可作。", "俄有悲秋之羽蟲兮，自傷時去物改，擁舊柯而孤吟。", "四郊莽蒼聲斷裂兮，久而不勝其歎音。", "平生之梗槩兮欲蕭蕭而去眼，將絕之言語兮忽歷歷而經心。", "謂逝者有知兮，何喜而棄此去也。", "謂逝無知兮，誰職爲此夢也。", "憑須臾之不再得兮，哀此言之不予聽。", "回廊窈窕月皓白兮，無復曩時之履聲。", "擥平生之餘製兮，薌澤其猶未沫。", "雖飄飄其日敗兮，吾不忍改其此佩。", "愁薨薨其中予兮，如醳酒之不化。", "欻別離之幾時兮，誰與此夏日冬夜。", "自我先兮一無窮，在我後兮亦一無窮。", "六七十便了一生兮，何異木末之有狂風。", "待外物而造適兮，固不若放之自得之場。", "彼莊生之一缶兮，亦何異荀氏之神傷。", "吾固知藏於天者至精，交於物者甚粗。", "飲泣爲昏瞳之媒，幽憂爲白髮之母。", "憂來泣下不可安排兮，如孟津之捧土。", "彼寒暑之寖化兮，天地尚不能以朝莫。", "目煢煢而不寐兮，夜亹亹而過中。", "雖來者猶不可待兮，恐不及當時之從容。"]'),
('1f64a9d9-75ee-439d-bfca-897a3d0f5549','聽履霜操','黄庭堅','宋','宋诗','song-poetry','','[]','靈宮窈窕兮寒夜永，篁竹造天兮明月下影，木葉隕霜兮秋聲動。',341,'全唐诗/poet.song.57000.json','["靈宮窈窕兮寒夜永，篁竹造天兮明月下影，木葉隕霜兮秋聲動。", "我以歲莫起視夜兮，北山飲予斗柄。", "幽人拂琴而當予，曰夫子則鍾期，嘗試刳心而爲之聽。", "若有人兮亦既脩，宴衽席之言兮不知其子之齊聖。", "嘉孝子之心終無已兮，不忍忘初之戒命。", "人則不語兮弦則語，客有變容而涕洟，奄不知哀之來處。", "悲乎痛哉！葛屨翦翦兮絺綌凉凉，衣則風兮車上霜，天雲愁兮空山四野。", "竭九河湔涕痕兮，忽承睫其更下。", "嫠不憂其緯兮，恤楚社之不血食。", "盡子職而不我愛兮，終非父母之本心。", "天高地厚施莫報兮，固自有物以至今。", "雉雊雞乳兮，麋鹿解角。", "天性則然兮，無有要約。", "哀號中野兮，於父母又何求。", "我行于野兮，不敢有履聲。", "恐親心爲予動兮，是以有履霜之憂。", "古人之骨朽矣，匪斯今也。", "蹙然如動乎其指，浩然如生乎其心也。", "聲音之發，鈎其深也。", "枯薪三尺，惟學林也。"]'),
('25ad12f4-ba72-482a-9066-8ff1b47e2562','鄒操','黄庭堅','宋','宋诗','song-poetry','','[]','歸歟懷哉，此邦不可以遊。',273,'全唐诗/poet.song.57000.json','["歸歟懷哉，此邦不可以遊。", "眷吾車而有柅，非河滸之無舟。", "政何君而莫與，君何國而莫求。", "歲荏荏而老至，慨時運之不逑。", "洋洋乎水哉，丘之不得濟也。", "昊天不弔，仁者此無罪也。", "攬國辟而家擅，幾何而不殆也。", "心病不可藥，手足未有害也。", "鳥覆巢於主人，鳳摩天而逝也。", "求所用生喪其生，吾不忍幪此蠆也。", "豈曰如之何，然後求諸蔡也。", "已乎已乎！鳥獸山林，則以食也。", "天下有道，丘不與易也。", "歸我休矣，奉帝則也。", "大同至小，天地德也。", "小物自私，智之賊也。", "國無知兮，我非傷悲兮。", "騶御委轡，四牡馳兮。", "心不慊於前驅，又欲下而走兮。", "中園有林，斧所相兮。", "大厦峨峨，不謀匠兮。", "往者不可及，來者吾猶望兮。"]'),
('82d928aa-095f-4a4a-9cce-a271e6ab4092','渡江','黄庭堅','宋','宋诗','song-poetry','','[]','行渡江兮吾無舟，蕩蕩東注兮褰裳不可以遊。',118,'全唐诗/poet.song.57000.json','["行渡江兮吾無舟，蕩蕩東注兮褰裳不可以遊。", "漁橫舟兮不即渡，夐萬里以在前兮無家反顧。", "雲翳翳兮雨凄凄，不濟此兮誰與歸。", "行渡江兮我無楫，釋吾馬兮不可以涉。", "嗟行路之難兮，援琴以身忘。", "手不得於吾心兮，聲久抑而不張。", "天涔涔兮又暮雨，不濟此兮吾歸何處。"]'),
('3ff6fe9d-52c3-4d32-b333-2ca1f6745fea','毀璧','黄庭堅','宋','宋诗','song-poetry','','[]','毀璧兮隕珠，執手者兮問過。',206,'全唐诗/poet.song.57000.json','["毀璧兮隕珠，執手者兮問過。", "愛憎兮萬世一軌，居物之忌兮，固常以好爲禍。", "羞桃肴兮飯汝，有席兮不嬪汝坐。", "歸來兮逍遙，采雲英兮禦餓。", "淑善兮清明，陽春兮玉冰。", "畸於世兮天脫其攖，愛骨人兮冥冥。", "棄汝陽侯兮遇汝曾不如生，未危可以去兮殆而其雛嬰，衆雛羽翼兮故巢傾。", "歸來兮逍遙，西山浪波何時平。", "山涔涔兮猿鶴同舍，瀑垂天兮雷霆在下。", "雲月爲晝兮風雨爲夜，得意山川兮不可繪畫。", "寂寥無朋兮去道如咫，彼生坎兮可謝。", "歸來兮逍遙，增膠兮不聊此暇。"]'),
('8bf74377-aa46-4cc6-abbd-635bff6e0aef','題萬松亭','黄庭堅','宋','宋诗','song-poetry','','[]','天柱峰無比肩，鬰鬰高松滿川。',98,'全唐诗/poet.song.57000.json','["天柱峰無比肩，鬰鬰高松滿川。", "萬身蒼髯老禪，刳心忘義忘年。", "說法曾無間歇，松風寺後山前。", "四海五湖衲子，更於何處參玄。", "若覓向上關捩，靈龜石下流泉。", "太平堂中老將，家活都無一錢。", "會得佛頭著地，不會佛脚梢天。"]'),
('9ae6c75d-6552-439e-952f-06b265fefd26','寄題欽之草堂','黄庭堅','宋','宋诗','song-poetry','','[]','河南有伏流，經營太行根。',144,'全唐诗/poet.song.57000.json','["河南有伏流，經營太行根。", "盛德不終晦，發爲清濟源。", "公家濟源上，太行正當門。", "修竹带藩籬，百禽鳴朝暾。", "仰視浮雲作，俯窺流水奔。", "相望有盤谷，李愿故居存。", "主人國之老，實惟商巖孫。", "斑行昔供奉，屢進逆耳言。", "天子色爲動，群公聲亦吞。", "肅肅冰霜際，不改白玉溫。", "出處士所重，其微難具論。", "公勿懷草堂，朝庭待公尊。"]'),
('39a69968-bad3-430e-a665-f448fb4d55b4','東坡畫竹贊','黄庭堅','宋','宋诗','song-poetry','','[]','孤生危苦，播蕩風雨。',40,'全唐诗/poet.song.57000.json','["孤生危苦，播蕩風雨。", "歲不我與，誓將尋斧。", "刳心達節，萬籟中發。", "黄鍾同律，偉哉造物。"]'),
('cf17f8f4-3581-4281-a7e4-b8b6ec4e422e','戲題戎州作余真','黄庭堅','宋','宋诗','song-poetry','','[]','前身寒山子，後身黄魯直。',24,'全唐诗/poet.song.57000.json','["前身寒山子，後身黄魯直。", "頗遭俗人惱，思欲入石壁。"]'),
('fe3c37c9-6351-4be9-a5ae-45a5e5688e89','峨眉真人陳圖南真贊','黄庭堅','宋','宋诗','song-poetry','','[]','一藤出山，來正人紀。',62,'全唐诗/poet.song.57000.json','["一藤出山，來正人紀。", "見藝祖太宗，曰天下定矣。", "如月在天，去來無疵。", "巍巍頎頎，爲帝王師。", "聖哲肺腑，天人眉目。", "三峰遶宅，歲晚松菊。"]'),
('ec8efcfa-0eaa-497e-b86a-56515011c4a6','彌陀贊','黄庭堅','宋','宋诗','song-poetry','','[]','彌陀願滿衆生界，衆生界是本來心。',64,'全唐诗/poet.song.57000.json','["彌陀願滿衆生界，衆生界是本來心。", "良由自心取自心，往來西方極樂國。", "蹔時斂念門戶開，處處文殊入普賢。", "親見本身無量壽，情與無情成正覺。"]'),
('085a1d99-bcf4-4973-9931-b541fa984bb9','觀音贊','黄庭堅','宋','宋诗','song-poetry','','[]','衆生墮八難，身心俱喪失。',102,'全唐诗/poet.song.57000.json','["衆生墮八難，身心俱喪失。", "惟有一念在，能呼觀世音。", "火坑與刀山，猛獸諸毒藥。", "衆苦萃一身，呼者常不痛。", "何用呼菩薩，當自救痛者，不煩觀音力。", "衆生以二故，一身受衆苦。", "若能真不二，則是觀世音。", "八萬四千人，同時俱起救。"]'),
('85ba952e-b1bf-4ca2-8702-261ef6ef738b','知命弟觀音贊','黄庭堅','宋','宋诗','song-poetry','','[]','普陀巖大聖，應身三十二。',96,'全唐诗/poet.song.57000.json','["普陀巖大聖，應身三十二。", "慈悲視衆生，八萬四千眼。", "救一切苦難，八萬四千聲。", "依歸觀世音，是先得道者。", "南無黄居士，具足神通力。", "亦具智方便，何不自觀音。", "瞿唐風浪中，歸命施無畏。", "一人自歸依，諸人皆解脫。"]'),
('cdc35cc9-34b9-4e53-85da-200b49bf9aae','維摩詰畫贊  其一','黄庭堅','宋','宋诗','song-poetry','','[]','維摩無病自灼灸，不二門開休闖首。',32,'全唐诗/poet.song.57000.json','["維摩無病自灼灸，不二門開休闖首。", "文殊贊歎辜負人，不如趙州放笤帚。"]'),
('55c5db91-acd1-469a-a703-a5a3fbdc5cc8','維摩詰畫贊  其二','黄庭堅','宋','宋诗','song-poetry','','[]','不二法門無別路，諸方臨水不敢渡。',32,'全唐诗/poet.song.57000.json','["不二法門無別路，諸方臨水不敢渡。", "鶖子怕霑天女花，花前竹外是誰家。"]'),
('e719a952-f684-40a6-b214-16f919fadfa8','翠巖璣禪師真贊','黄庭堅','宋','宋诗','song-poetry','','[]','一步一彌勒，一句一釋迦。',48,'全唐诗/poet.song.57000.json','["一步一彌勒，一句一釋迦。", "逢人雖不殺，袖裏有青蛇。", "是翠巖則二，非翠巖則別。", "彌勒下生時，亦作如是說。"]'),
('67dbeed1-2d58-4fc4-b7d5-8fb7c4440faf','圓通璣禪師贊','黄庭堅','宋','宋诗','song-poetry','','[]','諸法坐處坐，諸佛行處行。',40,'全唐诗/poet.song.57000.json','["諸法坐處坐，諸佛行處行。", "如來無簡擇，清鏡坦然平。", "有人借問誰家曲，眨目眉毛何似生。"]'),
('0d869c10-7303-475c-b970-2906927ad4a4','承天寶禪師贊','黄庭堅','宋','宋诗','song-poetry','','[]','靈山會上，得箇消息。',40,'全唐诗/poet.song.57000.json','["靈山會上，得箇消息。", "達安城中，不落裷𩃫。", "黄撫路口，雪裏開花。", "九江渡頭，無風起浪。"]'),
('af560be9-595b-4ce1-b262-3d2fdbec2701','郭功父得楊次公家金書細字經求予作贊','黄庭堅','宋','宋诗','song-poetry','','[]','爲一□□□，□說妙蓮華。',144,'全唐诗/poet.song.57000.json','["爲一□□□，□說妙蓮華。", "清浄法光明，透徹十二部。", "我□□□□，□□□曾說。", "是故祕密藏，藏在微塵中。", "有大□□□，□□□□卷。", "字義皆炳然，堂堂而祕密。", "或以糅□□，□□□□□。", "以其翰墨切，微細作佛事。", "勝眼若千□，□□□□海。", "說法從心起，復以心莊嚴。", "非小亦非大，□□衆心量。", "水牛生象牙，墮在諸佛數。"]'),
('6e75075a-4b1d-4011-8771-f5300d9b84ad','蒲團座贊','黄庭堅','宋','宋诗','song-poetry','','[]','謂余輪邪，吾不隨爾馳逐；謂予扇邪，吾不亂爾寒燠。',80,'全唐诗/poet.song.57000.json','["謂余輪邪，吾不隨爾馳逐；謂予扇邪，吾不亂爾寒燠。", "寬燥厚緩者，老人之養安；質朴自然者，野人之無欲。", "娛爾以貝葉銅瓶，文爾以繩牀筇竹。", "跏趺主人百不能，一裘一葛□□□。"]'),
('02e7d2de-d61a-4592-be17-046f5c459abb','龐道者名悟超贊','黄庭堅','宋','宋诗','song-poetry','','[]','悟道識性，超凡入聖。',20,'全唐诗/poet.song.57000.json','["悟道識性，超凡入聖。", "文殊一源，普賢萬行。"]'),
('4468aab1-6146-4578-a1e8-934eb6908886','芝贊','黄庭堅','宋','宋诗','song-poetry','','[]','不生甘泉銅池邊，一莖九葉媚神天。',32,'全唐诗/poet.song.57000.json','["不生甘泉銅池邊，一莖九葉媚神天。", "伴余西去禦魑魅，馬湖江上看蠻船。"]'),
('ed60e0db-df25-4367-8553-f76478f4acc4','畫木石贊','黄庭堅','宋','宋诗','song-poetry','','[]','小山叢竹，到天古木。',20,'全唐诗/poet.song.57000.json','["小山叢竹，到天古木。", "石下有人，定是山谷。"]'),
('1b572489-5dfc-4a90-9ac2-8835cbd94bec','題崇德君所畫雀竹蜩螗圖贊','黄庭堅','宋','宋诗','song-poetry','','[]','蒿下蹄間，斥鷃飲啄。',40,'全唐诗/poet.song.57000.json','["蒿下蹄間，斥鷃飲啄。", "爭雄穹枝，竿網將作。", "蟬嘒竹間，自謂得己。", "螗螂從之，雞鳴不已。"]'),
('2a0f73fb-4210-4b59-834b-b3fd435b8914','綠菜贊','黄庭堅','宋','宋诗','song-poetry','','[]','蔡蒙之下，彼江一曲。',90,'全唐诗/poet.song.57000.json','["蔡蒙之下，彼江一曲。", "有茹生之，可以爲蔌。", "蛙蠙之衣，采采盈掬。", "吉蠲洗澤，不溷沙礫。", "芼以辛鹹，宜酒宜餗。", "在吳則紫，在蜀則綠。", "其臭味同，遠故不錄。", "誰其發之，班我旨蓄。", "維女博士，史君炎玉。"]'),
('24833898-d6a4-4ac8-bfa3-72e0b9fde4fd','劉元輔畫馬扇贊','黄庭堅','宋','宋诗','song-poetry','','[]','天材權奇，以龍爲友。',74,'全唐诗/poet.song.57000.json','["天材權奇，以龍爲友。", "玄黄虺隤，以脚支柱。", "與物殊絕，筆墨易取。", "至於庸庸，殆難爲工。", "然後知何時有古人之風。", "觀其雄雌，矜顧不進。", "庸中俊佼，駑中駿⿰馬旦邪。"]'),
('e957e7ef-36f0-419d-b57f-ea763b2d3e6b','禪頌','黄庭堅','宋','宋诗','song-poetry','','[]','自古多如此，君今獨奈何。',24,'全唐诗/poet.song.57000.json','["自古多如此，君今獨奈何。", "可來白雲裏，教汝紫芝歌。"]'),
('f8e23e86-719e-4c0f-a5f6-0164cc0631e6','壽禪師悟道頌','黄庭堅','宋','宋诗','song-poetry','','[]','樸落非他物，縱橫不是塵。',24,'全唐诗/poet.song.57000.json','["樸落非他物，縱橫不是塵。", "山河及大地，全露法王身。"]'),
('a907fb37-1cdb-434b-8923-ced0ea7982e9','與六祖長老頌','黄庭堅','宋','宋诗','song-poetry','','[]','昨夜三更，有人點燭。',68,'全唐诗/poet.song.57000.json','["昨夜三更，有人點燭。", "燒盡十方，天堂地獄。", "不知是誰家之子，都無面目。", "但只向深草中藏，莫向孤峰上宿。", "齋時有飯，天明有粥。", "自然而得，山青水綠。"]'),
('b7333758-4dfd-4206-8207-7ac00299e189','慈母巖亮長老頌','黄庭堅','宋','宋诗','song-poetry','','[]','敕書改律爲禪，意在無力宗空。',56,'全唐诗/poet.song.57000.json','["敕書改律爲禪，意在無力宗空。", "人欲破禪作律，羣兒更助之攻。", "莫恨塞翁失馬，會取楚人亡弓。", "老夫亦不掩耳，我來自聽松風。"]'),
('6b73eb28-280f-48ea-a00a-5ff7c6251482','和宣叔乞笋伽陀二頌  其一','黄庭堅','宋','宋诗','song-poetry','','[]','笋充庖，日百尾。',40,'全唐诗/poet.song.57000.json','["笋充庖，日百尾。", "千角鹿，九首虺。", "心生竅，渾沌死。", "搜中林，撅稚子。", "腹便便，老饕耳。"]'),
('f1fd86d3-3fb6-478e-9fd1-03ecdf9a409f','和宣叔乞笋伽陀二頌  其二','黄庭堅','宋','宋诗','song-poetry','','[]','收夏筤，四月尾。',40,'全唐诗/poet.song.57000.json','["收夏筤，四月尾。", "雨斑斑，雷虺虺。", "繭栗幡，觳𧥆死。", "數持來，勤老子。", "或遭駡，牆有耳。"]'),
('d52f146b-c2b3-4859-b60d-b3c974112187','戲呈峨眉僧正簡之頌','黄庭堅','宋','宋诗','song-poetry','','[]','普賢菩薩不來，山谷老人不去。',56,'全唐诗/poet.song.58000.json','["普賢菩薩不來，山谷老人不去。", "夜來月上勝峰，說盡薩提露布。", "驚起峨眉衲子，脚酸不到中路。", "杜鵑識甚鬧忙，剛道不如歸去。"]'),
('e02c6323-c6df-4bb9-ad77-f0a5be43ffc1','明叔惠示二頌云見七佛偈似有警覺乃是向道之端發於此故以二頌爲報  其一','黄庭堅','宋','宋诗','song-poetry','','[]','山川圍燕坐，日月轉庭隅。',48,'全唐诗/poet.song.58000.json','["山川圍燕坐，日月轉庭隅。", "般若心常是，如來卧起俱。", "多聞成外道，只守即凡夫。", "欲聽虛空鼓，須彌作鼓桴。"]'),
('4168dbd2-a79c-4dee-8fb3-faf06faef5fe','明叔惠示二頌云見七佛偈似有警覺乃是向道之端發於此故以二頌爲報  其二','黄庭堅','宋','宋诗','song-poetry','','[]','平生討經論，苦行峻廉隅。',48,'全唐诗/poet.song.58000.json','["平生討經論，苦行峻廉隅。", "僞契已無分，買山雲自俱。", "身爲廊廟宰，夢作種田夫。", "欲辨身兼夢，還如鼓與桴。"]'),
('2ffe7a26-aaf5-4a2c-bfb4-682d127adafa','化氈頌','黄庭堅','宋','宋诗','song-poetry','','[]','奪却羣生夏衣，成得衲僧卧具。',61,'全唐诗/poet.song.58000.json','["奪却羣生夏衣，成得衲僧卧具。", "爲伊業識茫茫，所以一奪一與。", "三百四百野狐隊，中有一兩箇不瞌睡。", "十方虛空百雜碎，寧不打破慳皮袋。"]'),
('9131997b-9022-4630-9fed-dff366987d29','失紫竹柱杖頌','黄庭堅','宋','宋诗','song-poetry','','[]','袁門西關失却柱杖，木平萬載縣裏拾得。',36,'全唐诗/poet.song.58000.json','["袁門西關失却柱杖，木平萬載縣裏拾得。", "恰似鄭州却出曹門，何處待此左科禪客。"]'),
('1138a6c7-0e99-4cbf-97d0-152dd5b34e30','竹頌','黄庭堅','宋','宋诗','song-poetry','','[]','深根藏器時，寸寸抱奇節。',24,'全唐诗/poet.song.58000.json','["深根藏器時，寸寸抱奇節。", "遭時上風雲，故可傲冰雪。"]'),
('b565e727-1c81-4dd6-9378-51149cf33be4','爲茭橋居士作念念即佛頌','黄庭堅','宋','宋诗','song-poetry','','[]','諸佛心內，衆生心心作佛。',52,'全唐诗/poet.song.58000.json','["諸佛心內，衆生心心作佛。", "衆生心中，諸佛念念證真。", "君言諸佛無相，山鬼窟裏安葬。", "即今十二時中，是誰隨波逐浪。"]'),
('2ca5c562-94ef-4e20-85d6-f293ac488cdb','寄清新二禪師頌  其一','黄庭堅','宋','宋诗','song-poetry','','[]','石公來斲鼻端塵，無手人來斧鑿親。',64,'全唐诗/poet.song.58000.json','["石公來斲鼻端塵，無手人來斧鑿親。", "白牯貍奴心即佛，銅睛虎眼主中賓。", "自携瓶去沽村酒，幻著衫來作主人。", "萬里相看如對面，死心寮裏有清新。"]'),
('3d960eba-8587-41b7-81b6-d84735a61d74','寄清新二禪師頌  其二','黄庭堅','宋','宋诗','song-poetry','','[]','死心寮裏有清新，把斷黄河塞要津。',64,'全唐诗/poet.song.58000.json','["死心寮裏有清新，把斷黄河塞要津。", "一段風濤驚徹底，箇中無我爾無人。", "夢驚蛇咬慞惶走，痛學尋毉□有神。", "此是如來正法藏，覺來牀上笑番身。"]'),
('06bff930-8819-4c1c-aea2-645375887de2','送黄龍曉禪師住觀音頌','黄庭堅','宋','宋诗','song-poetry','','[]','黄龍一卧十五年，攪潭驚起舊頭角。',96,'全唐诗/poet.song.58000.json','["黄龍一卧十五年，攪潭驚起舊頭角。", "張公攪潭是好心，但向西江起風雹。", "河陽新婦畫蛾眉，老婆不可重新學。", "長連体上鋪棘針，滿鉢飯飣鐵菱角。", "有能歡喜受供養，聰明一一安排著。", "張公若問解何宗，食月蝦蟆救月弓。"]'),
('e7c867a2-9ed1-4f21-b311-2d6cf402c974','雲居祐禪師燒香頌','黄庭堅','宋','宋诗','song-poetry','','[]','一身入定千身出，雲居不打這鼓笛。',32,'全唐诗/poet.song.58000.json','["一身入定千身出，雲居不打這鼓笛。", "虎馱太華入高麗，波斯鼻孔撐白日。"]'),
('8cc8a506-e536-4c21-bba7-1be7cbe72c7a','歸宗茶堂森明軒頌','黄庭堅','宋','宋诗','song-poetry','','[]','萬竹森然，莫非自己。',60,'全唐诗/poet.song.58000.json','["萬竹森然，莫非自己。", "作如是觀，可謂明矣。", "菁菁翠竹，來者得眼。", "其不得者，我亦無簡。", "助發此觀，亦有風雨。", "若問軒名，請與竹語。"]'),
('1be3d03f-fac7-4dc1-b766-dbde798f6665','送慧林明茶頭頌','黄庭堅','宋','宋诗','song-poetry','','[]','慧林有一老人，恰似銀甕盛雪。',112,'全唐诗/poet.song.58000.json','["慧林有一老人，恰似銀甕盛雪。", "徹底元無滲漏，旁觀但知皎潔。", "有徒三百二百，木鑽漫鑽磐石。", "或遇東海鯉魚，一棒令生羽翼。", "其餘兩兩三三，歸堂又要茶喫。", "上人南來雲水，因行不妨掉臂。", "鳳山修水東西，靈草春來滿地。", "但令己事相應，歸日馿馱不起。"]'),
('a8511b51-11ce-496b-8c0b-a65e621d48cd','題般若會疏頌','黄庭堅','宋','宋诗','song-poetry','','[]','六祖深禪獨脚，與盲抉開眼膜。',28,'全唐诗/poet.song.58000.json','["六祖深禪獨脚，與盲抉開眼膜。", "走人天下乞錢，涪翁放過一著。"]'),
('004e29a2-6313-4dce-80f2-c755bc5e3658','因六祖舉太和山語而成頌貴此話大行','黄庭堅','宋','宋诗','song-poetry','','[]','峨眉山中老，千頌自成集。',24,'全唐诗/poet.song.58000.json','["峨眉山中老，千頌自成集。", "持問太和山，鶻臭當風立。"]'),
('1cbd0d9d-7768-4012-900e-c782cf020747','墨蛇頌','黄庭堅','宋','宋诗','song-poetry','','[]','此書驚蛇入草，書成不知絕倒。',28,'全唐诗/poet.song.58000.json','["此書驚蛇入草，書成不知絕倒。", "自疑懷素前身，今生筆法更老。"]'),
('5d39737d-e2b9-4b60-baec-e58f641cc769','以香燭團茶琉璃獻花碗供布袋和尚頌  其一','黄庭堅','宋','宋诗','song-poetry','','[]','一鉢千家飯，孤身萬里浮。',24,'全唐诗/poet.song.58000.json','["一鉢千家飯，孤身萬里浮。", "知音若相問，不住涅槃州。"]'),
('b9aa94b3-a7a2-4903-bb4f-3adcadb3b32a','以香燭團茶琉璃獻花碗供布袋和尚頌  其二','黄庭堅','宋','宋诗','song-poetry','','[]','彌勒真彌勒，分身千百億。',24,'全唐诗/poet.song.58000.json','["彌勒真彌勒，分身千百億。", "若問下生時，不打這鼓笛。"]'),
('8668e99b-a534-406e-96f8-fada58fd6b0c','玉泉長老不受承天襯因作頌','黄庭堅','宋','宋诗','song-poetry','','[]','達摩從西來，不受梁武襯。',24,'全唐诗/poet.song.58000.json','["達摩從西來，不受梁武襯。", "却面少林牆，衣鉢一萬貫。"]'),
('ab92f5d3-b5ec-4ffa-bf55-7710de0679ed','不俗軒耐閒軒頌','黄庭堅','宋','宋诗','song-poetry','','[]','不愛孔方乃不俗，放下利欲是耐閒。',28,'全唐诗/poet.song.58000.json','["不愛孔方乃不俗，放下利欲是耐閒。", "棒打石獅子，論實不論虛。"]'),
('8c71cabb-96ec-49f6-a481-fac1f84aee48','東禪長老夢偈','黄庭堅','宋','宋诗','song-poetry','','[]','伐木丁丁斧下鳴，隔溪便應谷中聲。',32,'全唐诗/poet.song.58000.json','["伐木丁丁斧下鳴，隔溪便應谷中聲。", "不因蘋末微風起，漂影溪光本自明。"]'),
('f8153442-f8cf-4230-a0fd-5925d2cd55f8','次韵奉答南山禪師二頌兼呈琦上人  其一','黄庭堅','宋','宋诗','song-poetry','','[]','魚吼鐘鳴索飯錢，牧牛耕種別人田。',32,'全唐诗/poet.song.58000.json','["魚吼鐘鳴索飯錢，牧牛耕種別人田。", "淮師收得祖關在，一笛操江月滿船。"]'),
('d394d735-dd2e-4d65-ab3c-7e8c98cb522a','次韵奉答南山禪師二頌兼呈琦上人  其二','黄庭堅','宋','宋诗','song-poetry','','[]','南山四至分明也，一日元來十二時。',32,'全唐诗/poet.song.58000.json','["南山四至分明也，一日元來十二時。", "兩箇泥牛齊著力，矛頭淅米劍頭炊。"]'),
('77fc37bd-9bf5-4750-bbe9-6fb10b1f8b52','奉留楚金長老  其一','黄庭堅','宋','宋诗','song-poetry','','[]','長安甚鬧不須驚，好與牛兒著鼻繩。',32,'全唐诗/poet.song.58000.json','["長安甚鬧不須驚，好與牛兒著鼻繩。", "方便把他悲願滿，斬新然佛大明燈。"]'),
('75e35bd3-ec7f-472e-ae3b-305af4fbb7ca','奉留楚金長老  其二','黄庭堅','宋','宋诗','song-poetry','','[]','但將飯向無心椀，自有人扶折脚鐺。',32,'全唐诗/poet.song.58000.json','["但將飯向無心椀，自有人扶折脚鐺。", "不用重尋舊巢穴，胡蜂窠掛萬年藤。"]'),
('d62e4588-ef0a-4f9f-a945-9e55a9372018','長短星歌','黄庭堅','宋','宋诗','song-poetry','','[]','正月虎，七澤陰風無避處。',338,'全唐诗/poet.song.58000.json','["正月虎，七澤陰風無避處。", "少年射殺白額歸，二十一歲賜旗鼓。", "二月兔，翰墨功名歸四杜。", "中山毛遂定從還，十九上客誰復數。", "三月龍，定力降來一鉢中。", "昇騰便欲致雲雨，十六開士觀雲風。", "四月蛇，九蛇相輔成晉家。", "屈原離騷二十五，不及之推死怨嗟。", "五月馬，十五國風多詠寫。", "漢將西極天馬來，二十五城不當價。", "六月羊，十歲小兒牧道傍。", "他年叱石金華路，二十年前身姓黄。", "七月猴，恒山八命列封侯。", "當年傳國二十二，想是衣冠騎土牛。", "八月雞，二妙靈臺向曉啼。", "五更風雨十八九，殘月昏昏信可期。", "九月狗，三窟深坑四荒走。", "暮歸得兔十六七，黄盧朱雀皆在後。", "十月豬，白頭一笑獻士夫。", "殺身願爲魯津伯，申封蘭王十四都。", "十一月鼠，列十二辰配龍虎。", "二十二年看仙飛，一朝化作蝙蝠去。", "十二月牛，百戶椎肥醉九州。", "角端圍寸二十五，良弓之材牛带牛。"]'),
('5068a394-235f-41ad-9e57-843ad8343c7d','虛飄飄','黄庭堅','宋','宋诗','song-poetry','','[]','虛飄飄，虛飄飄，花飛不到地，虹起漫成橋。',60,'全唐诗/poet.song.58000.json','["虛飄飄，虛飄飄，花飛不到地，虹起漫成橋。", "入夢雲千疊，遊空絳萬條。", "蜃樓百尺聳滄海，雁字一行書絳霄。", "虛飄飄，北人生命猶堅牢。"]'),
('97428b95-1720-4168-a188-a3adeaab7155','南浦','黄庭堅','宋','宋诗','song-poetry','','[]','太守俱來此西山，樓觀重複半煙間。',32,'全唐诗/poet.song.58000.json','["太守俱來此西山，樓觀重複半煙間。", "高僧置酒林泉處，南浦名區望沒環。"]'),
('56efad1d-a761-45bd-a46c-13bbd3068dcf','結客','黄庭堅','宋','宋诗','song-poetry','','[]','結客結英豪，肯同兒女曹。',48,'全唐诗/poet.song.58000.json','["結客結英豪，肯同兒女曹。", "黄金粧珮劍，猛獸畫旗旄。", "北極狼星落，中原王氣高。", "終令賀蘭賊，不著赭黄袍。"]'),
('0f69f608-08c1-4d03-8acb-8a30136ff026','貴耳賤目謎','黄庭堅','宋','宋诗','song-poetry','','[]','馿耳對軒軒，爭酬價十千。',24,'全唐诗/poet.song.58000.json','["馿耳對軒軒，爭酬價十千。", "眈眈兩虎視，不值一文錢。"]'),
('dd558874-8bb3-4912-9dfb-67e11494dfcc','禪句二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','牽馿飲江水，鼻吹波浪起。',24,'全唐诗/poet.song.58000.json','["牽馿飲江水，鼻吹波浪起。", "岸上蹄踏蹄，水中嘴對嘴。"]'),
('863c83b4-93ae-4d54-aa56-5de72d69c7b6','禪句二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','予自釣魚船上客，偶除鬚鬢著袈裟。',32,'全唐诗/poet.song.58000.json','["予自釣魚船上客，偶除鬚鬢著袈裟。", "佛祖位中留不住，夜來依舊宿蘆花。"]'),
('7479ea14-41ad-4668-8d3c-6ad942734f80','題東丁水','黄庭堅','宋','宋诗','song-poetry','','[]','古人題作東丁水，自古東丁直到今。',32,'全唐诗/poet.song.58000.json','["古人題作東丁水，自古東丁直到今。", "我爲改名方響洞，要知山水有清音。"]'),
('2bd346c3-e6cc-49fe-9f84-7550952f4a75','文與可嘗云老僧墨竹一派近在湖州吾竹雖不及石似過之此一卷公案不可無魯直正句因次韵','黄庭堅','宋','宋诗','song-poetry','','[]','東坡雖是湖州派，竹石風流各一時。',32,'全唐诗/poet.song.58000.json','["東坡雖是湖州派，竹石風流各一時。", "前世畫師今姓李，不妨還作輞川詩。"]'),
('f7503021-663a-49de-9918-068f332e2862','出池藕花','黄庭堅','宋','宋诗','song-poetry','','[]','惜絲不肯織宮鞋，花月仙人謫下來。',64,'全唐诗/poet.song.58000.json','["惜絲不肯織宮鞋，花月仙人謫下來。", "河伯借泥封玉腕，風神翻浪沃香腮。", "無房不許僧歸宿，有蓋嘗令鷺自開。", "何事冤他結青女，一朝收拾付塵灰。"]'),
('0a898a91-bff3-424b-ab4c-eb46e0311abe','題孟浩然畫像','黄庭堅','宋','宋诗','song-poetry','','[]','先生少也隠鹿門，爽氣洗盡塵埃昏。',96,'全唐诗/poet.song.58000.json','["先生少也隠鹿門，爽氣洗盡塵埃昏。", "賦詩真可凌鮑謝，短褐豈愧公卿尊。", "故人私邀伴禁直，誦詩不顧龍鱗逆。", "風雲感會雖有時，顧此定知毋枉尺。", "襄江渺渺泛清流，梅殘臘月年年愁。", "先生一往今幾秋，後來誰復釣槎頭。"]'),
('10f047a0-a7b0-44e3-af87-3d75f9b790db','咏萍','黄庭堅','宋','宋诗','song-poetry','','[]','白髮已侵殘夢境，綠苔應憶舊漁磯。',32,'全唐诗/poet.song.58000.json','["白髮已侵殘夢境，綠苔應憶舊漁磯。", "桃源雞犬塵凡隔，韋曲桑麻念想歸。"]'),
('c859d0d3-dfc9-49ac-bd7a-f4563069045a','錢塘舊游','黄庭堅','宋','宋诗','song-poetry','','[]','薄宦飄然笑漫郎，瑟洲花草弄幽芳。',64,'全唐诗/poet.song.58000.json','["薄宦飄然笑漫郎，瑟洲花草弄幽芳。", "莫教景物添春色，轉覺山川是異鄉。", "南北峰巖空入夢，短長亭舍自相望。", "湖邊山寺清明後，相見蘭開禊水香。"]'),
('943017d6-1d11-47e3-af64-e03c7369e7b9','中秋','黄庭堅','宋','宋诗','song-poetry','','[]','灝氣才中兔魄圓，衆躔韜彩獨娟娟。',64,'全唐诗/poet.song.58000.json','["灝氣才中兔魄圓，衆躔韜彩獨娟娟。", "魏宮烏繞空枝上，漢苑桐凋露井前。", "金液萬重涵渤海，玉沙千里對江邊。", "遙知此夕多情思，三級蕭臺枕碧漣。"]'),
('de0ba3b0-489a-4e9a-a1cf-a4277b6bdffe','和孫莘老','黄庭堅','宋','宋诗','song-poetry','','[]','上帝羣玉府，道家蓬萊山。',96,'全唐诗/poet.song.58000.json','["上帝羣玉府，道家蓬萊山。", "延閣排霄起，圖書擅榮觀。", "宮槐綠葱葱，岑絕非世間。", "王度日修飭，文章麗朝班。", "國器攻杞梓，珍羣揜孔鸞。", "中臺省符移，僚屬禮數寬。", "品藻開英鑒，賞音發清彈。", "儒林數耆舊，少監髮新斑。"]'),
('6575184a-a696-4574-8d37-adc7164aebb8','宿錢塘尉廨','黄庭堅','宋','宋诗','song-poetry','','[]','平湖繞舍山無盜，官事長閑俸有金。',32,'全唐诗/poet.song.58000.json','["平湖繞舍山無盜，官事長閑俸有金。", "安得終身爲禦寇，不辭兒女作吳音。"]'),
('c2eaf1d4-6bc8-4965-9f7a-d9b8b326c768','吊死心禪師偈','黄庭堅','宋','宋诗','song-poetry','','[]','海風吹落楞伽山，四海禪徒著眼看。',32,'全唐诗/poet.song.58000.json','["海風吹落楞伽山，四海禪徒著眼看。", "一把柳絲收不得，和煙搭在玉欄干。"]'),
('c032ff07-1f83-4929-b264-f28ea62b35a4','衡山','黄庭堅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','萬丈融峰插紫霄，路當窮處架仙橋。',128,'全唐诗/poet.song.58000.json','["萬丈融峰插紫霄，路當窮處架仙橋。", "上觀碧落星辰近，下視紅塵世界遙。", "螺簇山低青點點，線拖遠水白迢迢。", "當門老檜枝難長，絕頂寒松葉不彫。", "纔到秋初霜已降，每逢春盡雪方消。", "猥岩老衲針常把，度夏禪僧扇懶摇。", "雷向池中興雨澤，鳥於窗外奏簫韶。", "游人未必長居此，暫借禪房宿兩宵。"]'),
('3a72aeee-bfa6-41be-ab72-3f99e9e88cf3','清心院雙清軒','黄庭堅','宋','宋诗','song-poetry','','[]','萬劫千峰繞座隅，一泓澄澈見遊鱼。',64,'全唐诗/poet.song.58000.json','["萬劫千峰繞座隅，一泓澄澈見遊鱼。", "誰家欄檻烟雲裏，坐我瀟湘水墨圖。", "人物度橋疑海市，樓臺拍水信蓬壺。", "潺湲枕底催鄉夢，雙井溪頭有舊廬。"]'),
('39ba9f1a-9c9d-4d99-a521-dbe688cab43c','香爐峰','黄庭堅','宋','宋诗','song-poetry','','[]','香爐不鑄石陶甄，鼻不聞香眼見烟。',32,'全唐诗/poet.song.58000.json','["香爐不鑄石陶甄，鼻不聞香眼見烟。", "上有文殊師利塔，好將一瓣此中燃。"]'),
('3ee92d58-27e2-4a2a-9e01-ae11de3eab4f','白鶴觀','黄庭堅','宋','宋诗','song-poetry','','[]','複殿重樓墮杳冥，故基喬木尚崢嶸。',64,'全唐诗/poet.song.58000.json','["複殿重樓墮杳冥，故基喬木尚崢嶸。", "銀河不改三千尺，鐵馬曾經十萬兵。", "華表故應終化鶴，謫仙未解獨騎鯨。", "林泉一二兒童舊，白髮衰顔只自驚。"]'),
('adaa33b6-0e0b-440c-b1c6-3ac794f453de','游張公洞','黄庭堅','宋','宋诗','song-poetry','','[]','古洞深沉白晝間，煙霞出沒絕塵寰。',64,'全唐诗/poet.song.58000.json','["古洞深沉白晝間，煙霞出沒絕塵寰。", "落紅滿地花初歇，啼鳥一聲春自閒。", "丹竈苔荒仙去遠，松壇月冷鶴飛還。", "我來幾欲重登眺，削壁題詩興不慳。"]'),
('a0fded85-fc01-4b60-b528-83d0aa8df263','東林寺二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','白蓮種出凈無塵，千古風流社裏人。',32,'全唐诗/poet.song.58000.json','["白蓮種出凈無塵，千古風流社裏人。", "禪律定知誰束縛，過溪沽酒見天真。"]'),
('9fb07468-b4ef-4f41-acbe-4a4c17f570eb','東林寺二首  其二','黄庭堅','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','勝地東林十八公，廬山千古一清風。',32,'全唐诗/poet.song.58000.json','["勝地東林十八公，廬山千古一清風。", "淵明豈是難拘束，正與白蓮出處同。"]'),
('dd858b18-fd8b-497e-98ca-f1e3eb6c8da2','玉笥山','黄庭堅','宋','宋诗','song-poetry','','[]','上天下地似探梯，怪石巉巖襯馬蹄。',32,'全唐诗/poet.song.58000.json','["上天下地似探梯，怪石巉巖襯馬蹄。", "擬是客程行不得，隔林猶聽杜鵑啼。"]'),
('e38bc2f1-9026-435a-a279-824c29694728','詩一首','黄庭堅','宋','宋诗','song-poetry','','[]','石磴層層鳥道斜，仙家樓閣鎖煙霞。',64,'全唐诗/poet.song.58000.json','["石磴層層鳥道斜，仙家樓閣鎖煙霞。", "丹砂已化黄金鼎，玉洞猶開白鶴花。", "鐵簡有雲神永護，金鐘無韵鬼曾楂。", "洞天福地陰陽合，勝事留傳豈浪誇。"]'),
('d7eda8c2-5124-46f7-bed6-de1a7178e50a','秀江亭','黄庭堅','宋','宋诗','song-poetry','','[]','因循不到此江頭，匹馬黄埃三十秋。',64,'全唐诗/poet.song.58000.json','["因循不到此江頭，匹馬黄埃三十秋。", "舊舍只今人共老，清波常與月分流。", "羨君瀟洒成佳趣，感我凄凉念舊遊。", "沽酒買魚終不負，何時相與泛扁舟。"]'),
('8021f0e5-750c-48a5-ab19-fe8ac13b5a97','大秀宮','黄庭堅','宋','宋诗','song-poetry','','[]','玉笥山前大白峰，望仙橋下水溶溶。',64,'全唐诗/poet.song.58000.json','["玉笥山前大白峰，望仙橋下水溶溶。", "前溪流水後溪月，五步白雲三步松。", "半夜珮環朝上闕，插天樓閣度疏鐘。", "夢餘彷彿鈞天奏，如在蓬萊第幾重。"]'),
('e603bca9-bc04-4c28-9359-1e45418e6553','全州雙松堂','黄庭堅','宋','宋诗','song-poetry','','[]','文殊堂下松，永日如鳴琴。',36,'全唐诗/poet.song.58000.json','["文殊堂下松，永日如鳴琴。", "我登雙松堂，時步雙松陰。", "中有寂莫人，安禪無古今。"]'),
('5362469d-fe88-44b3-ba28-f86afdb5798c','古意','黄庭堅','宋','宋诗','song-poetry','','[]','太華峰頭玉井蓮，開花十丈藕如船。',64,'全唐诗/poet.song.58000.json','["太華峰頭玉井蓮，開花十丈藕如船。", "冷比雪霜甘比蜜，一片入口沉痾痊。", "我欲求之不憚遠，青壁無路難夤緣。", "安得長梯上摘食，下種七澤根株連。"]'),
('e04469d1-80bd-4377-9a51-3bd21aa095c5','塞上曲','黄庭堅','宋','宋诗','song-poetry','','[]','十月北風燕草黄，燕人馬肥弓力强。',64,'全唐诗/poet.song.58000.json','["十月北風燕草黄，燕人馬肥弓力强。", "虎皮裁鞍鵰羽箭，射殺山陰雙白狼。", "青氈帳高雪不濕，擊鼓傳觴令行急。", "戎王半醉擁貂裘，昭君猶抱琵琶泣。"]'),
('c1363a8a-20d9-4d6d-9c54-18264c0fc8c3','次韵謝借觀五老圖','黄庭堅','宋','宋诗','song-poetry','','[]','五老天然一會閒，太平時節振儒冠。',64,'全唐诗/poet.song.58000.json','["五老天然一會閒，太平時節振儒冠。", "相君于理回天詔，輔國驅夷立塞桓。", "妖術圖奸梁木壞，黨碑雷震雹冰寒。", "丹心忠厚來安泰，惠澤垂流仰止看。"]'),
('0e25ccce-e10a-4baf-bdc9-98f5b4e83715','楊凝式行書','黄庭堅','宋','宋诗','song-poetry','','[]','俗書祇識蘭亭面，欲換凡骨無金丹。',32,'全唐诗/poet.song.58000.json','["俗書祇識蘭亭面，欲換凡骨無金丹。", "誰知洛陽楊風子，下筆便到烏絲闌。"]'),
('9182287c-e2c0-484c-a7a6-43fdd93fd3b0','法語','黄庭堅','宋','宋诗','song-poetry','','[]','兀然無事無改換，無事何須論一段。',316,'全唐诗/poet.song.58000.json','["兀然無事無改換，無事何須論一段。", "真心無散亂，他事不須斷。", "過去已過去，未來何用算。", "兀然無事何曾有，人喚向外覓工夫，總是癡頑漢。", "糧不蓄一粒，逢飯但知駡。", "世間多事，人事相趁。", "渾不及我，不樂生天，亦不受福田。", "饑來一缽飯，困來展脚眠。", "愚人以爲笑，智者謂之然。", "非愚亦非智，不是玄中玄。", "要去如是去，要住如是住。", "身披一破衲，脚著娘生袴。", "多言復多語，由來反相誤。", "若欲度衆生，無過且自度。", "莫漫求真佛，真佛不可見。", "妙性及靈臺，何曾受薰鍊。", "心是無事心，面是娘生面。", "劫石可動摇，箇中無改變。", "無事何須讀文字，削除人我本，冥合箇中意。", "種種勞筋骨，不如林下睡兀兀。", "舉頭見日出，乞飯從頭𢫫。", "將功用功，展轉冥蒙。", "取即不得，不取自通。", "吾有一言，絕慮忘緣，巧說不得用心傳。"]'),
('666ab784-a601-4eee-8deb-37a2a9f334b3','慈竹','黄庭堅','宋','宋诗','song-poetry','','[]','門中何物靈，有竹慈爲名。',288,'全唐诗/poet.song.58000.json','["門中何物靈，有竹慈爲名。", "一叢澗數步，森森數十莖。", "長莖覆短莖，枝葉不崢嶸。", "去年筍已長，今年筍又生。", "高低相倚向，渾如長幼情。", "孝子侍父立，順孫隨祖行。", "居然抱慈孝，根底信天成。", "吾聞唐之人，孝行常欣欣。", "鄆州張公藝，九代同一門。", "大帝聞其名，衡茅降至尊。", "馮宿丱歲時，隨父廬祖墳。", "父子相隨孝，靈芝特地春。", "北海呂元簡，四世同家主。", "以至牛馬羊，異母皆相乳。", "虞鄉董公直，鞠養諸孤遺。", "鸜鵒與鴉鵲，同巢而共枝。", "孝行動天壤，鳥獸皆隨時。", "又聞猓𤡮獸，死不相棄離。", "𧑒蝎與蛟魚，子母長相隨。", "獸面而人心，此獸信有之。", "獸心而人面，其人誠可悲。", "李鈞爲侍御，棄母在□州。", "母因殍餓死，世□何悠悠。", "光祿李□者，亦是斯人流。"]'),
('a2afc286-f6df-48cb-a018-60a2d60136af','三言二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','寄岳雲，安九夏。',32,'全唐诗/poet.song.58000.json','["寄岳雲，安九夏。", "無間綠，實瀟灑。", "碧溪頭，古松下。", "卧槃陀，晝復夜。"]'),
('5b74e540-0f72-43b9-a3bb-3eb13578dea7','三言二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','八德水，清且美。',32,'全唐诗/poet.song.58000.json','["八德水，清且美。", "盪精神，浸牙齒。", "亂雲根，衆峰裏。", "掬與斟，隨器爾。"]'),
('4103d07c-2518-408f-80ea-b9d29758be2b','頭陀贊','黄庭堅','宋','宋诗','song-poetry','','[]','梵語頭陀，華言抖擻。',240,'全唐诗/poet.song.58000.json','["梵語頭陀，華言抖擻。", "浄一真心，振三毒垢。", "如來親試，迦葉稱首。", "聖教推崇，哲人遵守。", "衣三食四，住處五名。", "曰十二行，對治修行。", "十三或八，要以三并。", "練磨三境，攝化三乘。", "起四歡喜，行四聖種。", "以戒爲基，止觀相踵。", "大矩崇規，鍊金烹礦。", "號菩薩僧，志惟堅勇。", "知足少欲，伏我受根。", "無取無著，情絕所存。", "若有讚者，同讚世尊。", "續佛慧命，開佛正門。", "在昔能仁，囑付彌勒。", "守護三寶，後五百歲。", "彌勒稱揚，此行爲最。", "適當其時，應身出世。", "阿蘭若處，作衆依歸。", "則先賢軌，髮薙肩垂。", "白麻劫貝，不隨染衣。", "表如玉雪，不受塵泥。"]'),
('d8f748d9-bb4f-45c6-b901-6694bc1e9545','絕句','黄庭堅','宋','宋诗','song-poetry','','[]','花氣薰人欲破禪，心情其實過中年。',32,'全唐诗/poet.song.58000.json','["花氣薰人欲破禪，心情其實過中年。", "春來詩思何所似，八節灘頭上水船。"]'),
('13465a85-d104-413d-9a73-0831fc2f3249','題襄陽米芾祠  其一','黄庭堅','宋','宋诗','song-poetry','','[]','千峰映碧湘，真叟此中藏。',48,'全唐诗/poet.song.58000.json','["千峰映碧湘，真叟此中藏。", "飯不着石喫，眉應似髮長。", "楓梩搘酒甕，鸐風落琴牀。", "强效忘機者，斯人尚未忘。"]'),
('d9011d0c-b6c0-44b0-840b-e3737fd00d76','題襄陽米芾祠  其二','黄庭堅','宋','宋诗','song-poetry','','[]','萬里莓苔地，不見驅馳蹤。',48,'全唐诗/poet.song.58000.json','["萬里莓苔地，不見驅馳蹤。", "唯開文字窗，時寫日月容。", "竹韵漫蕭屑，草花徒織茸。", "披霜入衆木，獨自識青松。"]'),
('8568bcf4-bf0c-48a9-b1b5-5508518901a4','次韵梨花','黄庭堅','宋','宋诗','song-poetry','','[]','桃花人面各相紅，不及天然玉作容。',32,'全唐诗/poet.song.58000.json','["桃花人面各相紅，不及天然玉作容。", "總向風塵塵莫染，輕輕籠月倚牆東。"]'),
('5fd55792-93ca-444e-a359-957c9e5a082e','戒殺詩','黄庭堅','宋','宋诗','song-poetry','','[]','我肉衆生肉，名殊體不殊。',48,'全唐诗/poet.song.58000.json','["我肉衆生肉，名殊體不殊。", "原同一種性，只是別形軀。", "苦惱從他受，肥甘爲我須。", "莫教閻老斷，自揣應何如。"]'),
