('e1c8de94-61fd-4ee6-a396-be4d2b68b5c9','縣齋 弦歌堂','朱之純','宋','宋诗','song-poetry','','[]','洋洋百里起嘔吟，惠化薰陶谷水陰。',64,'全唐诗/poet.song.58000.json','["洋洋百里起嘔吟，惠化薰陶谷水陰。", "明月詩函三島秀，清風曲奏一堂深。", "武城浪說言游道，單父休誇子賤音。", "政敏誰知過齊國，想君真得古人心。"]'),
('d3083352-2736-434e-b195-1239c1b7e067','縣齋 三山亭','朱之純','宋','宋诗','song-poetry','','[]','俗易風移古道還，縣齋疊石作三山。',64,'全唐诗/poet.song.58000.json','["俗易風移古道還，縣齋疊石作三山。", "因憐席上紅塵少，贏得壺中白日閑。", "想見六鼇擎水下，坐看雙鶴落雲間。", "何須更叩黄金闕，只此幽亭是玉關。"]'),
('36b952d5-468b-400c-89e8-9615c24b75ba','縣齋 艮閣','朱之純','宋','宋诗','song-poetry','','[]','畫閣峨然冠翠巒，更占艮地特巑岏。',64,'全唐诗/poet.song.58000.json','["畫閣峨然冠翠巒，更占艮地特巑岏。", "曉窗高揖東風暖，夜幕低垂北斗寒。", "突兀狀驚青蜃吐，徘徊勢若老龍蟠。", "嗟予勁節非徐子，那得陳侯一榻看。"]'),
('00a4a7cf-4d74-4945-8154-2bab6b0e407a','思吳堂','朱之純','宋','宋诗','song-poetry','','[]','畫堂重構一湖中，更述民思渤海公。',64,'全唐诗/poet.song.58000.json','["畫堂重構一湖中，更述民思渤海公。", "自昔三年留惠政，至今百里誦清風。", "波間𨺗覺歡聲別，陌上新傳樂事同。", "從此邦人轉懷德，悠悠谷水幾時窮。"]'),
('19f922db-3bc7-4ca4-867f-c38d78f3b4ea','湖齋','朱之純','宋','宋诗','song-poetry','','[]','平湖十頃水汪洋，得意茅齋且屈藏。',64,'全唐诗/poet.song.58000.json','["平湖十頃水汪洋，得意茅齋且屈藏。", "園種小桃今結子，池栽翠芰更聞香。", "六龜已兆千年瑞，雙鶴看呈八月祥。", "居此倏然忘世味，此心尤懶去龍陽。"]'),
('ee5dc0bb-df40-4088-9885-f70d4683629e','客宛陵遇鄉人作集句','王吉甫','宋','宋诗','song-poetry','','[]','揚子江頭楊柳春，衣冠南渡多崩奔。',64,'全唐诗/poet.song.58000.json','["揚子江頭楊柳春，衣冠南渡多崩奔。", "柳條弄色不忍見，東西南北更堪論。", "誰謂他鄉各異縣，豈知流落復相見。", "青春作伴好還鄉，爲問淮南米貴賤。"]'),
('4293a600-d080-492c-8102-e7f60f2f2af7','送羅正之年兄出使二浙','范鉞','宋','宋诗','song-poetry','','[]','紫泥封詔出蓬萊，且指東南倚憲臺。',64,'全唐诗/poet.song.58000.json','["紫泥封詔出蓬萊，且指東南倚憲臺。", "千里忽驚霜斧去，百城爭望錦衣來。", "淛江氣象心先到，吳俗姦媮膽欲摧。", "天姥舊山還好在，應尋鄉老一裴徊。"]'),
('d9187a46-ee4d-451c-a31c-fff06c9816fc','碧光亭','程之邵','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','寺壓高臺最上頭，一亭新就得清遊。',64,'全唐诗/poet.song.58000.json','["寺壓高臺最上頭，一亭新就得清遊。", "天連遠岫交相碧，地枕長江分外幽。", "烟際晴光渾不斷，望中詩思浩難收。", "公餘幸有賓朋樂，聊把狂篇索唱酬。"]'),
('da6544cf-d056-41c8-b392-40946f98b92b','遇雪偶書','程之邵','宋','宋诗','song-poetry','','[]','三伏登途徹盛寒，客程猶未解征鞍。',32,'全唐诗/poet.song.58000.json','["三伏登途徹盛寒，客程猶未解征鞍。", "明時用捨皆公道，自是非才進路難。"]'),
('4f3be237-27e0-4c6f-bd03-72208d02d550','遊碧落洞','陳履','宋','宋诗','song-poetry','','[]','碧落傳聞久，茲來列彥同。',48,'全唐诗/poet.song.58000.json','["碧落傳聞久，茲來列彥同。", "草沾遊士屐，臺挹大王風。", "一澗流元始，雙崖鑿混濛。", "天然自奇絕，不惜五丁功。"]'),
('ad0c916e-a415-4300-ad57-24100e5e6c7c','句','廖蒙','宋','宋诗','song-poetry','','[]','疊嶂秋光淺，寒松古韵清。',12,'全唐诗/poet.song.58000.json','["疊嶂秋光淺，寒松古韵清。"]'),
('d4e3dd6b-28b9-4a66-ada5-f2092ac1ed2f','崇寧乙酉元巳率同僚修禊於七星巖','張漸','宋','宋诗','song-poetry','','[]','妙意其誰運大鈞，玲瓏奧室闢天真。',64,'全唐诗/poet.song.58000.json','["妙意其誰運大鈞，玲瓏奧室闢天真。", "斗臨北地精初結，龍去丹霄穴未湮。", "洪造故教虛待物，良辰贏得樂同民。", "我來禊有自然興，豈羨蘭亭曲水濱。"]'),
('43875b3f-e62a-435f-8ea1-d24090c14664','句','上官彝','宋','宋诗','song-poetry','','[]','虎頭峭立何巉巉，下有百本松與杉。',16,'全唐诗/poet.song.58000.json','["虎頭峭立何巉巉，下有百本松與杉。"]'),
('9c8c1c37-d892-4fe7-a1ac-38fde5bca3e1','題方氏清芬閣','朱彥','宋','宋诗','song-poetry','','[]','干戈唐季風塵中，一代文章掃地空。',179,'全唐诗/poet.song.58000.json','["干戈唐季風塵中，一代文章掃地空。", "先生詩鳴最晚出，句法未減元和工。", "玉壺藏冰不受垢，卜隠宛蹈嚴陵蹤。", "至今名字照人目，直與山水爲無窮。", "我舟南紀坐煩促，接歲風波仍轉蓬。", "緬懷先生酌溪水，梅花如霰落晚風。", "清芬築室家有法，亦見裔孫白雲翁。", "叔今策得待三接，仲也昔跨御史驄。", "乃翁歸來三十載，語笑但覺朱顔紅。", "翁不見東飛百勞西飛燕，南飛烏鵲北飛鴻。", "人生游宦正如此，我欲買田歸江東。"]'),
('a93d73ca-3a12-4a54-baee-c33e50d7e0a8','題嚴子陵釣臺','朱彥','宋','宋诗','song-poetry','','[]','泊舟釣臺側，敬謁嚴子陵。',120,'全唐诗/poet.song.58000.json','["泊舟釣臺側，敬謁嚴子陵。", "碧山如佩環，水作鏘然聲。", "定知千載後，尚復有遺靈。", "長嘯明月下，緬懷今古情。", "世利濁於酒，末俗遭塵冥。", "毫髮不一直，戈矛豈相爭。", "先生得高蹈，萬鈞獨可輕。", "持釣偶自適，潜魚不吞醒。", "清風在人耳，凜凜見典刑。", "不如臺下水，方可濯塵纓。"]'),
('9214e2e8-60f4-4ddf-9e5f-908586d7a0c3','寒光閣','朱彥','宋','宋诗','song-poetry','','[]','駕舟掠杭越，小泊清溪門。',132,'全唐诗/poet.song.58000.json','["駕舟掠杭越，小泊清溪門。", "平生江令尹，邀我谿南園。", "丹碧氣成霞，樓疏何鬰盤。", "江城春事起，臘候已向殘。", "的皪小梅花，暗香媚山樊。", "冰髯絕可愛，青士聯蒼官。", "君家藝蘭畹，歲久蘭有蓀。", "我生真漫浪，嗜好無一存。", "尚作山水想，十年勞夢魂。", "歷眼滄洲趣，茲盟那可寒。", "他年釣竿手，來傍沈郎灘。"]'),
('e8461f8c-c253-4af3-8bc2-a0c6bf0de2a1','麻姑山','朱彥','宋','宋诗','song-poetry','','[]','羽駕龍車舊宅，金爐玉簡幽宮。',70,'全唐诗/poet.song.58000.json','["羽駕龍車舊宅，金爐玉簡幽宮。", "雙練亭前秋水，七星杉下春風。", "蓮沼何年變白，桃源幾度翻紅。", "明月清陰軒上，星冠羽褐髯翁。", "一弄瑶池新曲，夜寒風入霜松。"]'),
('9f96498f-032d-4503-a622-50cd6d9d14c3','江樓','朱彥','宋','宋诗','song-poetry','','[]','麻源山壓盱江水，江樓迥對江山起。',96,'全唐诗/poet.song.58000.json','["麻源山壓盱江水，江樓迥對江山起。", "波平月滿千里空，金斗欄干露如洗。", "此時想見一尊開，杳杳征帆破浪來。", "揮毫寫盡江山景，何有飄零庾信哀。", "自憐久作紅塵客，夢斷江南烟水白。", "會歌黄鵠賦前溪，不作區區吟越舄。"]'),
('5cb846b8-1eaa-48ce-a375-3879531632f8','安仁寺','朱彥','宋','宋诗','song-poetry','','[]','一洞寒雲鎖翠虬，水聲長遶影邊流。',32,'全唐诗/poet.song.58000.json','["一洞寒雲鎖翠虬，水聲長遶影邊流。", "令人坐憶南泉路，滿目春山幾萬秋。"]'),
('e846464b-6245-4772-903c-1f7e7b704bc3','游黄山','朱彥','宋','宋诗','song-poetry','','[]','三十六峰高插天，瑶臺瓊宇貯神僊。',32,'全唐诗/poet.song.58000.json','["三十六峰高插天，瑶臺瓊宇貯神僊。", "嵩陽若與黄山並，猶欠靈砂一道泉。"]'),
('2cac8d71-9b4a-45e7-8def-302eacb6b705','讀齊雲院碑有感','朱彥','宋','宋诗','song-poetry','','[]','玉像傳香火，金鐘警旦昏。',48,'全唐诗/poet.song.58000.json','["玉像傳香火，金鐘警旦昏。", "建藍知有自，種德豈無門。", "善力歸慈母，餘波到遠孫。", "拂碑今日淚，揮灑舊松根。"]'),
('df246b45-b992-44c9-bec0-4a32b5155481','寄弟迪','徐遘','宋','宋诗','song-poetry','','[]','杜雲姜被每相思，物換星移又一期。',64,'全唐诗/poet.song.58000.json','["杜雲姜被每相思，物換星移又一期。", "知汝再尋鸚鵡賦，起予深念鶺鴒詩。", "山寒久厭猿啼苦，水闊那堪雁到遲。", "好約春風共携手，玉壺沽酒繫青絲。"]'),
('1da9ae4f-956d-42b2-88c2-a38c452044ea','題李公麟畫歸去來圖','陳師錫','宋','宋诗','song-poetry','','[]','百中神鋒誇妙手，當時破敵祗因機。',32,'全唐诗/poet.song.58000.json','["百中神鋒誇妙手，當時破敵祗因機。", "餘花墮裓無人見，半偈流傳豈易知。"]'),
('c647e32b-8ad4-4220-85b4-40c85c0cffbd','句  其一','陳師錫','宋','宋诗','song-poetry','','[]','金馬舊遊三學士，玉麟交政兩諸侯。',16,'全唐诗/poet.song.58000.json','["金馬舊遊三學士，玉麟交政兩諸侯。"]'),
('e5f86dd8-0a46-4bdd-94a7-886bd4635b0c','句  其二','陳師錫','宋','宋诗','song-poetry','','[]','溪門寂寞無人到，只有清風獨自來。',16,'全唐诗/poet.song.58000.json','["溪門寂寞無人到，只有清風獨自來。"]'),
('916b8517-0fc3-4984-adee-fbb589a0dff6','劍池','徐輔','宋','宋诗','song-poetry','','[]','劍去池空水自寒，游人到此凭欄桿。',32,'全唐诗/poet.song.58000.json','["劍去池空水自寒，游人到此凭欄桿。", "年來自是銷磨盡，只有青山好靜看。"]'),
('2a36463c-c27d-4e0e-a131-73dd548c984e','朱氏天和堂','徐鐸','宋','宋诗','song-poetry','','[]','先生晦迹谷水東，志趣不與晉賢同。',96,'全唐诗/poet.song.58000.json','["先生晦迹谷水東，志趣不與晉賢同。", "遥聽鶴唳笑二陸，巢傾穴碎非爲工。", "浩然養素遠聲利，脫去羈束離樊籠。", "醉隠亭中三十載，桃紅李白搖春風。", "感時嘯詠聊自適，誰知富貴爲窮通。", "羨君高操超流俗，直疑變姓稱朱公。"]'),
('c1a205b4-7f81-4ca7-9008-18e4b63e5a85','詠東溪碧波亭','姚孳','宋','宋诗','song-poetry','','[]','頼簡池臺兩蜀誇，東溪別是一仙家。',32,'全唐诗/poet.song.58000.json','["頼簡池臺兩蜀誇，東溪別是一仙家。", "令人却憶康王谷，坐看珠簾濺雨花。"]'),
('da469eb8-d397-43bc-855e-866f1b35391d','金雞關','姚孳','宋','宋诗','song-poetry','','[]','甘露靈根不老，爾朱丹竈空存。',28,'全唐诗/poet.song.58000.json','["甘露靈根不老，爾朱丹竈空存。", "三十六蒙好處，倚欄役破詩魂。"]'),
('17e4b1fc-915d-49b5-82a0-37ea5c0bef8c','石橋','姚孳','宋','宋诗','song-poetry','','[]','萬派鏗鞫走電車，跨巖蚴蟉玉虹斜。',32,'全唐诗/poet.song.58000.json','["萬派鏗鞫走電車，跨巖蚴蟉玉虹斜。", "靈禽飛下傳消息，五百甌心結茗花。"]'),
('88f9684f-e837-4319-b3e3-4b8a3cb0f83a','國清寺','姚孳','宋','宋诗','song-poetry','','[]','梵宮四面五峰巑，兜率臺高倚翠巒。',32,'全唐诗/poet.song.58000.json','["梵宮四面五峰巑，兜率臺高倚翠巒。", "會有寒山重到此，倩誰試與問豐干。"]'),
('d0651f63-70aa-4c50-a96b-c215a4a6fd2b','鳴山巖','林豫','宋','宋诗','song-poetry','','[]','青山招隠桂叢高，五十年來姓字逃。',64,'全唐诗/poet.song.58000.json','["青山招隠桂叢高，五十年來姓字逃。", "春雨晴時星欲洗，晚雷殷處水生濤。", "關門不鎖空玄室，花徑無媒自碧桃。", "安得飄颻塵外事，胡麻白日飯吾曹。"]'),
('a6c3f4fc-d504-4b8b-a3a9-466ebe7b04cb','冷泉','林稹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一泓清可沁詩脾，冷暖年來只自知。',32,'全唐诗/poet.song.58000.json','["一泓清可沁詩脾，冷暖年來只自知。", "流向西湖載歌舞，回頭不似在山時。"]'),
('9d0afc9f-8b78-4ede-a7c3-1d388e8bd121','石橋','樓光','宋','宋诗','song-poetry','','[]','溪流長卷千重玉，茗碗齊開五百花。',32,'全唐诗/poet.song.58000.json','["溪流長卷千重玉，茗碗齊開五百花。", "方廣只留方寸地，不須辛苦上仙槎。"]'),
('74729c30-4301-4d62-84b0-def836635cda','過臨淄','李格非','宋','宋诗','song-poetry','','[]','擊鼓吹竽七百年，臨淄城闕尚依然。',32,'全唐诗/poet.song.58000.json','["擊鼓吹竽七百年，臨淄城闕尚依然。", "如今只有耕耘者，曾得當時九府錢。"]'),
('f6a1e39f-c580-4ed2-b9f2-0459ccfe1e2b','試院','李格非','宋','宋诗','song-poetry','','[]','斗暄成小疾，亦稍敗吾勤。',24,'全唐诗/poet.song.58000.json','["斗暄成小疾，亦稍敗吾勤。", "定是朱衣吏，乘時欲舞文。"]'),
('7ec1cccf-e2cd-47e8-a6d9-e14b5dfe60a5','初至象郡  其一','李格非','宋','宋诗','song-poetry','','[]','裨海環□□，□□□□國。',84,'全唐诗/poet.song.58000.json','["裨海環□□，□□□□國。", "世人持兩足，遽欲窮畛域。", "心知禹分土，未盡舜所涉。", "吾遷桂嶺外，仰亦見斗極。", "升高臨大路，郵傳數南北。", "山川來時經，草樹略已識。", "枝床歸夢長，鄉堠行歷歷。"]'),
('9024dd56-c21d-4181-be2c-246f42f4bbf5','初至象郡  其二','李格非','宋','宋诗','song-poetry','','[]','去日有近遠，寒暑乃不同。',96,'全唐诗/poet.song.58000.json','["去日有近遠，寒暑乃不同。", "手捉而喙飲，嗜慾南北通。", "是邦亦洙泗，人可牛與弓。", "良知盡虛市，妙質老耕農。", "彼時張曲江，此時余襄公。", "二子稍穎脫，一洗凡馬空。", "斯文隔裔土，後生昧華風。", "閩中要常衮，劍外須文翁。"]'),
('1728c49e-faad-4500-bc36-a59f29f28915','初至象郡  其三','李格非','宋','宋诗','song-poetry','','[]','秦扁不南遊，醫方略嵐嶂。',60,'全唐诗/poet.song.58000.json','["秦扁不南遊，醫方略嵐嶂。", "茅黄秋兩淫，與瘧蓋同狀。", "咒師烏能神，適市半扶杖。", "吾欲養黄婆，母壯子亦王。", "妙藥只眼前，乞汝保無恙。"]'),
('f5a85149-9b5e-4b2c-ba0b-0612c45ad5d2','初至象郡  其四','李格非','宋','宋诗','song-poetry','','[]','居近城南樓，步月時散策。',72,'全唐诗/poet.song.58000.json','["居近城南樓，步月時散策。", "小市早收燈，空山晚吹笛。", "兒呼翁可歸，恐我意慘戚。", "從來堅道念，老去倦形役。", "天其卒相予，休以南荒謫。", "宴坐及此時，聊觀鼻端白。"]'),
('38ac1a6c-7e4f-456c-83d6-cd4c4fa143ae','絕句  其一','李格非','宋','宋诗','song-poetry','','[]','步履江村霧雨寒，竹間門巷繫黄團。',32,'全唐诗/poet.song.58000.json','["步履江村霧雨寒，竹間門巷繫黄團。", "猶嫌骯髒驚魚鳥，父老相呼擁道看。"]'),
('3df10f09-ef06-4614-8682-b6f8fa21fb2e','絕句  其二','李格非','宋','宋诗','song-poetry','','[]','八尺方床織白藤，含風漪裏睡瞢騰。',32,'全唐诗/poet.song.58000.json','["八尺方床織白藤，含風漪裏睡瞢騰。", "若無萬里還家夢，便是三湘退院僧。"]'),
('e33f4990-fe69-4692-a7fe-a3a1195d4aa2','駕幸太學倡和','李格非','宋','宋诗','song-poetry','','[]','日月天回十二章，詔移清蹕幸膠庠。',64,'全唐诗/poet.song.58000.json','["日月天回十二章，詔移清蹕幸膠庠。", "六龍穩轉橋門曲，多士橫穿錦仗行。", "俎豆威儀瞻闕里，東西風教自周王。", "太平誰謂初無象，四海形容在一堂。"]'),
('d9f2807c-4335-41df-8556-c5b389304cbf','句  其一','李格非','宋','宋诗','song-poetry','','[]','邴吉勳勞猶未報，衛公精爽僅能歸。',16,'全唐诗/poet.song.58000.json','["邴吉勳勞猶未報，衛公精爽僅能歸。"]'),
('bc45d0e0-4b98-4873-b539-57fd046f52d6','句  其二','李格非','宋','宋诗','song-poetry','','[]','魯直今已矣，平生作小詩。',12,'全唐诗/poet.song.58000.json','["魯直今已矣，平生作小詩。"]'),
('59032752-e647-4fd6-857f-da554ee18b7b','武夷山昇真洞','陳覺民','宋','宋诗','song-poetry','','[]','昇真洞口接天門，靈草丹桃日日春。',32,'全唐诗/poet.song.58000.json','["昇真洞口接天門，靈草丹桃日日春。", "聽說列仙來瑞世，三朝德業在斯民。"]'),
('c4b79c97-ad30-4b5e-b3d3-72b840e31076','五仙觀','陳覺民','宋','宋诗','song-poetry','','[]','古木脩篁絕世間，越王臺殿作仙壇。',32,'全唐诗/poet.song.58000.json','["古木脩篁絕世間，越王臺殿作仙壇。", "白羊常在玉虛遠，玄鶴不來金井寒。"]'),
('73b94250-d98a-4a3c-93be-20ed4e871590','寄米元章二首  其一','陳覺民','宋','宋诗','song-poetry','','[]','汩汩塵埃閱歲華，青山相見認空花。',32,'全唐诗/poet.song.58000.json','["汩汩塵埃閱歲華，青山相見認空花。", "清淮風月元無價，憑仗詩翁爲我賒。"]'),
('5333cdb5-67a9-4001-ad2a-ca36a15445b6','寄米元章二首  其二','陳覺民','宋','宋诗','song-poetry','','[]','長淮千古自流東，六月城頭日日風。',32,'全唐诗/poet.song.58000.json','["長淮千古自流東，六月城頭日日風。", "天際玉潢無少處，夜山圖在明月中。"]'),
('4e9e8534-4456-4376-aa76-4236f24c39f3','句  其一','陳覺民','宋','宋诗','song-poetry','','[]','却憶當年江處士，辭言秋色藹人家。',16,'全唐诗/poet.song.58000.json','["却憶當年江處士，辭言秋色藹人家。"]'),
('9f1bf549-1292-4aae-a43f-c7823ad5e765','句  其二','陳覺民','宋','宋诗','song-poetry','','[]','弔江爲處士。',6,'全唐诗/poet.song.58000.json','["弔江爲處士。"]'),
('749d1731-f228-41a9-ae6b-e03f24fb25a5','偶題雪竇和尚親書偈卷','周仲仁','宋','宋诗','song-poetry','','[]','道人詩句從梁老，筆意崢嶸自一家。',32,'全唐诗/poet.song.58000.json','["道人詩句從梁老，筆意崢嶸自一家。", "誰會林間相見事，莫都錯看亂飄花。"]'),
('777b93c4-e1d0-4067-8a27-267afbfa1869','句','梁立曦','宋','宋诗','song-poetry','','[]','遺像梁朝佛。',6,'全唐诗/poet.song.58000.json','["遺像梁朝佛。"]'),
('11518422-9eee-4f1a-8869-9f03d55d414e','句','廣州部人','宋','宋诗','song-poetry','','[]','三年清似鏡。',6,'全唐诗/poet.song.58000.json','["三年清似鏡。"]'),
('cfa2cf5b-dda3-485e-8b4e-fa5a43327a31','貞女峽','歐陽經','宋','宋诗','song-poetry','','[]','退之雄文露天巧，夢得清詩揮秀格。',32,'全唐诗/poet.song.58000.json','["退之雄文露天巧，夢得清詩揮秀格。", "迨今聲名三百年，文字山水相輝赫。"]'),
('f0cb0444-d64e-4ebf-b4c9-4f329d7b6f34','句  其一','歐陽經','宋','宋诗','song-poetry','','[]','林青乍聽鶑聲喚，花嫩初籠日影遲。',16,'全唐诗/poet.song.58000.json','["林青乍聽鶑聲喚，花嫩初籠日影遲。"]'),
('b51632c6-1ad4-4132-a722-22a5a8b5581d','句  其二','歐陽經','宋','宋诗','song-poetry','','[]','峰頭華創占瓌奇，下視湖山迤邐卑。',16,'全唐诗/poet.song.58000.json','["峰頭華創占瓌奇，下視湖山迤邐卑。"]'),
('30ef8a45-c329-48a9-8e5b-66c43f3de18d','句  其三','歐陽經','宋','宋诗','song-poetry','','[]','小桃斜映綠楊絲，激水泠泠漾日暉。',16,'全唐诗/poet.song.58000.json','["小桃斜映綠楊絲，激水泠泠漾日暉。"]'),
('1ba89fe2-d632-4186-bd08-d765bd1bc27d','登幼山','羅畸','宋','宋诗','song-poetry','','[]','殿角纔餘一握天，我來神骨自飄然。',48,'全唐诗/poet.song.58000.json','["殿角纔餘一握天，我來神骨自飄然。", "影移隠隠烟霞裏，身在亭亭日月邊。", "脚底擁青寒樹杪，面前凝翠亂峰顛。"]'),
('7a7a808d-9f38-4e82-9ecc-7f63d161a971','句  其一','羅畸','宋','宋诗','song-poetry','','[]','幾疑銀漢餘波溢，浪衮黄金砌畔泉。',16,'全唐诗/poet.song.58000.json','["幾疑銀漢餘波溢，浪衮黄金砌畔泉。"]'),
('be6d9c4d-3a94-459c-b646-54e2f205911f','句  其二','羅畸','宋','宋诗','song-poetry','','[]','山圍碧玉神仙島，地湧黄金宰相沙。',32,'全唐诗/poet.song.58000.json','["山圍碧玉神仙島，地湧黄金宰相沙。", "丹荔熟時堆錦繡，翠榕空裏起龍蛇。"]'),
('e3997d58-8117-4c0e-9334-a49bf8fcb8dd','句','李宋卿','宋','宋诗','song-poetry','','[]','潮來潮退東西渚，雲起雲收前後山。',16,'全唐诗/poet.song.58000.json','["潮來潮退東西渚，雲起雲收前後山。"]'),
('839a49ce-ffe4-4f10-b925-4683c939ed8a','蛇首巖','求仲弓','宋','宋诗','song-poetry','','[]','石如蛇首隠林端，未得風雷且蟄蟠。',32,'全唐诗/poet.song.58000.json','["石如蛇首隠林端，未得風雷且蟄蟠。", "俗眼莫嫌無變化，待生頭角始堪觀。"]'),
('867178db-4981-47af-8322-138ee323b451','靈龜潭','求仲弓','宋','宋诗','song-poetry','','[]','江湖雖闊多罾網，幽澗清虛且勉旃。',32,'全唐诗/poet.song.58000.json','["江湖雖闊多罾網，幽澗清虛且勉旃。", "待我功成買雙鶴，歸來伴汝一千年。"]'),
('3fd8c17f-4712-40c9-af55-1e73b217026d','江瀆泛舟和吳中復韵','雍方知','宋','宋诗','song-poetry','','[]','火老金柔尚伏藏，快風收雨送新凉。',64,'全唐诗/poet.song.58000.json','["火老金柔尚伏藏，快風收雨送新凉。", "人隨竹馬來方盛，酒入蓮筩特地香。", "春草與誰占夢句，白雲空自頌觥觴。", "欲知此日公之樂，正喜西城息亢陽。"]'),
('9e6fa464-5f60-4519-ab70-defa4be32d1d','句  其一','施子安','宋','宋诗','song-poetry','','[]','蟬喚翠陰聲斷續，鳥藏紅葉響啁啾。',16,'全唐诗/poet.song.58000.json','["蟬喚翠陰聲斷續，鳥藏紅葉響啁啾。"]'),
('24738d18-3b6d-4507-9721-5ffe8fc2dc42','句  其二','施子安','宋','宋诗','song-poetry','','[]','隴雲飄軟玉，江月洗寒金。',12,'全唐诗/poet.song.58000.json','["隴雲飄軟玉，江月洗寒金。"]'),
('c4ee28a9-9af6-4690-8162-3174b59a71eb','北山隠居','王拙','宋','宋诗','song-poetry','','[]','負郭蕭然築短牆，北山隠几意悠長。',64,'全唐诗/poet.song.58000.json','["負郭蕭然築短牆，北山隠几意悠長。", "靜看青草隨時換，笑問白雲何事忙。", "范蠡浮家終覺晚，劉伶荷鍤信非狂。", "楮冠布褐安吾分，那有移文到草堂。"]'),
('f4734486-3ab0-408f-86b8-e342e5181a14','送向綜通判桂州','張鏌','宋','宋诗','song-poetry','','[]','百里常淹展驥材，除書遠自九天來。',64,'全唐诗/poet.song.58000.json','["百里常淹展驥材，除書遠自九天來。", "綠油車上揚旌去，畫鷁舟中疊鼓催。", "桂嶺花光紛似雪，荔江波色淥如苔。", "訟庭塵滿無留事，惟伴登臨燕席開。"]'),
('b9361694-dce9-4ae6-8554-975f1b5e459d','嬌娘行','孫次翁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','楚宮女兒身姓孫，十五綠鬢堆濃雲。',384,'全唐诗/poet.song.58000.json','["楚宮女兒身姓孫，十五綠鬢堆濃雲。", "臉花歌笑艷杏發，肌玉纔近紅瓊溫。", "仙源曾引劉郎悟，天教謫下風塵去。", "策金堤上起青樓，照水花間開繡戶。", "山陽天下居要衝，春行處處皆香風。", "花名樂府三千輩，惟君第一嬌姿容。", "畫舫驕馬日過門，過者知名求見君。", "侍君顔色肯一顧，方肯延入羅芳樽。", "遏雲數聲貫珠善，驚鴻舞態流風轉。", "不是當朝朱紫人，歌舞筵中難得見。", "朝英國士相歡久，學詩染翰顔兼柳。", "衛尉卿男號富兒，黄金滿載來見之。", "朝歡夕宴奉歌酒，春去秋來情愈厚。", "青絲偷剪結郎心，暗發深誠誓婚偶。", "深更不與家人露，藏頭掩面隨郎去。", "千里相從人不知，鴛鴦比翼凌雲飛。", "帝城風物正春色，與郎遍賞遊芳菲。", "郎去高堂負父意，父親惜子情難制。", "六禮安排迎入門，且圖繼嗣延家世。", "銓行補吏任忠州，整袖長江同泝流。", "瞿塘灧澦遍經歷，二年惟愛居蠻陬。", "解官入京重調轉，空閨獨坐居京輦。", "傷離感疾時召醫，無何楚客皆聞知。", "急具高堂報阿母，母怒大發如風雨。"]'),
('d79591af-ca87-4106-a8fa-3384c8739b03','句','石處雄','宋','宋诗','song-poetry','','[]','巨區形勝甲江東，可見全吳澤國雄。',16,'全唐诗/poet.song.58000.json','["巨區形勝甲江東，可見全吳澤國雄。"]'),
('15abd8af-c36e-455a-a274-d2e9abf6345c','題招題院靜照堂','任恬','宋','宋诗','song-poetry','','[]','門掩世喧外，幽栖向此堂。',48,'全唐诗/poet.song.58000.json','["門掩世喧外，幽栖向此堂。", "一心能自盡，萬事即都忘。", "塵冷孤蟾白，庭空異草香。", "何須隠林壑，處處可韜光。"]'),
('5856f8ac-759d-4b1d-8cf8-408e716179e2','題招題院靜照堂','牟景先','宋','宋诗','song-poetry','','[]','金色成千界，毫光獨萬緣。',48,'全唐诗/poet.song.58000.json','["金色成千界，毫光獨萬緣。", "堂名斯擬象，法眼示通圓。", "座踞軒楹內，明觀善惡前。", "吾當除滯見，清信奉周旋。"]'),
('1d09c3c8-55ff-4bc8-b262-143e1c7de063','東溪','朱正民','宋','宋诗','song-poetry','','[]','陽安多勝概，劉子卜郊居。',24,'全唐诗/poet.song.58000.json','["陽安多勝概，劉子卜郊居。", "江流清牖戶，山列圍庭衢。"]'),
('871f2861-6c44-4d64-b86c-1d3c4ec31b06','憶秦望照湖二境','吳逕','宋','宋诗','song-poetry','','[]','東南山水古馳名，合與騷人養性靈。',64,'全唐诗/poet.song.58000.json','["東南山水古馳名，合與騷人養性靈。", "秋色欲歸雲轉白，潮痕不到草常青。", "巖房避暑堪長往，桂楫浮春幾度經。", "何事深思無暇日，宿猨崖近狎鷗汀。"]'),
('d45874b2-759e-475c-ab9c-79209163f450','雁蕩山','釋惟一','宋','宋诗','song-poetry','','[]','四海名山曾過目，就中此景難圖錄。',32,'全唐诗/poet.song.58000.json','["四海名山曾過目，就中此景難圖錄。", "山前向見白頭翁，自道一生看不足。"]'),
('c06ffd03-a2b7-4dc3-8145-6f296147fb60','仙魚驛','李處訥','宋','宋诗','song-poetry','','[]','少年常誦少陵詩，寤寐城南天下稀。',48,'全唐诗/poet.song.58000.json','["少年常誦少陵詩，寤寐城南天下稀。", "錦屏山色行看遠，閬苑風光願與違。", "回首玉臺山下路，黄粱初熟夢成非。"]'),
('e8e0bfb4-c835-4f83-aaf7-8ceb51cfdfeb','和王微之使君齊山懷古韵','曹仁海','宋','宋诗','song-poetry','','[]','臨風眺遠夕陽開，雁陣橫江一送哀。',64,'全唐诗/poet.song.58000.json','["臨風眺遠夕陽開，雁陣橫江一送哀。", "爲感千秋森棨戟，不知何處是蓬萊。", "謫仙豪放空餘韵，小杜風流擅治才。", "數點烟波今古思，尊前黄菊幾低徊。"]'),
('51373810-be1c-4942-a169-5d19ebba6d96','賦新繁周表權如詔亭','羅登','宋','宋诗','song-poetry','','[]','詩禮當年學此亭，先生題作義方名。',64,'全唐诗/poet.song.58000.json','["詩禮當年學此亭，先生題作義方名。", "豈知天詔加褒美，冥合君言被寵榮。", "銀組郎曹新進秩，綵衣子舍貴專城。", "一門忠孝誰能繼，官蔭恩先及弟兄。"]'),
('e2676102-669e-4ba4-bb9b-6a8c015f93e2','題樓觀南樓','王工部','宋','宋诗','song-poetry','','[]','常恨閑行少，匆匆忽解鞍。',24,'全唐诗/poet.song.58000.json','["常恨閑行少，匆匆忽解鞍。", "秋風尹家宅，更得暫盤桓。"]'),
('95a34aec-bea7-4130-8d86-77c2581d108b','至樓觀作','王工部','宋','宋诗','song-poetry','','[]','罷歸關令存遺宅，羽駕真人有舊丘。',64,'全唐诗/poet.song.58000.json','["罷歸關令存遺宅，羽駕真人有舊丘。", "水石自含仙氣爽，烟雲常許世人遊。", "悠悠天道推終始，擾擾塵纓滯去留。", "君看一官容易捨，老來棲止占山陬。"]'),
('a86b6ede-63b9-4b1f-b785-5d909acb1cdb','句','張獻圖','宋','宋诗','song-poetry','','[]','吾今爲奉職，子莫怨鸞孤。',12,'全唐诗/poet.song.58000.json','["吾今爲奉職，子莫怨鸞孤。"]'),
('ba6a138d-d1e4-4a98-a1b5-ddc5fe3b1b25','句  其一','陳智夫','宋','宋诗','song-poetry','','[]','花笑似留客，鳥啼如喚人。',12,'全唐诗/poet.song.58000.json','["花笑似留客，鳥啼如喚人。"]'),
('36a36437-9bb8-4fd0-bf48-8e00d1a3dea0','句  其二','陳智夫','宋','宋诗','song-poetry','','[]','野花臨水數枝恨，芳草連天千里情。',16,'全唐诗/poet.song.58000.json','["野花臨水數枝恨，芳草連天千里情。"]'),
('a0925021-87ed-4d66-b502-523ea3bfecba','諧謔','劉郛','宋','宋诗','song-poetry','','[]','坐上若有一點紅，斗筲之器成千鍾。',32,'全唐诗/poet.song.58000.json','["坐上若有一點紅，斗筲之器成千鍾。", "坐上若無油木梳，烹龍庖鳳皆成虛。"]'),
('a5e8ea4c-d633-461d-9c93-978761e30303','夜宿仙都山聞松聲作','胡志道','宋','宋诗','song-poetry','','[]','仙都古洞天，雲闕高嵲嵲。',99,'全唐诗/poet.song.58000.json','["仙都古洞天，雲闕高嵲嵲。", "新宮欣然成，碧瓦燦鱗列。", "我時宿{王禁}房，六月失煩熱。", "松聲起中夜，夢枕忽驚輟。", "天籟鳴虛徐，玉簫遞泠徹。", "鳳歌諧律呂，鶴舞想應節。", "安知非群仙，宴罷搖珮玦。", "從來箏笛耳，一洗萬想滅。"]'),
('bcf20461-ad14-4831-b9c8-845ef8bfad9a','黄帝祠宇','胡志道','宋','宋诗','song-poetry','','[]','李侯神仙才，宇宙在其手。',120,'全唐诗/poet.song.58000.json','["李侯神仙才，宇宙在其手。", "古篆誇雄奇，鐵柱貫金鈕。", "標榜黄帝祠，字畫氣渾厚。", "想當落筆時，雲夢吞八九。", "每傳風雨夜，蜿蜿龍蛇走。", "光怪發岩竇，草木潤不朽。", "鬼物煩撝訶，一旦忽失守。", "隨烟遽飛騰，無復世間有。", "因訪山中人，石刻尚仍舊。", "誰能一新之，易若運諸肘。"]'),
('f692884d-486f-48cd-9c7d-7f2b23fdbbba','隠真堂','胡志道','宋','宋诗','song-poetry','','[]','休說神仙事眇茫，出游塵世且和光。',64,'全唐诗/poet.song.58000.json','["休說神仙事眇茫，出游塵世且和光。", "誰知今日真棲地，便是他年羽化鄉。", "朝罷玉壇雲滿袖，夢回金闕月侵廊。", "茲游似覺青冥上，隠隠微聞詠洞章。"]'),
('6c674736-7bae-4aa4-af8f-7e1847d6764e','望雪閣','胡志道','宋','宋诗','song-poetry','','[]','黄帝乘雲至帝鄉，空留轍迹鎖穹蒼。',64,'全唐诗/poet.song.58000.json','["黄帝乘雲至帝鄉，空留轍迹鎖穹蒼。", "茫茫丹鼎知何在，曳曳霓旌不可望。", "乞得溪山增氣象，真成草木被恩光。", "我來睇目憑欄久，是可無情憶楚襄。"]'),
('858230a3-020e-4199-9550-c8d647d9ba0d','可理室','胡志道','宋','宋诗','song-poetry','','[]','百年日月馬上過，贏得閑中可理生。',64,'全唐诗/poet.song.58000.json','["百年日月馬上過，贏得閑中可理生。", "絳闕清都非渺漠，寸田尺宅得經營。", "默存長使三宮在，急守須防五嶽傾。", "他日功成定仙去，願隨風馭到蓬瀛。"]'),
('58821355-fa17-4bac-b275-e5aa34371981','競秀軒','胡志道','宋','宋诗','song-poetry','','[]','幾年困塵鞿，厥狀浸成俗。',84,'全唐诗/poet.song.58000.json','["幾年困塵鞿，厥狀浸成俗。", "比來夢魂清，勝賞得林麓。", "群峰綰烟鬟，炯炯皆在目。", "寒碧冷相射，秀氣還可掬。", "哦詩三伏中，清風起幽谷。", "只恐吹我衣，化爲雲錦服。", "汗流籍湜輩，上下相追逐。"]'),
('f52aa220-2824-44cd-8f92-69bcdc5068b8','擷芳軒','胡志道','宋','宋诗','song-poetry','','[]','仙家日月遲，春物長芳菲。',48,'全唐诗/poet.song.58000.json','["仙家日月遲，春物長芳菲。", "欲擷瓊瑶英，咀嚼雲腴肥。", "只恐花霧深，香氣濕我衣。", "坐哦心未愜，歸夢遶岩扉。"]'),
('88780f2b-ab19-4ebd-8915-0b94fbe995b1','練玉軒','胡志道','宋','宋诗','song-poetry','','[]','曉誦黄庭經，暮歌紫芝曲。',48,'全唐诗/poet.song.58000.json','["曉誦黄庭經，暮歌紫芝曲。", "若欲童子顔，軒中勤練玉。", "羽衣絡霞青，雲鬢頹鬒綠。", "功用信如許，庶可追妙躅。"]'),
('45049ae6-818f-4655-bc24-9a0f6c91206b','煥照室','胡志道','宋','宋诗','song-poetry','','[]','門外無俗駕，眼中有餘清。',48,'全唐诗/poet.song.58000.json','["門外無俗駕，眼中有餘清。", "上登嶢嶢闕，八窗皆虛明。", "三光煥爾照，萬象無隠情。", "試觀弄丹筆，雲篆俱天成。"]'),
('5e40df20-a181-4fc7-bb82-50916d64022b','仙水洞','胡志道','宋','宋诗','song-poetry','','[]','升巍躡層巔，雲陛近百尺。',96,'全唐诗/poet.song.58000.json','["升巍躡層巔，雲陛近百尺。", "平生塵土足，到此還幾歷。", "有岩中枵然，斧鑿若天劃。", "玉泉出石罅，雨點散寒碧。", "我來供茗事，松鼎煮瓊液。", "餘甘生齒頰，可以醒醉魄。", "永懷鶴髮翁，四顧但空壁。", "似聞便仙去，山間謾留舄。"]'),
('da7b7e41-c0f9-4eb9-bfd1-9436b3d4da19','忘歸洞','胡志道','宋','宋诗','song-poetry','','[]','好山如故人，欣然見眉宇。',120,'全唐诗/poet.song.58000.json','["好山如故人，欣然見眉宇。", "又如梳曉鬟，紅綠相媚嫵。", "况茲愛山者，握筆喜臨賦。", "有岩巉然開，欲陟縱蹇步。", "清游亦不惡，勝境得飽飫。", "掃石坐晚凉，濃翠濕冠屨。", "好花續春遲，紛紛雜紅霧。", "仙家在何許，恐入桃源誤。", "竟爲彌日留，直待山月吐。", "謾尋流水歸，不記來時路。"]'),
('0e559a08-dccd-464b-940a-3f3e2667df61','初暘谷','胡志道','宋','宋诗','song-poetry','','[]','山嵐鬰蒼蒼，溪水流浩浩。',120,'全唐诗/poet.song.58000.json','["山嵐鬰蒼蒼，溪水流浩浩。", "紛然世上人，換易如秋草。", "奇哉三洞天，連路極深窈。", "陽崖射朝曦，先見扶桑曉。", "誰能餐九華，顔色端使好。", "仙翁蟬蛻去，遺迹不可考。", "我來愜登臨，幽事費尋討。", "悲嘯聞澗猿，啁哳聽啼鳥。", "平生憤懣臆，到此始一掃。", "行將袖手版，汗漫游八表。"]'),
('56e055e6-c312-42ff-99de-001c20b7a79b','龍泓洞','胡志道','宋','宋诗','song-poetry','','[]','茲山何巍巍，欲上捫蘿蔦。',96,'全唐诗/poet.song.58000.json','["茲山何巍巍，欲上捫蘿蔦。", "怪石虎踞蹲，老枿虬夭矯。", "中有古洞天，劖然若天造。", "爰從開闢來，日月自昏曉。", "神龍此蟄蟠，雷玉吐淼淼。", "每逢歲旱乾，山老必見禱。", "顧盼層雲生，撖舞百川倒。", "何時謝魚蝦，昂雷騰浩渺。"]'),
('9d40bb2a-e30b-430c-a868-a5b995c4999c','寶林寺','申屠炯','宋','宋诗','song-poetry','','[]','欲共高僧話，幽尋入寶林。',48,'全唐诗/poet.song.58000.json','["欲共高僧話，幽尋入寶林。", "途分喧寂境，座息是非心。", "老鶴栖巢穩，靈鰻蟄井深。", "山中饒勝迹，歲月幾登臨。"]'),
('5dcc8289-a4ca-4b6c-bb32-5357518b2aae','題錢知監東皋別業','封萬里','宋','宋诗','song-poetry','','[]','別墅連城郭，超然遠垢氛。',48,'全唐诗/poet.song.58000.json','["別墅連城郭，超然遠垢氛。", "蚌明宵閣見，鶴唳曉堂聞。", "翠滴階前露，紅鋪水上雲。", "悠悠持祿者，應媿不如君。"]'),
('7bde8bac-4736-4d68-9e1e-52c0e9acb972','題巫山神女廟','唐耜','宋','宋诗','song-poetry','','[]','楚澤隠巫山，翠壁開鴻濛。',216,'全唐诗/poet.song.58000.json','["楚澤隠巫山，翠壁開鴻濛。", "萬流束長峽，怒浪日簸舂。", "朝暉澹高唐，巖阿閟彤宮。", "罘罳散烟霧，榮光繞長虹。", "恭聞雲華君，少陰體沖融。", "受道紫清闕，飛化凌三空。", "徜徉江海上，千騎馳蒼龍。", "羽節回天津，央央弭層峰。", "悽惻下土人，昏墊無所容。", "寶書授神禹，百靈倏奔從。", "蛟螭委鞭策，山川奠西東。", "九州免爲魚，遂成萬世功。", "嗟余晚聞道，蓬心蔽倥侗。", "維舟垂崖邊，再拜望遺蹤。", "嶙峋山頭石，雲衣尚溶溶。", "縹緲玉瑛臺，如在指顧中。", "童律不可問，至言誰擊蒙。", "仰首天壇下，松柏悲回首。"]'),
('6c8ef908-eb9b-4ea3-85ec-a7ae1830e1db','十憶 憶行','李元膺','宋','宋诗','song-poetry','','[]','屏帳腰支出洞房，花枝窣地領巾長。',32,'全唐诗/poet.song.58000.json','["屏帳腰支出洞房，花枝窣地領巾長。", "裙邊遮定鴛鴦小，只有金蓮步步香。"]'),
('6d7c1eeb-b603-4a29-84d3-175c18bef48a','十憶 憶坐','李元膺','宋','宋诗','song-poetry','','[]','椅上藤花闞面平，繡裙斜綽茜羅輕。',32,'全唐诗/poet.song.58000.json','["椅上藤花闞面平，繡裙斜綽茜羅輕。", "踏青姊妹頻來喚，鴛履貪弓不意行。"]'),
('561fa6a4-3044-483f-9691-4d92f00e2f30','十憶 憶飲','李元膺','宋','宋诗','song-poetry','','[]','綠蟻頻催未厭多，帕羅香軟襯金荷。',32,'全唐诗/poet.song.58000.json','["綠蟻頻催未厭多，帕羅香軟襯金荷。", "從教弄酒春衫涴，別有風流上眼波。"]'),
('6215b9e7-0526-4e8d-8f12-153aa1f07b33','十憶 憶歌','李元膺','宋','宋诗','song-poetry','','[]','一串紅牙碎玉敲，碧雲無力駐晴霄。',32,'全唐诗/poet.song.58000.json','["一串紅牙碎玉敲，碧雲無力駐晴霄。", "也知唱到關情處，緩按餘聲眼色招。"]'),
('c46be9b5-cfbd-4d54-bd20-9139e811bcf2','十憶 憶書','李元膺','宋','宋诗','song-poetry','','[]','纖玉參差象管輕，蜀牋小研碧窗明。',32,'全唐诗/poet.song.58000.json','["纖玉參差象管輕，蜀牋小研碧窗明。", "袖紗密掩嗔郎看，學寫鴛鴦字未成。"]'),
('2c3e8cb5-03ff-40b9-aec5-c8fcfce7891c','十憶 憶博','李元膺','宋','宋诗','song-poetry','','[]','小閣爭籌畫燭低，錦茵圍坐玉相欹。',32,'全唐诗/poet.song.58000.json','["小閣爭籌畫燭低，錦茵圍坐玉相欹。", "嬌羞慣被諸郎戲，袖映春葱出注遲。"]'),
('2354eec9-54d0-4a31-9ce2-3ccdb4d63f7b','十憶 憶顰','李元膺','宋','宋诗','song-poetry','','[]','漫注橫波無語處，輕攏小板欲歌時。',32,'全唐诗/poet.song.58000.json','["漫注橫波無語處，輕攏小板欲歌時。", "千愁萬恨關心曲，却使眉尖學別離。"]'),
('cd384973-7121-4fda-8016-4c3e583f307d','十憶 憶笑','李元膺','宋','宋诗','song-poetry','','[]','從來題目值千金，無事羞多始見心。',32,'全唐诗/poet.song.58000.json','["從來題目值千金，無事羞多始見心。", "乍向客前猶掩斂，不知已覺鈿窩深。"]'),
('e1dfca36-63a4-436c-913a-bbca5853e69e','十憶 憶眠','李元膺','宋','宋诗','song-poetry','','[]','泥嬌成困日初長，暫卸輕裙玉簟凉。',32,'全唐诗/poet.song.58000.json','["泥嬌成困日初長，暫卸輕裙玉簟凉。", "漠漠帳烟籠玉枕，粉肌生汗白蓮香。"]'),
('76692a71-9aff-4015-9587-defe03d68019','十憶 憶妝','李元膺','宋','宋诗','song-poetry','','[]','宮樣梳兒金縷犀，釵梁水玉刻蛟螭。',32,'全唐诗/poet.song.58000.json','["宮樣梳兒金縷犀，釵梁水玉刻蛟螭。", "眉間要點雙心事，不管蕭郎只畫眉。"]'),
('aafdebbe-172c-4f8b-bf7b-e03c754eba44','觀前古美人圖','李元膺','宋','宋诗','song-poetry','','[]','璧月塵昏瓊樹秋，無從百媚一回眸。',64,'全唐诗/poet.song.58000.json','["璧月塵昏瓊樹秋，無從百媚一回眸。", "荼蘼香度梅妝冷，鸚鵡聲低玉笛幽。", "吐袖但能知禍水，逢春輒莫上迷樓。", "歸來安守無鹽女，不寵無驚共白頭。"]'),
('4427fce2-deba-411b-9f23-4652c9e1284f','折楊柳','李元膺','宋','宋诗','song-poetry','','[]','東風來何時，百花已飄零。',72,'全唐诗/poet.song.58000.json','["東風來何時，百花已飄零。", "獨有堤上柳，慘淡含春榮。", "扁舟復何適，延客江上亭。", "顧無青玉案，何以送子行。", "攀條欲相贈，上有雙流鶑。", "流鶑正求友，奈此離別情。"]'),
('3a423e4d-45de-4f21-bdff-2a069844646f','句  其一','李元膺','宋','宋诗','song-poetry','','[]','夾道桃花三月暮，馬蹄無處避殘紅。',16,'全唐诗/poet.song.58000.json','["夾道桃花三月暮，馬蹄無處避殘紅。"]'),
('a766803f-c965-4ae4-9167-56a743c43534','句  其二','李元膺','宋','宋诗','song-poetry','','[]','蓼花無數入船窗。',8,'全唐诗/poet.song.58000.json','["蓼花無數入船窗。"]'),
('31265a93-6d70-4621-9b18-d19a60a9fb78','邛徠關','朱紱','宋','宋诗','song-poetry','','[]','九折先驅叱馭行，此心豈是不思親。',32,'全唐诗/poet.song.58000.json','["九折先驅叱馭行，此心豈是不思親。", "忠臣孝子元同道，可是王陽獨愛身。"]'),
('28c687fb-f63c-46b2-aaa9-20abefd08929','題南華竹軒','葛敏修','宋','宋诗','song-poetry','','[]','不用山僧供帳迎，世間無此竹風清。',32,'全唐诗/poet.song.58000.json','["不用山僧供帳迎，世間無此竹風清。", "獨拳一手支頤卧，偷眼看雲生未生。"]'),
('38ac0ba9-fb36-438a-897f-844874a3258f','羅仙觀','葛敏修','宋','宋诗','song-poetry','','[]','羅仙一去二百載，馬跡飛橋今尚存。',64,'全唐诗/poet.song.58000.json','["羅仙一去二百載，馬跡飛橋今尚存。", "鶴馭不爲緱氏嶺，桃花空出武陵源。", "千年光景馳駒隙，三級波濤透禹門。", "欲見此翁論此事，夜深無夢入莊魂。"]'),
('589ce1f6-3ffa-40c4-9cb0-5f1ada3fca45','句  其一','葛敏修','宋','宋诗','song-poetry','','[]','一瀉三百里，列爲十八灘。',12,'全唐诗/poet.song.58000.json','["一瀉三百里，列爲十八灘。"]'),
('57e7907d-118b-4e60-949f-098f54b34a3f','句  其二','葛敏修','宋','宋诗','song-poetry','','[]','從今益勉爲忠義，一噎如何便廢餐。',16,'全唐诗/poet.song.58000.json','["從今益勉爲忠義，一噎如何便廢餐。"]'),
('bb20474c-2b34-465e-a49d-888a4c800d4e','句  其三','葛敏修','宋','宋诗','song-poetry','','[]','章江來自西，貢水東其源。',24,'全唐诗/poet.song.58000.json','["章江來自西，貢水東其源。", "合流虎頭下，共注鱉口村。"]'),
('cad10bbd-6925-4263-9154-1031b31cfc9a','奉借子進接䍦','歐陽棐','宋','宋诗','song-poetry','','[]','奉借山公舊接䍦，最宜筇杖與荷衣。',32,'全唐诗/poet.song.58000.json','["奉借山公舊接䍦，最宜筇杖與荷衣。", "習家池上花初盛，醉後多應倒載歸。"]'),
('31b0cf36-551e-4f73-baba-911345c58215','述懷','任伯雨','宋','宋诗','song-poetry','','[]','元符庚辰歲，孟冬十二日。',288,'全唐诗/poet.song.58000.json','["元符庚辰歲，孟冬十二日。", "任子丞大宗，碌碌奉朝籍。", "聖主訪落初，聽言勞日昃。", "諫路員有闕，求人恐不及。", "誰謂方遴選，邂逅首疏逖。", "詔旨忽中授，聞命旦夕惕。", "不是憂不合，愛君憂失職。", "既憂亦復喜，不是貪祿秩。", "平生慕古人，素願或可畢。", "精神倍疏瀹，激昂登文石。", "青雲開九天，清光親咫尺。", "每見情益交，肝膽盡剖析。", "敬承丁寧訓，重許以忠直。", "自喜千載遇，奮身遑他恤。", "志欲收主威，力先排巨室。", "切齒憤欽永，刻意望夔稷。", "不數千羊皮，豈讓一狐腋。", "勤勤履霜戒，不復慮不密。", "問夜欲自勞，百疏意何益。", "哀哉愛君心，不能當衆嫉。", "投湘爲獨醒，得罪因懷璧。", "尚頼天德廣，閱歲已再謫。", "仇人意未厭，窮荒必投斥。", "轉海僅萬里，艱危備經歷。"]'),
('682f85d8-8329-4c2e-b3fe-a0d28a37d1ca','元日','任伯雨','宋','宋诗','song-poetry','','[]','憶昔東班賀紫宸，和風佳氣浄無塵。',64,'全唐诗/poet.song.58000.json','["憶昔東班賀紫宸，和風佳氣浄無塵。", "龍墀初下觚稜日，雉扇齊開玉座春。", "接武九霄曾近侍，投荒三載作流人。", "窮通忤合雖天理，俯仰尋思不爲身。"]'),
('b93d21c2-d780-48e9-878c-60abdf93a7ca','自歎','任伯雨','宋','宋诗','song-poetry','','[]','當年言路亦逡巡，白簡青蒲十一人。',32,'全唐诗/poet.song.58000.json','["當年言路亦逡巡，白簡青蒲十一人。", "半斥炎荒半除籍，而今無一預朝紳。"]'),
('950b48d4-e695-45e2-9106-75c03a79c08e','感古二首  其一','任伯雨','宋','宋诗','song-poetry','','[]','一言借諭資鍾會，意在張華亦已深。',32,'全唐诗/poet.song.58000.json','["一言借諭資鍾會，意在張華亦已深。", "大抵知言由養氣，可憐晉武有蓬心。"]'),
('2fe17d0a-0ff0-45e2-9db9-5ccc4f0c6318','感古二首  其二','任伯雨','宋','宋诗','song-poetry','','[]','指鹿姦謀豈偶然，都緣人事不由天。',32,'全唐诗/poet.song.58000.json','["指鹿姦謀豈偶然，都緣人事不由天。", "要知左右皆言馬，只爲當時殺正先。"]'),
('296c2b52-5ca6-495a-904e-c0db0dfe2d93','宿西軒','任伯雨','宋','宋诗','song-poetry','','[]','茅簷不動晚風微，獨對爐烟枕半欹。',32,'全唐诗/poet.song.58000.json','["茅簷不動晚風微，獨對爐烟枕半欹。", "惟有多情沙上月，依然青瑣照人時。"]'),
('88143f69-cb40-48c5-98fc-cadaee488cc2','焚香有感','任伯雨','宋','宋诗','song-poetry','','[]','掃地焚香開竹扉，輕烟郁郁閒朝暉。',32,'全唐诗/poet.song.58000.json','["掃地焚香開竹扉，輕烟郁郁閒朝暉。", "却思昔日延和殿，對罷曾携滿袖歸。"]'),
('98cac25d-a76a-46e4-96e0-2f047c20bbe7','獨坐','任伯雨','宋','宋诗','song-poetry','','[]','得喪榮枯事，悠悠過耳風。',48,'全唐诗/poet.song.58000.json','["得喪榮枯事，悠悠過耳風。", "此身猶是幻，何物不爲空。", "酒聖心常醉，詩窮語更工。", "小軒搔首坐，斜日滿窗紅。"]'),
('3f795407-250e-4268-89cd-23139e0bcaf5','登狼山','任伯雨','宋','宋诗','song-poetry','','[]','狼山青青迹已陳，惟餘樓閣向南薰。',64,'全唐诗/poet.song.58000.json','["狼山青青迹已陳，惟餘樓閣向南薰。", "蓬瀛氣象群峰在，吳楚封疆一水分。", "野色西南平接日，潮聲東北怒穿雲。", "登臨更有超然興，回首塵埃不足云。"]'),
('ed492ca0-7390-49d9-bdce-b65c0f509a86','句','任伯雨','宋','宋诗','song-poetry','','[]','身投魑魅家何在，澤逮昆蟲罪未除。',16,'全唐诗/poet.song.58000.json','["身投魑魅家何在，澤逮昆蟲罪未除。"]'),
('bbbd020e-ffcb-467d-ab3b-7d66e59750d6','句','李夔','宋','宋诗','song-poetry','','[]','紫微風韵謫仙身，曾此徘徊今幾春。',16,'全唐诗/poet.song.58000.json','["紫微風韵謫仙身，曾此徘徊今幾春。"]'),
('562f21cb-4b13-4731-958e-b917d4f923d4','題仁樂亭','呂南公','宋','宋诗','song-poetry','','[]','真山蓄幽奇，僞山逞瑰怪。',36,'全唐诗/poet.song.58000.json','["真山蓄幽奇，僞山逞瑰怪。", "峰巒紛變現，座席疑廣大。", "未穿披雲屐，對此亦清快。"]'),
('b465a811-4576-481c-bd66-575e50f89018','虎泉','呂南公','宋','宋诗','song-poetry','','[]','昔聞孤女子，遇虎斯泉側。',48,'全唐诗/poet.song.58000.json','["昔聞孤女子，遇虎斯泉側。", "高僧爲追訶，弭耳不敢食。", "歲月幾何時，稱談如宿夕。", "故知事可傳，豈限涔泓窄。"]'),
('3aa894b9-59fa-45d9-9f51-2ddd530682d4','虛假行','呂南公','宋','宋诗','song-poetry','','[]','虛假復虛假，名陶不知瓦。',144,'全唐诗/poet.song.58000.json','["虛假復虛假，名陶不知瓦。", "養子役于人，不如生犬馬。", "公私嚴忌諱，勢利關取捨。", "奉生既疏違，喪死更苟且。", "苴麻不敢服，桐竹何由把。", "未得久哀呼，方當勤唯喏。", "百年聞罔極，一瞬經廬下。", "豈不近冠裳，驅牽到乖寡。", "沾沾荷鋤子，言動只山野。", "終制負凶縗，興辭淚如瀉。", "諸儒論鄙俗，不若都人雅。", "請問雨間民，誰爲稱情者。"]'),
('667bc072-73d6-42d4-a9fe-29e1e0e0f923','遊子篇','呂南公','宋','宋诗','song-poetry','','[]','遊子朱門兒，行樂畏不足。',240,'全唐诗/poet.song.58000.json','["遊子朱門兒，行樂畏不足。", "遐方寒苦士，自贊乞隨逐。", "朝馳錦韉末，夕讌鳳屏曲。", "雄豪棄殘賸，聲色化耳目。", "來時布素衣，羞耻見羅縠。", "幾許膏粱味，嗜好諱水菽。", "勞勞車馬塵，苒苒歲月速。", "家書懶拆封，舊業廢編牘。", "間嘗夢故國，驚覺如被辱。", "安知愜快餘，窮愁入皮肉。", "趨承偶踰節，况味稍𨃪跼。", "長年倚恩輝，積漸致輕凟。", "因逢故人語，始歎誤程躅。", "都城名利場，豈不多所欲。", "從前入關客，無慮共貧毒。", "商鄽聚珍貲，科舉仰廩祿。", "神乎奪我魄，而獨迷所屬。", "何人不謀身，計慮自不淑。", "寄聲風塵子，哀恨吾已酷。", "當知帝里游，有禍亦有福。"]'),
('8255e003-038c-4676-beba-2962cea7de8d','莓莓原上田','呂南公','宋','宋诗','song-poetry','','[]','莓莓原上田，春至早已種。',72,'全唐诗/poet.song.58000.json','["莓莓原上田，春至早已種。", "墢墢樊間圃，蔬好亦培壅。", "農家樂地利，倚此擬微俸。", "依隨節序停，領略兒孫衆。", "徒耕有讙語，各息無愁夢。", "冷看里諸生，焦心望鄉貢。"]'),
('5518797c-4dea-43ee-b1da-34e01059c37a','和道先從義同過張掾梅花下飲','呂南公','宋','宋诗','song-poetry','','[]','山人如寒松，無可媚鶑蝶。',264,'全唐诗/poet.song.58000.json','["山人如寒松，無可媚鶑蝶。", "諒非清峻契，誰肯略顧接。", "春城偶來至，豪士懶舉睫。", "幽幽法曹廳，一往乃敢輒。", "主人雖壯齒，酷愛文字業。", "相看論古書，術不計勇怯。", "陳家俊公子，德義敦慶葉。", "聞我適過從，逢衣遽披攝。", "老成北扉掾，喜客若漁獵。", "招呼倒清樽，促迫信重疊。", "梅花香樹下，共醉死牛脅。", "勿憂侵暮冷，坐我有氈㲲。", "飛飛落梅英，繞座不待折。", "煌煌畫蠟蠋，未夜已戒設。", "徵詩爲罰令，獻白作飲節。", "譚高衡或爭，笑猛倒還絕。", "李侯解縣印，心注象魏闕。", "座中惜分袂，勸酒更酷烈。", "春先顯父筍，冬外尹吉鼈。", "肴佳俎未竟，酒美壺頻竭。", "更籌屢聞轉，歸乘不許謁。", "誰能避酩酊，但恨落角月。"]'),
('3d96d29a-c5db-4e73-8bc6-edff29a1f136','渠中水','呂南公','宋','宋诗','song-poetry','','[]','咨爾渠中水，源流本何許。',48,'全唐诗/poet.song.58000.json','["咨爾渠中水，源流本何許。", "特無停滀分，得此奔逝苦。", "過村穢濯溉，合澗渾沙土。", "還當歸海日，亦助雲濤巨。"]'),
('ab3dd2da-4c77-40ff-8cb6-c8131da69ef6','野翠堂','呂南公','宋','宋诗','song-poetry','','[]','重城似郊坰，接眼盡蒼翠。',36,'全唐诗/poet.song.58000.json','["重城似郊坰，接眼盡蒼翠。", "無復見枯疏，共疑春每至。", "丘樊豈少此，野叟不自貴。"]'),
('7172eeee-940d-4581-af25-d58ee76cfdc3','鴉聲','呂南公','宋','宋诗','song-poetry','','[]','鴉聲譟人凶，聽者知慘然。',48,'全唐诗/poet.song.58000.json','["鴉聲譟人凶，聽者知慘然。", "忠言論禍福，受之如不聞。", "禽口不可緘，人言因義發。", "畏禽而忽人，使我心如割。"]'),
('a48d6dc4-03e4-4144-914c-7a1e2f446acf','小蟲','呂南公','宋','宋诗','song-poetry','','[]','大螾身尺餘，輝彩盈首尾。',228,'全唐诗/poet.song.58000.json','["大螾身尺餘，輝彩盈首尾。", "小蟲未知名，長不過半指。", "相遭籬畔草，錯愕雜憂喜。", "孤征有令凶，忿鬭莫我止。", "交攻久騰突，反覆召傾毀。", "螾跳欲忘生，蟲怒乃抵死。", "奔衝徹心腹，劫捷沸唇觜。", "方磨雨痕沙，又墮足跡水。", "肥無敏才智，短有毒牙齒。", "吾豪且深侵，彼困漫决起。", "壯軀俄奄奄，恨血稍泚泚。", "蟲休遂馳歸，少頃復臨𦧇。", "安詳銜螾鼻，拖攃繞籬阯。", "却納幽穴中，其將食之矣。", "人間有勝負，不在校形體。", "樓蘭雖雄王，命盡傅介子。", "新家巨無霸，一戰亦爲鬼。", "苟惟性資悍，端可制魁偉。", "君看小蟲威，何獨畏封豕。"]'),
('6c6d7241-8d8d-4ada-9168-261f5ef12dc3','有蟲','呂南公','宋','宋诗','song-poetry','','[]','堂陰闞曲沼，其浸可濫觴。',288,'全唐诗/poet.song.58000.json','["堂陰闞曲沼，其浸可濫觴。", "有蟲宅其間，游息能自將。", "名號亂龜鼈，形軀亞蜣蜋。", "何知一生微，頗以氣調張。", "秋風七八月，泓浸稍減常。", "低回尚飄然，未若謀穴藏。", "十月水泉竭，泥沙暴枯霜。", "迷迷舊坻堮，影迹類已藏。", "延綿盈昃多，天雨斷霈霶。", "皆言此蟲絕，軀殻應碎殭。", "咨嗟亦含氣，所託異慨慷。", "邇來節令改，泰卦直春陽。", "甘霖一夕飛，灌注成濊汪。", "凌晨沼面漲，蟲輩早奮揚。", "上下逞風操，同形喜相望。", "如知出處時，故以偪仄忘。", "余嘗舍其側，終始得瞻相。", "因思物理深，未易草草量。", "江海非不大，其魚每屠傷。", "此沼固褊淺，其蟲乃靈長。", "浮生短與修，有命不可襄。", "運數苟未盡，憂悲豈其戕。", "安危與時俱，窮達須預防。", "所以真至人，如往皆暇遑。"]'),
('23123b1a-0480-4604-b036-57212cbbe473','勝因院','呂南公','宋','宋诗','song-poetry','','[]','莊嚴起何代，幽佚惟天與。',48,'全唐诗/poet.song.58000.json','["莊嚴起何代，幽佚惟天與。", "有衆倚耕桑，無人歎寒暑。", "嵐氛蠹金碧，谷響酬鐘鼓。", "白晝方丈西，猶眠聽經虎。"]'),
('dea9fedf-ee68-4644-bdd9-2fffce000536','招豫亭飲','呂南公','宋','宋诗','song-poetry','','[]','愛酒不日醉，多爲病相妨。',288,'全唐诗/poet.song.58000.json','["愛酒不日醉，多爲病相妨。", "饑虛或傷脾，飲過亦腐腸。", "略困尚舉白，既頹方卧床。", "沈迷劇淹旬，得疾豈可禳。", "嘔泄憎膳食，乖慵豈冠裳。", "愁醒甫旦朝，衰苶還慨慷。", "已復念傾倒，咨呼問瓶缸。", "妻兒惡吾貧，誡我以死亡。", "載讀伯倫傳，懦𮕪更强梁。", "與其憂百年，孰若夭醉鄉。", "家釀苦屢竭，市沽乏錢囊。", "進歌五柳陶，聊美天祿揚。", "幸近豫亭叟，其人固同方。", "有田百頃肥，秫稌歲益倉。", "憐我數寂寞，招邀共深觴。", "醒往酩酊歸，不悟日月長。", "有或致酬酢，肴蔬雜矜張。", "叟來坐酣酣，肯問味惡良。", "我蹇嗜墳史，叟豪樂笙簧。", "相殊不相關，對酌即兩忘。", "如此粗適矣，誰猶辨低昂。", "寧須賣菜傭，豈俟白面郎。", "今日又得酒，忍爲獨沽嘗。", "泔魚取芳鮮，煮狗到爛香。"]'),
('945ccaa3-e11b-4bb4-b1b8-7448a84327a7','濟道過飲偶成長句','呂南公','宋','宋诗','song-poetry','','[]','酤酒榷吏杓，買魚市兒籃。',240,'全唐诗/poet.song.58000.json','["酤酒榷吏杓，買魚市兒籃。", "雖非爛腸宴，亦知足一酣。", "冬景忽卓午，晴雲喪曇曇。", "室廬絕絲竹，文字入笑談。", "以此稱出俗，相看庶無慚。", "解衫掛前楹，豈問布與藍。", "追講石陂會，秋霜正黄柑。", "傅翁最後至，嘯詠能交參。", "題詩廡東閣，醉卧堂西庵。", "論子赴官職，可余老耕蠶。", "俱爲樂榆枋，非傚谿壑貪。", "摻袂歌慷慨，暌離各情含。", "寄書建水涯，年歷滿四三。", "不慮復見日，乃于郡樓南。", "子爲赤髯叟，我有學語男。", "問訊養生具，僅能無一簪。", "固知寒儒分，未易過石甔。", "棄置且勿道，行觴趣空壜。", "將來難預期，既往已備諳。", "聊盡酩酊興，安能每憂惔。"]'),
('78570b69-8b5e-4dce-a06c-7a3852ccd223','疇昔','呂南公','宋','宋诗','song-poetry','','[]','疇昔林野居，布絮不粗完。',192,'全唐诗/poet.song.58000.json','["疇昔林野居，布絮不粗完。", "及爲羈旅人，被服乃綺紈。", "何以出勝處，爲君究其端。", "籬蘇不馥郁，傳自故老言。", "魯邦無君子，子賤豈所倫。", "東方足文史，得飽在長安。", "蘇秦主父偃，亦各有後歎。", "况乎今異古，而本無一廛。", "自非稍激昂，何以脫饑寒。", "辭鄉挈囊書，豈敢言王官。", "苟免溝壑禍，微生已成全。", "文章蓋有力，溫燠此其源。", "遂離廝養科，首尾只十年。", "篋衣亦何者，聊足覆衰殘。", "有破得紉補，有新得縫刓。", "因嗟爲短詩，所以記初難。"]'),
('8249bd18-9f33-4a30-851c-e807782da11a','粟熟二首  其一','呂南公','宋','宋诗','song-poetry','','[]','昨者小麥熟，野人稍相寬。',144,'全唐诗/poet.song.58000.json','["昨者小麥熟，野人稍相寬。", "新粟今又黄，喜聞不青乾。", "補助復幾許，久饑情所難。", "譬如轍間魚，勺水亦暫安。", "澤國農事苦，無功及丘樊。", "方與三日晴，湖岸車已喧。", "所以終歲勤，不能離薄田。", "里豪多曠土，徒用養茅菅。", "雖有願耕手，賦收重夷蠻。", "秪今二種利，稀若管中斑。", "偶穢可勸後，必荒誰繼前。", "幸哉雨露仁，副此倚望歡。"]'),
('37d7314e-536c-4e34-9d61-2a02ad9f34a2','粟熟二首  其二','呂南公','宋','宋诗','song-poetry','','[]','種田亦耕山，投隙若避毆。',60,'全唐诗/poet.song.58000.json','["種田亦耕山，投隙若避毆。", "辛勤望成熟，得慰饑歉口。", "彼豪豈知苦，踞坐科秉籔。", "憯刻以誅收，奇贏復何有。", "尚喜不荒空，呼鄰買盃酒。"]'),
('19b42dc8-ad15-49ad-b1fb-a91e8d139a4b','宿凌雲山中留寄元禮','呂南公','宋','宋诗','song-poetry','','[]','凌雲山下村，逆旅路旁宅。',288,'全唐诗/poet.song.58000.json','["凌雲山下村，逆旅路旁宅。", "南征爲吾歸，寄卧偶一夕。", "無人伴幽語，孤詠到平昔。", "瞻懷此山人，曾是同硯席。", "蕭蕭古破屋，文字堆四壁。", "青燈照題評，皎月論肝膈。", "爲詩有盈卷，飲酒無剩滴。", "携筇繞平坡，班草尚遥碧。", "栽松此山上，共看徧岡脊。", "要約過人長，俱來蔭芳色。", "羈蹤忽分袂，不啻十載隔。", "世故日紛紜，舊游空想憶。", "今來此山下，松老似百尺。", "欲訪松主人，其車已他適。", "徘徊重咨歎，輾轉對窗隙。", "晨雞一何慵，傾聽久不得。", "春風吹殘月，半夜屋角白。", "難眠却求衣，起望河漢仄。", "寄聲巖扃去，華髮勿强摘。", "善醉真良圖，高談盡癡策。", "雲泉與朝市，處處堪偃息。", "桑榆景可量，名利不足識。", "無因接清話，趁曉拊征軛。", "已度滕家橋，回頭更悽惻。"]'),
('7f7df5e3-c504-4308-b4ee-2a2322d9c36e','哭劉郎中  其一','呂南公','宋','宋诗','song-poetry','','[]','谷風拂層冰，萬凍倏忽流。',192,'全唐诗/poet.song.58000.json','["谷風拂層冰，萬凍倏忽流。", "陽暉照積雪，寸片不得留。", "郎中冰雪人，清潔映北州。", "誰令司命家，速以風日收。", "得非峻節士，地下亦急求。", "哀哉吳隠之，已矣公儀休。", "衆皆殖貨利，我獨嫉貪牟。", "衆皆似芳春，我獨如霜秋。", "多藏豈不裕，害義固所羞。", "謀身豈不急，有命其何憂。", "辛勤洛宋倅，明白盱郡侯。", "未知居此官，數有斯人不。", "孤耿一德性，紛綸萬揶揄。", "嗚呼五十年，平步落九幽。", "象闕方肅肅，銘旌遽悠悠。", "吁嗟高論儒，何以示素修。"]'),
('7219a516-4cbe-47b2-8b98-0f2c729aa1c2','哭劉郎中  其二','呂南公','宋','宋诗','song-poetry','','[]','仕則慕貴顯，貧仍憂子孫。',120,'全唐诗/poet.song.58000.json','["仕則慕貴顯，貧仍憂子孫。", "陽窮詐恬淡，此道久滿門。", "嗟乎郎中心，違衆輒十分。", "登科未弱冠，白首兩朱轓。", "笑談傾一坐，絕口勢利言。", "遥聞朱頓流，索水洗耳根。", "服不至布絮，食不辭羔豚。", "自然清白行，皎皎不可昏。", "杳杳浚郊縣，蕭蕭栢林原。", "節士今已矣，誰表三尺墳。"]'),
('2fe6565a-aa9e-4cae-9e7f-21511d0b3306','初釀','呂南公','宋','宋诗','song-poetry','','[]','歲稔穀價卑，家家有新釀。',240,'全唐诗/poet.song.58000.json','["歲稔穀價卑，家家有新釀。", "諸鄰皆屢醉，吾舍只空盎。", "封書乞餘米，故舊不我相。", "淹旬乃分酬，如憊始賜杖。", "搔然且湛熾，督迫薪火旺。", "衰遲念盃觴，伺立久骯髒。", "夜聞觱沸韵，側枕屢欣暢。", "朝來見浮蛆，喜氣愈豪壯。", "槽端乍流瀝，指面已淫漾。", "肴蔬故稀荒，被服稍質當。", "無賓與酬酢，引滿自東向。", "須臾就醺酣，豈藉紅粉唱。", "人生但能醉，此外何足望。", "憂勤欲奚爲，一譽抵千謗。", "瓶罌幸未竭，吾盞且頻康。", "迴思冷醒時，愁寂可懲創。", "隔牆聞酨氣，涎活復嗟悵。", "非無畢公心，堅壁詎窺傍。", "如今粗沾給，後得戒初喪。", "太息富貴間，平生易遺忘。"]'),
('55820bf9-0c26-4282-b2c0-9ec4acd91374','雜興','呂南公','宋','宋诗','song-poetry','','[]','時情豈不脆，轉若輪行車。',72,'全唐诗/poet.song.58000.json','["時情豈不脆，轉若輪行車。", "昨日僕役兒，今朝賓友徒。", "問之何因爾，勢利已相如。", "福祿固足駭，流品胡能拘。", "淺草有孱兔，汙淵無瘦魚。", "宜矣潔介士，望望成遠疏。"]'),
('e53fca6b-2404-4b3d-b935-713bae01abd3','題迎賓亭','呂南公','宋','宋诗','song-poetry','','[]','僧閒有餘日，憐客尋幽隈。',36,'全唐诗/poet.song.58000.json','["僧閒有餘日，憐客尋幽隈。", "開亭翠岡腹，延竚心徘徊。", "年年車馬多，誰是思山來。"]'),
('036eb3aa-87d9-4634-afe2-9d407e26126f','綠凈橋','呂南公','宋','宋诗','song-poetry','','[]','涵虛正深明，扶檻跨空闊。',36,'全唐诗/poet.song.58000.json','["涵虛正深明，扶檻跨空闊。", "共喜雲退避，更憎魚撥剌。", "相從有文酒，讙快到夜月。"]'),
('9e9a682e-c76b-4e0b-8876-3f1625e12b7b','爲子舉杯酒','呂南公','宋','宋诗','song-poetry','','[]','爲子舉杯酒，軒然放吟聲。',84,'全唐诗/poet.song.58000.json','["爲子舉杯酒，軒然放吟聲。", "豈無哀噫調，不盡幽鬰情。", "念此高簡器，早爲貧緒縈。", "迷陽乞衣食，拍拍歲月更。", "人生負意氣，曷不懷光晶。", "譬如堅貞松，豈爲霜霰生。", "永慚苟活迹，胸府針芒并。"]'),
('272cacc3-31f6-4303-9e48-f20200ef5c61','獨夜','呂南公','宋','宋诗','song-poetry','','[]','悠悠此世路，窘窘諸生業。',48,'全唐诗/poet.song.58000.json','["悠悠此世路，窘窘諸生業。", "究竟非所宜，俱爲謬參涉。", "三年就羈旅，萬事轉拘劫。", "故山歸無月，獨夜夢黄葉。"]'),
('89076419-913a-453c-a4e7-60ecd23ed4ea','塵埃','呂南公','宋','宋诗','song-poetry','','[]','塵埃倚風日，放蕩乘空飛。',72,'全唐诗/poet.song.58000.json','["塵埃倚風日，放蕩乘空飛。", "既瞇馳者目，亦緇游子衣。", "雨汁忽散漫，低徊化汙泥。", "憧憧要歧路，致困在輪蹄。", "六合局萬有，成存各從宜。", "升沉俱害物，咄此其天姿。"]'),
('b45adf82-a3ea-47b1-955d-ee7197d0daa4','鄧夫子','呂南公','宋','宋诗','song-poetry','','[]','吾交鄧夫子，富有免俗氣。',120,'全唐诗/poet.song.58000.json','["吾交鄧夫子，富有免俗氣。", "包含吉人道，混協時輩事。", "讀書三十年，恬寞無所嗜。", "物古少明眼，聲希難側耳。", "自同崑岡石，堅厚保英粹。", "不畏埃𡏖染，非求霖露漬。", "幽姿審如此，鎸錯安得致。", "余生尠諧合，幸此蒙羼厠。", "上嶽眺高遠，趨濤玩滂濞。", "由來魏王瓠，不在惠施棄。"]'),
('10c48fd2-e408-4ee1-b78f-abc75c4b729e','戲作數目詩','呂南公','宋','宋诗','song-poetry','','[]','一廛徒自受，想象聖人甿。',120,'全唐诗/poet.song.58000.json','["一廛徒自受，想象聖人甿。", "二耜慚沮溺，疲羸不善耕。", "三時徒飽食，何力助戎兵。", "四部雖該涉，心非太學生。", "五噫聊慷慨，那復慕光榮。", "六逸如堪繼，相邀且倒傾。", "七弦休撫弄，里耳悅鏗轟。", "八殺賓宜懼，過門豈敢迎。", "九年儲莫望，吟醉但忘情。", "十室論忠信，吾窮或有名。"]'),
('9fa2a964-668f-40b3-81ff-7827ec1e3c2f','南干水','呂南公','宋','宋诗','song-poetry','','[]','清泚南干水，北至白石角。',96,'全唐诗/poet.song.58000.json','["清泚南干水，北至白石角。", "中間所經過，左右恣衝搏。", "來當高岸破，去復新田作。", "洲磧幾淵潭，灣渦或垠堮。", "余思二十載，更易見已數。", "唯此磐陀磯，愈潄愈堅確。", "不然磯陰地，何足化溪壑。", "固知制變材，可健不可弱。"]'),
('3c94ee75-e850-432d-9de2-9f08010fee95','上山','呂南公','宋','宋诗','song-poetry','','[]','行臨鳥逕前，下馬理屐齒。',36,'全唐诗/poet.song.58000.json','["行臨鳥逕前，下馬理屐齒。", "林風清不徹，石路晴如洗。", "何處是招提，東峰薄雲起。"]'),
('db6ab45b-536b-4e32-b656-a1e309a476ca','夜聽車舍哀歌有感而作  其一','呂南公','宋','宋诗','song-poetry','','[]','晝歌蟬焦焦，夜歌蚊灑灑。',48,'全唐诗/poet.song.58000.json','["晝歌蟬焦焦，夜歌蚊灑灑。", "隨牛繞輪轉，濁汙常滿把。", "雖歌未嘗樂，至苦不敢捨。", "豈知清凉屋，中有悲酸者。"]'),
('5600fd37-4730-47c3-b9f0-f0798e29692c','夜聽車舍哀歌有感而作  其二','呂南公','宋','宋诗','song-poetry','','[]','甘雨不肯降，吾車幾時休。',48,'全唐诗/poet.song.58000.json','["甘雨不肯降，吾車幾時休。", "溫風忽噴然，調苦聲更愁。", "仰視河漢轉，天星愈繁稠。", "寄言擊壤人，與爾非同流。"]'),
('17743adc-61bf-4817-a1fa-544332e2fbeb','蠅驥','呂南公','宋','宋诗','song-poetry','','[]','超超飛驥尾，獵獵蒼蠅翼。',228,'全唐诗/poet.song.58000.json','["超超飛驥尾，獵獵蒼蠅翼。", "託止如雅素，主之無避色。", "相從輒騰蹋，穩望千里益。", "朝芻雁田粟，夕飲龍淵液。", "天山峻杳繚，過若影撩隙。", "神官下旁闖，展折形歎惜。", "爲言螴蜳類，命自臭穢得。", "胡然謬携載，浼爾雲天骼。", "是時决驟次，何莫懷辟易。", "駸駸驊騮前，擬越窮髮北。", "仙風響琳琅，忽遇九方伯。", "殷勤致羈絆，審按題肉力。", "咨嗟絕塵足，恨乏軼群德。", "悲此中道驥，憤死秀岡側。", "蒼蠅試回首，海霧光圛圛。", "進途當此窮，退路安可識。", "寄聲人間世，遠致毋近測。", "棲翔度材分，勿妄希彩色。", "永鑒蠅驥窮，無妨每相擇。"]'),
('bb5d0dfa-dbf2-4e45-9cb7-1954652e8f15','魚蝦','呂南公','宋','宋诗','song-poetry','','[]','神龍在重淵，羣魚喜回環。',264,'全唐诗/poet.song.58000.json','["神龍在重淵，羣魚喜回環。", "自矜龍族類，安佚無後艱。", "曉戲腥浪餘，暮游浮沫間。", "輕則遠拂渚，深之下窮灣。", "或掉其尾萃，或昂其首頒。", "或揚鬣鋒銳，或耀鱗文斑。", "衆蝦亦恣睢，不慮器質孱。", "跳骹弄牙鬚，翕習事狠頑。", "漁師畏龍威，不敢數往還。", "操舟變色過，戰汗常盈顔。", "雖有網與矢，豈容垂且彎。", "魚蝦尚忿慍，出沒如嫉姦。", "一朝風雷動，波蕩若銀山。", "神龍捨淵去，恍惚達九關。", "魚蝦不自喻，固欲嚴追攀。", "奔衝競上擊，細大不肯閒。", "須臾雲霧息，墮落如見刪。", "或委頓砂礫，或摧傷草菅。", "里兒爭擇拾，窮血彌望殷。", "漁師嘯其徒，氣貌特愉憪。", "漉淵盡取之，不復計鋝鍰。", "魚蝦雖有悔，已死誰悲潸。"]'),
('56ef60c3-e68d-4a66-8e04-0696cf9d5abb','憶亨甫','呂南公','宋','宋诗','song-poetry','','[]','詩老海上去，三年斷音塵。',240,'全唐诗/poet.song.58000.json','["詩老海上去，三年斷音塵。", "初非乘桴行，正以廩食勤。", "夢想不悟遠，聲容藐難親。", "忍無一紙書，不寄故國人。", "昨日見其子，來歸自東濱。", "能言別後意，憔悴不可聞。", "一被吏責繞，心腸載愁輪。", "忘餐躡偷黨，閱月馳空村。", "勞事欲歌詠，匆匆未成文。", "遂於筆硯間，章句絕所陳。", "亦復病肺渴，尋常廢清樽。", "唯餘滿頷鬚，增進玉雪痕。", "伊昔坐學舍，蕭條恨長貧。", "題詩日數首，大醉必繼旬。", "仰望官祿戶，謂如隔天雲。", "豈思曳尾龜，勝却居檻猿。", "不肯空谷卧，願爲監綬奔。", "毫釐一失差，千里豈得論。", "嗟我實蹇拙，平生畏侯門。", "乃無詩老愁，何耻鳥獸羣。"]'),
('eeed2e99-cfc6-45ac-b794-c4532d725cf4','寄朱九','呂南公','宋','宋诗','song-poetry','','[]','北風吹寒聲，切烈催歲暮。',144,'全唐诗/poet.song.58000.json','["北風吹寒聲，切烈催歲暮。", "中歲楚人怨，愁絕不忍賦。", "念子太學居，辛勤即誰愬。", "陰爐擁文火，敗襖感陳絮。", "無錢買酒醪，醒坐若酣酗。", "三年詁訓藝，一月江淮路。", "歸夢識親庭，都城非屺岵。", "干時無好命，費力效章句。", "堆箱纂織辭，何以貿泉布。", "男兒營養意，汲汲水東注。", "三釜若後時，萬鍾猶不顧。", "勉思豹變義，勿守株下兔。"]'),
('8645d7ce-edc2-47c4-87a4-2a88f5f9e7b3','道傍見乞士捕蝨','呂南公','宋','宋诗','song-poetry','','[]','夕陽拂西岡，黄淡映古道。',168,'全唐诗/poet.song.58000.json','["夕陽拂西岡，黄淡映古道。", "晚風吹高林，病葉落如掃。", "饑人瘦於繖，俛默坐沙草。", "扶危猶强興，力備輒反倒。", "還持藍縷縫，委曲捕蝨蚤。", "視荒數抽空，殺緩或失腦。", "悠然不能罷，似欲銳鈎考。", "寧思百骸間，羣蟻即入保。", "傍行笑相顧，慧悟信難早。", "噆傷乃知嫌，餒死豈謂好。", "方爲大銷滅，而畏小苦惱。", "何有就薪蒸，先愁稍枯槁。", "衣青嗔駡賤，髮白諱呼老。", "與爾不同年，誰能共懷抱。"]'),
('77f9002c-dc7d-4293-a14c-7a18d60b6960','麻姑山詩 初入東麓嶺路','呂南公','宋','宋诗','song-poetry','','[]','調笑背南關，虛徐夢榛梗。',48,'全唐诗/poet.song.58000.json','["調笑背南關，虛徐夢榛梗。", "稍窮田上路，一驀雲間嶺。", "身高氣漸逸，步疾神方騁。", "傾蓋歎紅塵，滿身松檜影。"]'),
('896784d1-39e2-45f3-8a36-6c8c93fefb74','麻姑山詩 息羽駕亭下','呂南公','宋','宋诗','song-poetry','','[]','仙官不日見，羽駕今誰識。',48,'全唐诗/poet.song.58000.json','["仙官不日見，羽駕今誰識。", "漫向嶺松陰，掀掀對名額。", "蓬萊旌節到，夜半麟羞擗。", "簫韵沸寒空，山人初鼾息。"]'),
('92b855b8-d809-48c9-b46a-fd47a939f400','麻姑山詩 至瀑布崖前','呂南公','宋','宋诗','song-poetry','','[]','忽過亂峰曲，隔林聞水聲。',120,'全唐诗/poet.song.58000.json','["忽過亂峰曲，隔林聞水聲。", "止車問樵夫，知是飛瀑鳴。", "下步入幽徑，蕭然覓澎渹。", "仰看百尺崖，倒瀉霜雪明。", "乍近骨肉健，久留毛髮驚。", "疑身是雷仙，滿耳鼓不停。", "六月地赤渴，平川露乾汀。", "此源一何長，奔注常淫盈。", "利澤固不淺，邦人昧嗟矜。", "徒聞晏豫時，相與憐凄清。"]'),
('d2b605e9-26bc-4fdc-9f28-849341f25c4b','麻姑山詩 至憩車亭','呂南公','宋','宋诗','song-poetry','','[]','東岡十里險，游客未嘗畏。',48,'全唐诗/poet.song.58000.json','["東岡十里險，游客未嘗畏。", "競愛仙都名，豈知林下意。", "道人亦良苦，冠簡日延遲。", "漸近金龍潭，軒車且停憩。"]'),
('e9ac3c82-4416-4e50-b13a-1690314ae134','麻姑山詩 觀金龍潭','呂南公','宋','宋诗','song-poetry','','[]','鳴泉潄石出，湍壓東崖落。',156,'全唐诗/poet.song.58000.json','["鳴泉潄石出，湍壓東崖落。", "嶮石困衝撞，穿中若深鑊。", "轟如怒雷鬭，清響振林薄。", "行人每驚窺，心骨共矍索。", "傳言天寶帝，龍以黄金作。", "并投白玉簡，敕使臨淵壑。", "應雲啟靈祉，可不憂旱虐。", "豈思嵯峨間，雨霧長所託。", "寧須藏象物，乃以致滂博。", "茫茫八紘內，至理參冥漠。", "祈禳有舊文，千載引穿鑿。", "揚雄去不返，董相誣難削。", "勿怪洞中雲，陰森護纖蠖。"]'),
('78e6f8bd-a615-4057-9cfd-ec83f1134ead','麻姑山詩 過忘歸橋','呂南公','宋','宋诗','song-poetry','','[]','朱欄跨略彴，孤絕東山口。',48,'全唐诗/poet.song.58000.json','["朱欄跨略彴，孤絕東山口。", "不見客忘歸，華標字如斗。", "軒軒六龍轡，不醉雲間酒。", "何以贈遊人，松聲雜鳴溜。"]'),
('82f3522a-cf59-475a-a9a5-c7fa48208591','麻姑山詩 至碧蓮池','呂南公','宋','宋诗','song-poetry','','[]','青紅變芙蓉，各是天然色。',48,'全唐诗/poet.song.58000.json','["青紅變芙蓉，各是天然色。", "時情苦賤眼，每歎今非昔。", "人心與物態，自古有更易。", "只使碧蓮開，游人果何得。"]'),
('4d3c923f-dfd1-4748-9e99-416012eb68fb','麻姑山詩 上葛仙壇','呂南公','宋','宋诗','song-poetry','','[]','南峰枕崇坂，逕路荆榛稠。',48,'全唐诗/poet.song.58000.json','["南峰枕崇坂，逕路荆榛稠。", "遺壇在其巔，名爲仙翁留。", "石角已剝泐，林芳自春秋。", "誰無骨中塵，來繼沖霄遊。"]'),
('099ae5fc-fbca-46bf-aca4-996c3c5aa02c','麻姑山詩 尋鍊丹井','呂南公','宋','宋诗','song-poetry','','[]','何年鍊金丹，舊井穴田腹。',36,'全唐诗/poet.song.58000.json','["何年鍊金丹，舊井穴田腹。", "飛昇誰羽翼，腐盡貪人肉。", "幽草蘸寒泉，田禽時下浴。"]'),
('dc42d43c-c56d-4d65-ac45-641e529c20b1','麻姑山詩 遊流杯池','呂南公','宋','宋诗','song-poetry','','[]','靈仙心無累，會合祗偶然。',36,'全唐诗/poet.song.58000.json','["靈仙心無累，會合祗偶然。", "當時玉酒杯，放曠隨清漣。", "不知枯池上，遂有無窮傳。"]'),
('974bc393-47ef-4ad8-947a-37da03b0faa2','麻姑山詩 宿仙都觀','呂南公','宋','宋诗','song-poetry','','[]','仙山古秀拔，百里見遭匝。',96,'全唐诗/poet.song.58000.json','["仙山古秀拔，百里見遭匝。", "樓殿出其中，鼓鐘日鏜鞳。", "𠴳𠴳雲間鶴，下取芝菌噆。", "道人鋤藥歸，月色滿畚鍤。", "夜眠依松檻，清思逼睡榻。", "起詠步虛聲，傾觴煮蔬甲。", "事有屬外念，寄之以評商。", "何由使我心，浩浩上羲皇。"]'),
('966529f4-9942-4ef8-ba98-82d5beeb963a','麻姑山詩 讀李邕天師碣文','呂南公','宋','宋诗','song-poetry','','[]','騰騰六尺碣，標置羽客墳。',168,'全唐诗/poet.song.58000.json','["騰騰六尺碣，標置羽客墳。", "龜螭尚堅完，字畫稍破分。", "道士惜故物，編扶使長存。", "前已三百年，後當幾何春。", "昔誦八哀詠，頗推李邕文。", "披襟喜此逢，再讀目愈昏。", "道固難洞達，辭猶不雄渾。", "豈殊沸鳴蛙，見謂鼓吹繁。", "惜哉開元盛，乃乏史筆人。", "復疑少陵翁，賞識或失真。", "凡例竟何有，占招僅成言。", "當時干謁兒，誤聽一走門。", "富貴世所擅，文章我知論。", "忼慨韓柳思，不返撰述魂。"]'),
('baf79a59-2806-4318-a18a-a98c34ce03dc','麻姑山詩 謁真君殿','呂南公','宋','宋诗','song-poetry','','[]','稽首香案下，索火續新烟。',156,'全唐诗/poet.song.58000.json','["稽首香案下，索火續新烟。", "徘徊想功行，緬盡千載前。", "念昔魏晉間，士流罕身全。", "高人樂遺世，學者習虛玄。", "往往迷至道，琅琅漫清言。", "真君當此時，豈以口吻賢。", "獨持濟衆術，敢論名後先。", "陰隲竟感格，飛昇遂聯翩。", "嚴嚴白玉京，侍從皆羣仙。", "舊宅入祀典，列祠更他巔。", "平生豈有意，德在名自傳。", "浩浩一氣游，蕭蕭諸象專。", "孰能知真君，庸俗但告虔。"]'),
('a96853f5-8537-4d69-9755-f68967d24364','麻姑山詩 三清殿西廡見穆質題名石刻','呂南公','宋','宋诗','song-poetry','','[]','香像壞已久，虛名在金石。',120,'全唐诗/poet.song.58000.json','["香像壞已久，虛名在金石。", "深知無窮傳，須以託文墨。", "穆卿剛直者，公論觸權戚。", "至於禍福間，亦有隨俗迹。", "端知守財虜，倚此銷罪慝。", "秪今蚩蚩流，持論能引掖。", "憑誰致我語，解彼蚩蚩惑。", "欲慕穆卿賢，當充穆卿德。", "區區建香像，是乃卿瑕讁。", "用此而希卿，何殊以耳食。"]'),
('02bc8bc7-9fac-4c89-9f52-1382e0458fe4','麻姑山詩 殿後七星杉','呂南公','宋','宋诗','song-poetry','','[]','巖巖寥陽殿，東有蔽牛杉。',96,'全唐诗/poet.song.58000.json','["巖巖寥陽殿，東有蔽牛杉。", "下無蘿薜拘，上有雲霧參。", "靈根不納老，秀色長如天。", "已據烟霞都，更带星斗銜。", "成名在圖籍，匠手安得芟。", "由來非自謀，時值本不凡。", "鸞鶴豈無侶，棲翔倚䰐鬖。", "詎知高古林，大用有所堪。"]'),
('f1d7e3f4-7399-41be-8175-1067334344d3','麻姑山詩 上齊雲峰','呂南公','宋','宋诗','song-poetry','','[]','人言此峰峻，謂與浮雲齊。',144,'全唐诗/poet.song.58000.json','["人言此峰峻，謂與浮雲齊。", "浮雲雖滿空，勢自有高低。", "驚名不察實，世論所以迷。", "爲君上峰頭，曠望窮東西。", "杳繚城下澗，遥遥線環堤。", "人烟衆邑屋，蒙密亂町畦。", "想彼平地眠，仰如遇昏雞。", "應論峰頭人，已盡天路梯。", "古士說高廣，中州扺倉稊。", "豈嘗駭嶔岑，隘若坐一閨。", "安得千尺翼，翻身逐飛霓。", "扶搖過丹山，飽聽鳴鳳嘶。"]'),
('0c267a6f-6783-4177-a41d-55e957af73e2','麻姑山詩 道法堂檢點三帝御書','呂南公','宋','宋诗','song-poetry','','[]','日脚退前楹，崇堂豁明凈。',192,'全唐诗/poet.song.58000.json','["日脚退前楹，崇堂豁明凈。", "縑緗出百函，翰墨睹三聖。", "舒張溢牆壁，燦爛累籤㡠。", "鸞龍交飛翻，金石避堅硬。", "毫無半分弱，大至袤丈勁。", "真行體兼精，篆籀法畢正。", "篇章入題寫，作者一何幸。", "偉哉天縱能，豈謂學成性。", "名山徧藏蓄，終古得輝映。", "墨客徒醉心，黄冠荷覃慶。", "嘗思八世主，覆燾足仁政。", "詩書所敷揚，乃獨蔑此命。", "將非史官略，紀敘非盡併。", "不然天日資，肯特記名姓。", "或應淳古治，不以餘藝競。", "膚淺難考評，隨羣但稱盛。"]'),
('a5723be8-a383-4a87-a26e-3773eaf2a036','麻姑山詩 無爲閣見楊傑記仙都花','呂南公','宋','宋诗','song-poetry','','[]','山風吹春來，仙花靚如面。',48,'全唐诗/poet.song.58000.json','["山風吹春來，仙花靚如面。", "芳馨豈不美，俗耳未肯賤。", "吾聞西州地，薪以牡丹爨。", "何嫌此中花，開落無人看。"]'),
('08373d55-43e4-4dc1-bf31-b4641f1060ae','麻姑山詩 望秦人峰','呂南公','宋','宋诗','song-poetry','','[]','此地去秦中，贏糧每三月。',96,'全唐诗/poet.song.58000.json','["此地去秦中，贏糧每三月。", "秦人不厭遠，期以一死脫。", "何言幸可數，久竟各存活。", "得非潜逃心，世愛多洗割。", "迥然深林嶺，雲氣長不滅。", "避俗可成仙，斯言蓋疏闊。", "余來翠峰地，把酒望深樾。", "不見雲霞身，山禽但驚聒。"]'),
('3c58e753-fd75-4f77-9171-230165ded0e6','麻姑山詩 三門橋望五星峰','呂南公','宋','宋诗','song-poetry','','[]','弄水石橋西，退蔭百尺松。',168,'全唐诗/poet.song.58000.json','["弄水石橋西，退蔭百尺松。", "看山同羽人，初問五星峰。", "爲我袖手指，當前秀蒙籠。", "平排五青尖，似拱寥陽宮。", "自外雖峛崺，其高莫能同。", "固知天下名，有以形類通。", "不然天精緯，詎或聚此中。", "他山岡阜名，頓拔亦俊雄。", "民耕牛羊踐，稱謂誰與宗。", "維此古洞府，羣仙屢從容。", "烟霞庇草木，題號更峻崇。", "融結俱土石，靈凡異遭蒙。", "想當有初物，豈自知所從。", "嗟嗟蓬蓽士，何用羨帝公。"]'),
('21c3ad96-0c92-4441-9bbf-e7f162857ee0','麻姑山詩 問玳瑁石所出','呂南公','宋','宋诗','song-poetry','','[]','陂陀土中石，含彩若龜貝。',120,'全唐诗/poet.song.58000.json','["陂陀土中石，含彩若龜貝。", "伊誰攻取之，傳玩詫奇怪。", "山家厭搜鑿，養草事蔽蓋。", "閒名偶流聞，尚自困酬對。", "咨嗟人間世，豈直文爲害。", "大有可用姿，難能免侵敗。", "他山石不美，粗雜等頑塊。", "奈何亦爭求，爛漫入磨扢。", "情知既有物，順以除惡愛。", "不然悠悠生，孰在形器外。"]'),
('7be20338-5d3e-4230-b4bf-d2bf2983df8f','麻姑山詩 觀虎跑泉','呂南公','宋','宋诗','song-poetry','','[]','名山一境鎮，水土本深厚。',96,'全唐诗/poet.song.58000.json','["名山一境鎮，水土本深厚。", "誰令虎來跑，應爪泉飛透。", "吾知變化物，持氣異羣畜。", "慚愧剛猛身，堂堂負文繡。", "仙鄉既遊歷，不忍無所就。", "怒掌發靈蹤，山祇助噴溜。", "乾坤任陳故，稱號長芬富。", "歎息泯泯人，平生不如獸。"]'),
('efae25bd-a062-48d9-b834-a3821af96c00','麻姑山詩 入丹霞洞','呂南公','宋','宋诗','song-poetry','','[]','霞光滿西山，古洞在其下。',72,'全唐诗/poet.song.58000.json','["霞光滿西山，古洞在其下。", "石老只嵌空，泉寒亦飛瀉。", "有居容冠褐，無路縱車馬。", "遊人務周徧，强往不敢捨。", "森森南榮樹，飄葉撲香灺。", "過盡去來人，誰爲愛閒者。"]'),
('38281328-1970-4658-9f63-4d3c7e2fffa7','麻姑山詩 出山有感','呂南公','宋','宋诗','song-poetry','','[]','偶隨愛山客，亦賦看山詩。',48,'全唐诗/poet.song.58000.json','["偶隨愛山客，亦賦看山詩。", "方爲昔日登，又作今日歸。", "勞生竟何有，清賞不可期。", "故慚康樂侯，萬里窮攀躋。"]'),
('dfe977fb-80a1-4b2d-9044-2dc4b8d24b4c','答道先難交困新知二首  其一','呂南公','宋','宋诗','song-poetry','','[]','難交困新知，觸事得晚悔。',96,'全唐诗/poet.song.58000.json','["難交困新知，觸事得晚悔。", "人方趨勢富，我獨居老大。", "悠悠强衰顔，耿耿墮末界。", "豈無相於迹，襟腑殊惡愛。", "羞同復多嫌，樂與翻自壞。", "譚高遞互笑，飲勇周旋怪。", "嘉榮徒染濡，程孔肯傾蓋。", "閉門當止矣，非敢事閒退。"]'),
('59878f58-d367-470e-b2ea-fa489ec42585','答道先難交困新知二首  其二','呂南公','宋','宋诗','song-poetry','','[]','孤坐念平昔，悽然垂涕洟。',108,'全唐诗/poet.song.58000.json','["孤坐念平昔，悽然垂涕洟。", "他鄉二十遊，故里四十歸。", "父老略已盡，後來異襟期。", "卑躬揖我進，反顧問我誰。", "譬彼古器物，形模漫瑰奇。", "堯冠落戰國，不貴理亦宜。", "嘿塞習蹇吃，遲徊避橫飛。", "秋風吹我鬚，蕭颯近素絲。", "多感屬暮齒，難交困新知。"]'),
('bbca271c-8db9-40b5-a9c5-0e80bd6f5675','道先賢良以南公出山愆期示詩見促謹依來韵奉答','呂南公','宋','宋诗','song-poetry','','[]','爲農豈非天，歸計恨不早。',72,'全唐诗/poet.song.58000.json','["爲農豈非天，歸計恨不早。", "業已入犁鋤，謀惟在粱稻。", "春霜久不解，乾渴滿耕隩。", "布穀彼何心，聲聲似相報。", "不知蘭臺聚，安用樊間老。", "定許叩鈴齋，柴居就長道。"]'),
('b0760613-7fc8-4bc5-9928-fc00209a71a5','以雙井茶寄道先從以長句','呂南公','宋','宋诗','song-poetry','','[]','園公嗜慾淺，所好盃中物。',288,'全唐诗/poet.song.58000.json','["園公嗜慾淺，所好盃中物。", "有田在荒村，半以種糯秫。", "居然成醖釀，不復畏法律。", "客至啟柴扉，甆甌等閒出。", "春蔬間菘韭，秋果雜梨栗。", "取次得寬懷，何曾計餘日。", "山棲經五載，此興殊不失。", "獨有醒覺時，追傷往年屈。", "羈游住破屋，愁寂靠𨧱銊。", "仰望步兵厨，優如上公秩。", "無錢輸榷吏，窮素又畏咄。", "太息蘇源明，仁襟信奇倔。", "低徊憐鄭老，長使醉兀兀。", "發我感古人，何緣希彷彿。", "粵從歸村後，夙恨億萬畢。", "耕稼雖自勞，醺酣不他乞。", "親朋或知我，問訊俱委悉。", "亦有贈助恩，無非佳紙筆。", "鄰家世耝耰，竊笑事儒術。", "故故送樽壺，端爲鷂欺鶻。", "披襟忍辭拒，對案傾倒訖。", "特是今叚乖，遭承極紆鬰。", "遥遥海南尉，憫我卧蓬蓽。", "寄以累幅書，封題附郵驛。"]'),
('98f13c2b-b356-489f-b3af-28aeb35ca7f0','謝鄰翁','呂南公','宋','宋诗','song-poetry','','[]','窮秋我何事，歲計聊支準。',288,'全唐诗/poet.song.58000.json','["窮秋我何事，歲計聊支準。", "割稻三萬斤，栽松二千本。", "辛勤完廩庾，顛倒糞畦畛。", "爲有空腹憂，能忘此時謹。", "菘肥競垂陰，稻美方聯稛。", "自喜在丘園，年衰且優穩。", "天功偶不助，人力翻爲窘。", "彌月雨連淫，交冬霜不隕。", "蔬長煮有綫，穀濕舂多粉。", "厚望乃無聊，蕭如被宮臏。", "今朝二十九，看歷驚秋盡。", "去臘都幾何，陽烏尚高隠。", "鄰翁巧譚話，念我頻嗟憤。", "杖插肯經過，單辭稍牽引。", "上論穹昊意，窅嘿難裁忖。", "下說倚伏端，回環恒切近。", "熙寧大丞相，周孔登台衮。", "手運道德樞，生靈藉鍼診。", "勞神十五載，坐許無遺恨。", "歸卧睫未交，紛紜見矛盾。", "推稱忽排毀，歌詠俄咍哂。", "藹藹攀附人，層霄墮污溷。", "前愚初是智，昔禹今成鯀。", "譬彼羹涴衣，倉黄可潄抆。"]'),
('877acf7b-1509-4b3e-95c2-27bc07c34466','寄濟道','呂南公','宋','宋诗','song-poetry','','[]','有田山陂間，年歷六七過。',288,'全唐诗/poet.song.58000.json','["有田山陂間，年歷六七過。", "買園丘墓側，畎畝十丈大。", "於焉擬柴荆，垂就又垂破。", "豈無速成意，煎逼少財貨。", "淹留寄他門，一跌防百蹉。", "詩書相娛老，兒女既翦鬌。", "何必隨羈游，無屋覆高卧。", "昨來錢可貸，似有鬼陰佐。", "鄉閭喜吾歸，驚咤競告譒。", "一茅曾未結，羣盜忽譀𧬱。", "旌旗蔽枌榆，弓箭擁籬舍。", "連甍被焚蕩，萬室逃斫剉。", "吾衰當此時，林下若爲坐。", "蒼茫依井邑，買舍寧敢惰。", "迎家郡樓南，庭戶困堀堁。", "庇風惟古壁，容足乏高座。", "平生灌園心，一旦入頓挫。", "譬如千鈞弩，激發不中埻。", "力窮墜泥沙，豈免埃𡏖涴。", "浮沉非所善，耿介誦楚些。", "鄰叟異吾徒，軒咍不垂和。", "慇懃懷我友，契闊似棄播。", "早以聲氣同，中爲章服裹。", "牛刀到芥羽，蜀錦拭奴唾。"]'),
('401e475a-e400-4048-b487-1c41a9030a65','寄子發','呂南公','宋','宋诗','song-poetry','','[]','後事喜乖初，勞生擬何稟。',240,'全唐诗/poet.song.58000.json','["後事喜乖初，勞生擬何稟。", "思山有藏市，願起或成寢。", "交聲違本心，歎恨只愈甚。", "聽君東堂言，去計非苒荏。", "外危速官謗，內迫將母稔。", "不能傚飛鴻，爲悔比拾瀋。", "寒鄉有舊隠，秔稌歲充廩。", "及此掛吾冠，逍遥適衾衽。", "咨余方問舍，期就指冬凜。", "相邀林野娛，高詠略宋沈。", "閩蠻忽煽虐，白刃萬胸脩。", "驚奔託城闉，默若魚在槮。", "問君歸來信，延佇久纔審。", "亟聞漕臺公，推待過流品。", "縻留不許退，讒口亦旋噤。", "古人制行藏，緩走不爲𧾏。", "况今羣盜熾，巖谷豈安枕。", "秋風又開菊，庭砌鋪故錦。", "江鱸鱠絲肥，蔬果具豐稔。", "相思東堂遠，努力文字飲。"]'),
('f3ab6bfe-bf62-406d-8d1b-5f7e542e7f38','中山感懷','呂南公','宋','宋诗','song-poetry','','[]','西村灌園生，好尚只墳史。',288,'全唐诗/poet.song.58000.json','["西村灌園生，好尚只墳史。", "偶爲凍餒驅，放浪離桑梓。", "初謀旅人食，歲月涒灘紀。", "城西謁郎官，辭業入驚喜。", "題門辱皇甫，啖炙煩周顗。", "積漸近攀援，依稀召訾毀。", "郴陽不果往，劉館聊凄倚。", "俛仰秋夏交，飄然動行李。", "凌雲古空谷，中卧幽真士。", "寄書使來前，得共考經旨。", "依從得所好，不分嚴霜委。", "宵話酒乾樽，朝遊屐磨齒。", "春風忽浩蕩，客興又遷徙。", "邑里有名卿，相尋走函紙。", "淮南官未赴，盱上船猶艤。", "祿廩見賸餘，羈栖請依止。", "蕭條出門去，四月大江水。", "荏苒向樅山，愔沉傍書几。", "侯鯖豈無味，旅疾或多鬼。", "諷誦難呻呼，辛勤一朞矣。", "天書問鄉貢，侮角士爭起。", "却治舉場文，歸參白襴子。", "征鞍遂南首，故園衝炎晷。", "把卷詣棘闈，駢羅聚千趾。"]'),
('dcbe7b51-68ae-4b23-b7e8-337359c9dcdf','壬戌歲歸治西村居奉答次道見寄長句','呂南公','宋','宋诗','song-poetry','','[]','肅肅白虎殿，潭潭承明廬。',144,'全唐诗/poet.song.58000.json','["肅肅白虎殿，潭潭承明廬。", "人皆通籍游，我獨老飯蔬。", "譬彼獸啖土，豈其惡甘腴。", "道窮吾何之，只得歸荷鋤。", "盛夏督耘耔，先春理陂渠。", "低徊居未寧，倏忽歲又除。", "但怯簿有債，誰羞門少車。", "載歌裹飯辭，謁酒聊自娛。", "念子早奮拔，聲華係名駒。", "誰云破青衫，罪謗更勃如。", "朝野固異分，知安盡夷途。", "牛衣與樵歌，各是對妻孥。"]'),
('2e1bcc65-a09e-42f1-9f9f-1d9be4842c7d','烟雨','呂南公','宋','宋诗','song-poetry','','[]','朝來烟雨重，天與平田接。',168,'全唐诗/poet.song.58000.json','["朝來烟雨重，天與平田接。", "輕風更蕭蕭，清快繞我睫。", "開扉覓高嶺，沒若隔世劫。", "不見蒼翠顔，徘徊坐搘頰。", "農夫一何樂，羣輩聚稠疊。", "移秧塞塍圈，狼籍衣不攝。", "諠闐交野語，蹲踞就晨饁。", "臺笠映扉蓬，端能勝經笈。", "人生慕溫飽，萬趣歸一愜。", "何必少髭頦，區區羨長鬣。", "吾村有荒圃，吾屋葺未輟。", "早晚畫度全，方將事農業。", "耕耘黨既入，歌笑聲可躡。", "雖欲著新書，無妨理鍬鍤。"]'),
('1a17f4d4-0889-4a58-98d1-fa1e5523a080','傍湖行觀','呂南公','宋','宋诗','song-poetry','','[]','十日不出門，厭聞水車聲。',96,'全唐诗/poet.song.58000.json','["十日不出門，厭聞水車聲。", "昨來新雨足，耳外忽晏清。", "步屧踏初霽，舒徐繞塍行。", "向時荼蓼處，荒穢略殄平。", "青秧漸瀰漫，黑手益縱橫。", "固知農趨時，豈特勸督明。", "下士能致力，高天得無情。", "願言成歲豐，庶免寇盜驚。"]'),
('89f981da-0268-4db0-8863-ca65bc3eaa2c','覆船山','呂南公','宋','宋诗','song-poetry','','[]','峨峨覆船山，特起秀蟠勃。',294,'全唐诗/poet.song.58000.json','["峨峨覆船山，特起秀蟠勃。", "當前百十里，已見青突兀。", "行瞻漸詳諦，依約認毫忽。", "西峰自排列，儼若魁健卒。", "羣阜復東迴，欽如搢珪笏。", "橫岡挺戈劍，堅重不可杌。", "峻嶺擾騧驪，豪雄欲相揬。", "或寬侔放蕩，或迫類{甚乍}{甚卒}。", "或象喜紆餘，或同怒詬咄。", "林高盛巾幗，畬破露鬝禿。", "有險狀饑癯，有坌似壯腯。", "偉哉形態衆，盡敘難以猝。", "憶隨遊覽後，深入禪宅窟。", "樵徑坦復崎，遥村現還沒。", "是時五月晦，寒氣尚切骨。", "汲泉煮茶雲，石鼎沸鬻雪。", "夜垂紙帳卧，疑近鬼窸窣。", "曉引杖屨行，巖巒徧緣踤。", "幽坡獸跳𮛬，佳樹鳥咽嗢。", "飛瀑下層崖，鏗清斷污淈。", "分流浹田壤，千里利耕搰。", "愛此爽洒都，擬詠屢蹇訥。", "何由結廬舍，靜取蔬茹捽。", "夢想空洞靈，孤雲動飆𩖨。"]'),
('ba23f67b-5282-4792-99e4-6c24b883286d','奉和內翰太中城南放魚','呂南公','宋','宋诗','song-poetry','','[]','沾沾水中魚，生死豈有知。',216,'全唐诗/poet.song.58000.json','["沾沾水中魚，生死豈有知。", "成形四氣中，積漸長鱗鬐。", "但喜藻可依，未諳龍可隨。", "茫洋天地間，寄命此郡西。", "歲有竭澤例，肯縱捨者誰。", "秋潦走海去，荒壕已愁饑。", "方將赴烹芼，逃避計若爲。", "萬里雷雨解，一時離兌暌。", "夫何遇仁賢，顧盼成嗟嘻。", "載憫口腹累，鮮能毫髮遺。", "支川以三千，此獨數畝池。", "脫爾倉猝急，吾其亡肉糜。", "呼舟送中流，狡吏敢挾私。", "曾是潰爛勢，忽稱太平時。", "波瀾網罟多，要在慎所之。", "香餌不足愛，古言未應非。", "丙寅元祐年，內相守楚夷。", "愷悌見篇詠，魚乎爾恩斯。"]'),
('bbde843e-c625-417b-9b4e-dd697df216c2','偶遊僊都道先以長句見寄依韵奉答','呂南公','宋','宋诗','song-poetry','','[]','吹燈染小帖，借馬忤廐人。',288,'全唐诗/poet.song.58000.json','["吹燈染小帖，借馬忤廐人。", "豈其事朝參，强欲觀雲泉。", "盥櫛具袍带，超遥石橋間。", "同征二十蹄，駑駿亂後先。", "朝曦遽突兀，送我溢背溫。", "樂郊民何知，桃李自滿園。", "逶迤松下路，不踐已八年。", "道翁喜吾來，煮茗巨石根。", "導我復勉我，攀躋繞巑岏。", "依依夢中遊，忽得驚覺魂。", "一聽鐘鼓響，載慚塵土昏。", "顧茲清泚流，照洗憔悴顔。", "曀曀金碧光，嘈嘈杉檜喧。", "樓臺有新增，碑版多舊觀。", "嘯客徧廂闥，周爰訊黄冠。", "白頭師靈仙，不免歸丘墳。", "太息五濁士，憑癡待飛翻。", "譬持數寸膠，擬救九曲渾。", "往者不肯說，來乎付誰怨。", "唯當悟至真，可入了世論。", "崔嵬黄守庵，本是劉伶褌。", "憶我初借卧，嗒焉過西曛。", "踏黑叩歸戶，倉忙遭駡言。", "寧知復來時，邂逅乃見尊。"]'),
('a9df7e6f-7d32-46dc-a756-fb7a5eb26df8','蔡翁','呂南公','宋','宋诗','song-poetry','','[]','蔡翁高古士，終始素踐清。',240,'全唐诗/poet.song.58000.json','["蔡翁高古士，終始素踐清。", "曉然不欺心，可抵日月明。", "二十弄賦筆，周流教諸生。", "四十背辭場，歸來閉柴荆。", "長子力近利，旨甘足謀營。", "次男治詩書，庭戶弦歌聲。", "居止在城邑，身如隠林坰。", "舊交勢富門，十載不一登。", "稼穡有凶稔，翁無田可耕。", "閭閻多是非，翁耳不爲傾。", "蕭條一畝宅，裕若據八紘。", "書囊配酒樽，此外毫髮輕。", "晚醉有癭枕，朝饑有藜羹。", "未知窮與通，何者當達情。", "維彼九章衮，煖外未覺榮。", "維彼八味珍，飽來無足矜。", "妻子亦垂白，息孫初習行。", "讙愉同百年，世患安得攖。", "嗟我稍濩落，晚能慕幽貞。", "何由似吾翁，坦坦寄餘齡。"]'),
('f90f4a79-364d-4c92-ac3d-f60579e32f04','早穫','呂南公','宋','宋诗','song-poetry','','[]','溫風扇炎節，高壤見新稻。',120,'全唐诗/poet.song.58000.json','["溫風扇炎節，高壤見新稻。", "蒼黄色猶雜，鎌擔力已到。", "時當艱食久，不暇論贏耗。", "奔奔竭頃畝，翕翕資釜竈。", "蒸炊防碎折，焙煏取乾燥。", "鄉鄰自齊同，早暮誰諷告。", "老翁操匕筯，一食九嗟懊。", "豈凶存後憂，飽飫偶今暴。", "驕陽有炕暵，積雨或淹澇。", "未是安眠人，兒童但嬉譟。"]'),
('1098ae76-7a91-4a2c-be79-a957c6253fe7','窮鬼','呂南公','宋','宋诗','song-poetry','','[]','窮鬼斷去志，送之豈無文。',288,'全唐诗/poet.song.58000.json','["窮鬼斷去志，送之豈無文。", "譬如衢路埃，屢歸已復新。", "隨我三十載，間關不辭勤。", "誘我上債臺，爲我擁愁根。", "羈旅風雨夕，空廬冰雪晨。", "贊成蹇拙謀，謹守冷靜門。", "遇酒或略避，見錢輒生嗔。", "亦憎富貴兒，永矢不失身。", "昨者試羣士，閴亡忽連旬。", "謂其捨我行，忍不許我聞。", "乃復跳籬棘，譸張幻司閽。", "吹沙衆官眼，使視玉爲珉。", "詭計動有效，更誰評正真。", "歸來只康然，知我恥奏論。", "憶昔熙寧初，與子俱食貧。", "相語厭此鬼，多方願崩分。", "宗伯正憒惑，委其制風雲。", "倉黄刖我足，置我寂寞濱。", "子脫白布衣，鬼顔愁不欣。", "自子有官守，辭鄉八青春。", "坐想廩俸優，寧復鬼敢親。", "今者枉書札，無財亦云云。", "信哉此鬼多，不限吳楚閩。", "陰靈雖叵測，要自有婚姻。"]'),
('0f3da387-47e7-45d1-b87e-d6c97fc5ca87','讀東方朔傳','呂南公','宋','宋诗','song-poetry','','[]','武皇肆荒惑，公卿噤忠齦。',144,'全唐诗/poet.song.58000.json','["武皇肆荒惑，公卿噤忠齦。", "先生有直舌，談笑開吾君。", "董偃不敢怨，壽王誰與伸。", "堂堂補衮心，不厭犯怒頻。", "豈不顧仕養，崇卑位泥雲。", "耻同高論儒，瑟縮憂烹焚。", "賢人事昏主，獻替視所因。", "不爾朝野間，誰非愛其身。", "彼哉下世士，所見異吾聞。", "醜謬無不爲，乃思謗遺塵。", "國風歌善戲，孔聖許狂人。", "何嫌班孟堅，區區記餘芬。"]'),
('85d9581d-98ca-4e67-b5bc-24cbccd045b8','過巫師步','呂南公','宋','宋诗','song-poetry','','[]','還過巫師步，竚立想平昔。',288,'全唐诗/poet.song.58000.json','["還過巫師步，竚立想平昔。", "不見舊門閭，蒼蒼但榛棘。", "當時修竹圃，十里認濃碧。", "佳樹鬰瓏璁，高能百餘尺。", "連甍覆多瓦，厚塹疊堅甓。", "生計具安恬，鄰人總驩適。", "非無四時樂，乃預五等籍。", "不知九載間，剗滅自誰力。", "或尤近川水，川水豈其蹙。", "隄岸盡民廬，何斯最崩析。", "有疑沿鬼道，浮誕致淫慝。", "僻術固欺人，窮祆蓋傷德。", "不然當合會，大數名終極。", "幽玄竟難量，理意浪參測。", "憶初羈角歲，文字未深識。", "此地事遨嬉，隨羣慣經歷。", "波瀾澆暑汗，略彴騁霜屐。", "逗曉集圍魚，連宵按傳覡。", "走聽鐃鼓動，就視符籙敕。", "座軋歌神兒，盤分受釐食。", "中家餽牲果，豪屋送金帛。", "弟子爭聚藏，巫師坐欣懌。", "顧余方𦕈弱，比衆似岐嶷。", "撫省更呼留，慇懃賜遮扼。"]'),
('67ea2397-1f64-4423-9b29-056ea4947321','過辭歸嶺','呂南公','宋','宋诗','song-poetry','','[]','老翁愛園廬，未省越鄰塢。',120,'全唐诗/poet.song.58000.json','["老翁愛園廬，未省越鄰塢。", "婚姻挽他鄉，送客犯脩阻。", "委蛇上高嶺，四顧異吾土。", "相揖遽辭歸，驚如避豺虎。", "漂浮千世下，出意能近古。", "游子笑安居，相傳入名譜。", "黄塵壓碎石，歲月知何許。", "但有鬰蒼松，亭亭待斤斧。", "秋風吹我馬，路向此山取。", "因名重徘徊，不獨行役苦。"]'),
('69f92afb-b5dc-48ba-9be7-236c5389bc70','過憂劫嶺','呂南公','宋','宋诗','song-poetry','','[]','强步已半日，前岡更悠悠。',48,'全唐诗/poet.song.58000.json','["强步已半日，前岡更悠悠。", "下如趨龍宮，上若登雲樓。", "不見人舍宅，但聞鳥喧啾。", "我行只空囊，盜劫誰知憂。"]'),
('54e24e6d-60f1-4f8f-b00b-373f689cfe48','五月二十五日三陂橋晚眺','呂南公','宋','宋诗','song-poetry','','[]','漲水久已退，擎泥草扶疏。',192,'全唐诗/poet.song.58000.json','["漲水久已退，擎泥草扶疏。", "平疇極我目，一來施犁鋤。", "九夏行過六，尚憂復污潴。", "哀咨此鄉民，耕力豈躊躇。", "地勢苦卑薄，况無古川渠。", "愁潦懼熯乾，不可保終初。", "昨者多暑雨，洪波日凌虛。", "新來滿旬晴，滲涸類灌蒩。", "垂秋且當蒔，到否知何如。", "搖搖衆農心，凜若畏簡書。", "遠瞻來南山，其壤似郊墟。", "依微綠秀間，浮白略散舒。", "間喜早稻吐，因高得紆餘。", "幸無風早催，聊濟升斗儲。", "天下有大福，唯民樂田廬。", "樂哉俟豐登，快我羈旅居。"]'),
('c32adbff-0516-448e-b167-2b9902758993','詠榴花','呂南公','宋','宋诗','song-poetry','','[]','敷敷英乍含，春盡葉已碧。',120,'全唐诗/poet.song.58000.json','["敷敷英乍含，春盡葉已碧。", "垂垂實稍殘，秋晚花尚拆。", "鮮妍誰造化，遲暮我彩色。", "方託晨露滋，何知早霜烈。", "天時豈顧望，生理自溢逼。", "根柢或未衰，芳葩肯無益。", "徐孃老情重，武后善塗澤。", "所美出虛疏，其殃乃窮極。", "參差共沖氣，窈窕負靈識。", "草木可毋譏，吾傷在人德。"]'),
('d1ba360c-4fef-4964-949c-9c80e3f82aef','俗士','呂南公','宋','宋诗','song-poetry','','[]','俗士各何在，來登蓋徒然。',108,'全唐诗/poet.song.58000.json','["俗士各何在，來登蓋徒然。", "彼其見湖山，乃特論價錢。", "爲此可徑絕，陰梯阻狙猨。", "當有詩酒豪，相將快留連。", "一醉抵萬寶，高吟對遥天。", "下視闤闠兒，污埃盡癡年。", "嗟我濩落手，平生負雲烟。", "題詩不放縱，或似摹印圈。", "安得冰雪才，同聯座中篇。"]'),
('f63d1091-57ec-447a-8cfa-de837bb03b9c','歲除感舊','呂南公','宋','宋诗','song-poetry','','[]','舊德無路報，衰年又增多。',168,'全唐诗/poet.song.58000.json','["舊德無路報，衰年又增多。", "平生感激心，恐懼成蹉跎。", "幽幽黄鍾原，總角便經過。", "一飯倚從母，徘徊類媕婀。", "學書隨羣童，讙叫抵雁鵝。", "相逞知字畫，勇於渴尋河。", "羞耻道趙壹，矜誇有甘羅。", "豈云幼慇懃，乃取晚坎軻。", "荏苒三十載，萬千窮祟魔。", "舊遊不得尋，聽問徒悲歌。", "秋霜壓芳蘭，豈復異徑莎。", "願見故根畹，邈如隔岷峨。", "老窮怯脂韋，趣尚近笠簑。", "此恨長不沒，安能辨蒿峨。"]'),
('cb4554b0-2524-4fb3-b5d4-566fd9293038','偶題北軒','呂南公','宋','宋诗','song-poetry','','[]','說儒論四方，以北爲背明。',192,'全唐诗/poet.song.58000.json','["說儒論四方，以北爲背明。", "蓋言幽陰位，有嚮即非亨。", "遂令口耳兒，惡北如近刑。", "安知壬癸交，於此兆萬靈。", "天元氣始降，坎水首五行。", "理數漸推遷，至兌乃秋成。", "餘陰與初陽，分此朔易庭。", "故爲始終地，變化容可輕。", "不但天道爾，人爲亦該并。", "帝王宅九垓，輔相羅賢英。", "德雖若伊周，稽首爲公卿。", "如其惡北面，誰以臣庶稱。", "吾知講析師，苟以巧自矜。", "何能亂達識，止可欺愚冥。", "吾來坐書屋，軒楹有北名。", "題詩非賦詠，聊以說儒憎。"]'),
('164d55d1-3f4d-4154-9647-c343347f3bb4','初遊投子山','呂南公','宋','宋诗','song-poetry','','[]','東山未嘗到，興言往遊觀。',228,'全唐诗/poet.song.58000.json','["東山未嘗到，興言往遊觀。", "尋幽味已淡，全勝交凡官。", "揚鞭遂出郭，樵路行縈彎。", "遇險輒捨馬，聽松頻側冠。", "霜天正枵寥，野吹何蕭酸。", "强步且數里，猶在荒林間。", "峰回得古寺，一叩雲中關。", "高僧奪睡出，迎對如嗔煩。", "解榻迸伏鼠，煮茶爆新泉。", "東亭一何高，岌若崖臨淵。", "西庵更爽亢，基與堂甍班。", "延緣徧登坐，共羨閒人閒。", "同遊二三子，取酒醺吾顔。", "約略脩市果，橫斜列山盤。", "飲語快不徹，望睫張無端。", "曦光忽銜西，歸思攻餘歡。", "撩樵灑醉毫，拂壁羅矛干。", "調笑下前坂，暮色凄漫漫。", "行矣重回首，林凹數聲猨。"]'),
('28021923-4b50-4a6d-8e50-65a7e5b4e104','答濟道','呂南公','宋','宋诗','song-poetry','','[]','外物不可必，一官非我心。',180,'全唐诗/poet.song.58000.json','["外物不可必，一官非我心。", "榮生在適分，素願乃山林。", "知恩已三年，趣幕不覺深。", "因君累幅書，更激浩歎音。", "衮衮旦復暮，勞勞古猶今。", "其誰有功名，不顧憂患侵。", "富貴豈不欲，才力視所任。", "長鯨舞天淵，寸鮒安牛涔。", "性亦各得耳，何爲辨差參。", "夫子方得路，未應棄光陰。", "咨余厭卑摧，謀望止尺尋。", "誓買五畝宅，歸休以浮沉。", "耕漁入程途，文字亦所欽。", "看子展雲翼，騰凌和薰琴。", "還將草堂書，敵子朱與金。"]'),
('5646d0eb-3afe-48f2-bc33-d6dbea9b6e4f','答陳公美','呂南公','宋','宋诗','song-poetry','','[]','少壯事已遠，舊文良可懷。',288,'全唐诗/poet.song.58000.json','["少壯事已遠，舊文良可懷。", "百年能幾何，十載不得偕。", "念昔居鄉里，游處了無猜。", "飲食不相捨，談笑久所陪。", "拜君以爲兄，分密誰敢開。", "齒髮俱未老，未至衰與頹。", "我子在襁褓，君猶無嬰孩。", "君後獨捨去，爲吏天一涯。", "我又厭奔走，遠引不復來。", "歲月杳難恃，區區老吾儕。", "况從與君別，多事歲若排。", "心力不能究，衰病侵筋骸。", "二子皆已冠，如吾苦無才。", "君亦已有嗣，眉目秀且佳。", "人事知幾變，會合終不諧。", "昨者本不出，豪傑苦見咍。", "鬰鬰自不樂，誰爲予悲哀。", "幡然感其說，東走凌巔崖。", "不意君在此，得奉笑與詼。", "君顔蔚如故，大噱飛塵灰。", "我老應可怪，白髭生兩顋。", "新句辱先贈，古詩許見推。", "賢俊非獨少，故舊每所乖。", "作詩報嘉貺，亦聊以相催。"]'),
('06abc6e7-8b6c-4bea-9149-457199600d7b','擬古  其一','呂南公','宋','宋诗','song-poetry','','[]','仲尼魯司寇，官職亦已優。',60,'全唐诗/poet.song.58000.json','["仲尼魯司寇，官職亦已優。", "從祭肉不及，戴冕奔諸侯。", "當時不之知，爲肉誠可羞。", "君子意有在，衆人但愆尤。", "置之待後世，皎皎無足憂。"]'),
('bdbeb342-ad2d-4b91-8be4-d491472ae224','擬古  其二','呂南公','宋','宋诗','song-poetry','','[]','仲尼爲羣婢，一走四十年。',60,'全唐诗/poet.song.58000.json','["仲尼爲羣婢，一走四十年。", "荀卿老不出，五十猶力田。", "顧彼二夫子，豈其陷狂顛。", "出處固無定，不失稱聖賢。", "彼亦誠自信，誰能卹多言。"]'),
('55a94cfa-a970-462e-9a45-8442f21f3381','擬古  其三','呂南公','宋','宋诗','song-poetry','','[]','公孫昔放逐，牧羊滄海濱。',48,'全唐诗/poet.song.58000.json','["公孫昔放逐，牧羊滄海濱。", "勉强聽鄉里，垂老西遊秦。", "自顧未爲壯，徒爲久辛勤。", "君子豈必隠，孔子皆旅人。"]'),
('b6c6aad0-0227-4133-bafa-2eacc414d9ae','竹榻','呂南公','宋','宋诗','song-poetry','','[]','竹榻破壞久，隅稜類繩橋。',192,'全唐诗/poet.song.58000.json','["竹榻破壞久，隅稜類繩橋。", "扶身輕坐之，不敢直我腰。", "動小響已大，搘嚴勢仍搖。", "鋪氈蔽其顔，倚以度晨宵。", "醉卧稍安貼，如舟乍停橈。", "愁醒輾轉多，似泛八月潮。", "欲下必以緩，將登未嘗跳。", "奴僮爲我憂，疑我或悵怊。", "訝我合改置，我心豈其遥。", "所嗟成與虧，本以材用招。", "念此蒼翠幹，初非願枯焦。", "唯難逃匠手，遂與歲月凋。", "物固不求舊，人貧自無聊。", "憐强棄其衰，此志亦已恌。", "我有四壁宅，塵書映空瓢。", "何嫌此榻存，且以異貴驕。"]'),
('38a1f598-afed-42eb-8010-e92bf1ebbf62','寄陳道先','呂南公','宋','宋诗','song-poetry','','[]','寄聲西山閣，知我新近否。',144,'全唐诗/poet.song.58000.json','["寄聲西山閣，知我新近否。", "病嗽輒彌旬，無錢雇醫叟。", "夫何稍除去，乃自得醇酒。", "美味既沾腸，清甘更悅口。", "適從耕壟上，杯醆不在手。", "坎坎遂連傳，諠如擊盆缶。", "清秋田舍事，秫糯或稀有。", "傾渴聖賢心，囊空欲狂走。", "思君綵衣次，與我異好醜。", "病少官壺多，何因到衰朽。", "古人說天道，高下常更受。", "此語儻可徵，豐荒竟誰久。"]'),
('a670a93e-61df-4009-bf36-6b08b9a029bb','慈濟塔','呂南公','宋','宋诗','song-poetry','','[]','僧說姦雄人，亦發歸依願。',48,'全唐诗/poet.song.58000.json','["僧說姦雄人，亦發歸依願。", "秪今慈濟塔，乃自張崇建。", "雲空土石乾，碑倒龜龍斷。", "悠長香火事，豈以非夫賤。"]'),
('e7082a96-3a3d-44d6-a2a6-3033f38e7f40','一日復一日','呂南公','宋','宋诗','song-poetry','','[]','一日復一日，夜眠復朝興。',96,'全唐诗/poet.song.58000.json','["一日復一日，夜眠復朝興。", "不見事物窮，但覺憂患增。", "千慮不必免，不思亦如恒。", "未知此世間，有用智與能。", "少壯怯鬰屈，衰殘念軒騰。", "方如夏中蟬，忽若秋後蠅。", "非譽等毫絲，善惡計合升。", "可醉且勿道，雲來譬高曾。"]'),
('1637bd39-749a-4464-9843-511ae63f1b76','理髮','呂南公','宋','宋诗','song-poetry','','[]','我髮日以少，我梳未嘗頻。',144,'全唐诗/poet.song.58000.json','["我髮日以少，我梳未嘗頻。", "過旬一理之，每理愁欠伸。", "壯長足癢屑，奔馳更埃塵。", "搔爬不覺勞，垢結類組紃。", "雖復强櫛沐，憚如負千鈞。", "鉤牽就平直，流汗益苦辛。", "當時結似拳，漸細傚梅榛。", "懸知又十載，幾許及變銀。", "萬物有盛衰，吾何爲喜嗔。", "借令但兩鬢，豈害有冠巾。", "人言髮既凋，乃稍異癡民。", "題詩且自賀，漸係老成人。"]'),
('a9dc69f8-7c01-44f8-9ec9-c94534d2bff7','宿熯塘村','呂南公','宋','宋诗','song-poetry','','[]','盡日繞岡嶺，孤征凌險巇。',216,'全唐诗/poet.song.58000.json','["盡日繞岡嶺，孤征凌險巇。", "春風處處豪，游子行安之。", "過午或未飯，人烟信遐稀。", "暮投熯塘村，正見牛羊歸。", "黯黯亂山腹，茅廬壓笆籬。", "陽光向餘霞，畏虎先掩扉。", "繫馬就屋尾，解冠挂門眉。", "怡聲問前程，乞火照寢衣。", "夜半雨忽惡，長雷撼坤維。", "奴僕亦睡覺，雨瀉百箭馳。", "草草卷席避，倚牆願晨雞。", "故園豈無情，一夢不可期。", "我有三畝宅，比鄰勇鉏犁。", "何曾問三旌，自足了四時。", "不肯卧寂寂，亦來走栖栖。", "幸無王事驅，或是奇鬼欺。", "咄咄復咄咄，生平笑狂癡。", "明朝遇清溪，莫洗脚上泥。"]'),
('b419ce8f-852b-4c9f-a8d5-aa3e4c1cfa19','西村','呂南公','宋','宋诗','song-poetry','','[]','東村豈不佳，南村自清幽。',168,'全唐诗/poet.song.58000.json','["東村豈不佳，南村自清幽。", "北村亦可居，俗悍不易投。", "維此兌嶺曲，陂陀遶川流。", "桑麻有青園，耕稼有綠疇。", "雲峰十里外，足舉曠望頭。", "本無車馬喧，豈有聲利愁。", "伊我先君子，故家待增修。", "還當起楹簷，此志敢不求。", "開闢三處徑，疏通四前溝。", "有軒列琴書，有室貯鋤耰。", "壓麴擬長醉，藏芻待肥牛。", "超然了餘生，不問萬戶侯。", "我策久已决，我身强悠悠。", "安能荷篠翁，不以意相收。"]'),
('192b2047-bcfa-4b80-8005-bc42cc3a437a','鏡鑷','呂南公','宋','宋诗','song-poetry','','[]','鏡鑷亦何功，鏗鏗漫從事。',144,'全唐诗/poet.song.58000.json','["鏡鑷亦何功，鏗鏗漫從事。", "助人飾形骸，初若逞意思。", "須毛何足簡，塵垢何足薙。", "端爲兒女懷，豐靚以言貴。", "余家在農畝，耘耔當傳世。", "朝犁泥糊糊，暮耨草翳翳。", "風搔日暴炙，姿狀難娬媚。", "百年寄託身，顛倒皆順利。", "顔紅黑何害，髮黑白亦是。", "誰能妄去取，屑屑論姿致。", "深村擬三逕，歲月治去計。", "带經以隨牛，鏡鑷成相棄。"]'),
('8acb4981-c0b1-4b7b-bc6b-ad0ded05edda','秋色','呂南公','宋','宋诗','song-poetry','','[]','秋色今又動，凄然悟衰殘。',216,'全唐诗/poet.song.58000.json','["秋色今又動，凄然悟衰殘。", "筠床讀書軒，一卧八九歎。", "少壯非所惜，塵勞苦間關。", "端爲智慮傾，得此悄悄顔。", "筋骨衆疾劫，肺肝百憂攢。", "還當節律遷，刺促驚痟酸。", "夜眠却明燭，曉脾拒堅餐。", "從文未終篇，腰脊益痹頑。", "太息造物宰，勞余豈其偏。", "寧分無窮悲，直窘有限年。", "想彼向榮木，蕭森望雲端。", "雖無癭蠹虧，久竟歸朽乾。", "萬化有盡極，一身何足安。", "方當委順之，不必專憒煩。", "起坐仰星斗，環行繞簷欄。", "西風穿我懷，肅若臨矛干。", "世故屬無謂，悠悠諒何言。", "唯應就枕時，曠蕩如山樊。"]'),
('86400ac8-1f22-4409-a684-a15f26564f4c','歲寒亭','呂南公','宋','宋诗','song-poetry','','[]','北風搔長林，萬葉各窮屈。',36,'全唐诗/poet.song.58000.json','["北風搔長林，萬葉各窮屈。", "愛此清秀幹，高寒色如一。", "雖無化石驗，自是後凋質。"]'),
('5d35cb3b-fa19-4793-b9ab-513d790bb9e7','送傅亨父','呂南公','宋','宋诗','song-poetry','','[]','相公坐東府，簡拔無留才。',144,'全唐诗/poet.song.58000.json','["相公坐東府，簡拔無留才。", "賢良得帥權，志與馮趙偕。", "以策屈羣力，勃如飛蚊來。", "河湟多新田，隴渭少驚埃。", "壯矣功利舉，趣時各賢哉。", "誰言夫子喙，不在此日開。", "手把經綸書，想望黄金臺。", "相期衢道亨，紙墨皆雲雷。", "臘雪拍馬睫，朔風穿僕懷。", "雖云行路難，足免壯士哀。", "去去合利見，少微近三台。", "得志亦遄歸，我有賀酒盃。"]'),
('4314eb88-0898-4589-b21f-3dd568a561f2','和得茶雜韵','呂南公','宋','宋诗','song-poetry','','[]','衰翁脾病怯飲茶，不但嗜酒成雄夸。',128,'全唐诗/poet.song.58000.json','["衰翁脾病怯飲茶，不但嗜酒成雄夸。", "夜長晝短讀書苦，佇待雞鳴愁日斜。", "秋蔬搜腸酒正惡，踏爐火慢煎雙脚。", "偶然接得西安角，險欲衝塵送高閣。", "沉吟却憶陳公子，慣在京華看貢篚。", "蒙山顧渚建溪春，花乳清泠徧知味。", "今來下國深秋景，酒厚花稀心未醒。", "盱水中泠亦試烹，豈須奔走揚州井。"]'),
('77e14416-f6f7-4e72-8c41-f8e42a4e87f3','延陵行','呂南公','宋','宋诗','song-poetry','','[]','莫愛傾城名，名高禍將作。',61,'全唐诗/poet.song.58000.json','["莫愛傾城名，名高禍將作。", "莫嫁多才郎，才多情義薄。", "君不見季倫不保綠珠命，長卿終負文君託。", "豈如延陵廡下賃舂人，無色無才貧且樂。"]'),
('b4c3c092-510d-4d6e-80f4-8ba8f55f7394','烏翩翩行','呂南公','宋','宋诗','song-poetry','','[]','烏翩翩，魚漉漉，陂湖漫漫浮窮肉。',99,'全唐诗/poet.song.58000.json','["烏翩翩，魚漉漉，陂湖漫漫浮窮肉。", "貧民疫死屍且壞，冢兒忍看熏牆屋。", "桐棺一寸無錢置，亦可躶埋難乞地。", "繩攣簀載肩負{扌舁}，暮夜間關來此棄。", "哀號數聲淚淋瀝，歸掩柴荆鄰寂寂。", "官家政令如文王，日月不爲盆下光。"]'),
('720d8899-0302-4d48-beed-21ed52ec4e28','黄茅行','呂南公','宋','宋诗','song-poetry','','[]','黄茅颯颯天垂雺，夜宿野亭行旅共。',320,'全唐诗/poet.song.58000.json','["黄茅颯颯天垂雺，夜宿野亭行旅共。", "看看燈火問他鄉，聽說艱虞各悲痛。", "早年轉貨河東北，亦熟淄青涉梁宋。", "民生富裕利源寬，所至如家忘勒鞚。", "晚來凶札作饑饉，首尾七春荒播種。", "已知人物俱流亡，秖有室廬齊歇空。", "迴旋却走嚮淮浙，併值紛紛歎饑凍。", "積屍狼籍臭相兼，無異爛魚藏暑甕。", "去秋關陝穀將稔，踐嚼忽驚黄鼠衆。", "正憂飛輓負洮岷，敢論倉箱稀食用。", "昨聞王師又南伐，熊羆十萬臨諸洞。", "荆潭五嶺皆宿兵，日費千金誰運送。", "閩州旁助早成乏，何况匹夫圖竊弄。", "三川迢遞未得歸，懸想詎能餘賦貢。", "獨稱江國久豐足，游歷如今愁更重。", "旱傷水剝疫癘頻，何處商廛猶佚縱。", "囷京少食但蕭屑，寇盜乘虛還扇動。", "一宵此地漫安身，萬里故園難入夢。", "喓喓雞唱侵枕脚，淡淡曉光穿屋縫。", "去矣東西勿復言，文臣方獻昇平頌。"]'),
('bd6858eb-838d-47d3-809b-65e42dc3382d','遲晚行','呂南公','宋','宋诗','song-poetry','','[]','少年踴躍希卿宰，遲晚徒思老江海。',64,'全唐诗/poet.song.58000.json','["少年踴躍希卿宰，遲晚徒思老江海。", "吾道淹衰髮漸凋，壯圖銷鑠田今買。", "文苑鋒鋩稍收戢，醉鄉朋舊多携解。", "唯有憤世嫉邪心，自計終天不能改。"]'),
('dc46f50b-c4f1-4ef0-9a42-f568264cf164','嗚呼行爲閩寇屢動州郡無兵而作','呂南公','宋','宋诗','song-poetry','','[]','君不見熙寧宰相經綸苦，不肯養兵累神武。',230,'全唐诗/poet.song.58000.json','["君不見熙寧宰相經綸苦，不肯養兵累神武。", "多時州郡罷招軍，欲責耕民爲戰伍。", "詔書一日下九天，守令宣布周鄉田。", "十家嗟吁百家和，父子握手悲殘年。", "干戈不與鋤耰雜，此道幾迴輪歷甲。", "未能井牧似三王，何用匆匆謀混合。", "輿情有幸聞旒扆，斂鼓收旗防怨謗。", "爾來下國稍自安，其奈兵防已頹毀。", "大城有兵不千百，小城更少幾許力。", "一夫竊發數縣驚，坐恐饑癯皆盜賊。", "承平久矣稱繁富，儒生枉被高談誤。", "同聲敷奏盡哀矜，引手施行皆耗蠹。", "居不得寧輯，財安能充裕。", "嗚呼，爭得略如開元姚宋之民人，萬里東南開夜戶。"]'),
('3615e6cb-5e5f-4e7b-b762-f527b4c033b1','別離  其一','呂南公','宋','宋诗','song-poetry','','[]','東家賣兒價何卑，西家棄婦聲更悲。',64,'全唐诗/poet.song.58000.json','["東家賣兒價何卑，西家棄婦聲更悲。", "得錢未足三日飽，既別豈有歸來時。", "山如高城路如線，迴首難言淚盈面。", "螻蟻溝渠處處同，短長不復能相見。"]'),
('f24a3452-89ed-40b5-b81f-791989590164','別離  其二','呂南公','宋','宋诗','song-poetry','','[]','死別離，未如生別苦。',92,'全唐诗/poet.song.58000.json','["死別離，未如生別苦。", "綢繆恩意無窮處，忽作乖違成陌路。", "非緣官誅與私劫，忍令棄置隨童妾。", "夷齊不可人人學，爭得腹空無悚懾。", "生別苦，此苦無盡期，百年泉下亦銜悲。", "娶歸養兒畏不早，何知此日難相保。"]'),
('9ba7c940-248f-40b1-b8ce-8945a136f5f5','貧婦歎','呂南公','宋','宋诗','song-poetry','','[]','昨日良人死窮獨，糧空子幼身自哭。',64,'全唐诗/poet.song.58000.json','["昨日良人死窮獨，糧空子幼身自哭。", "賣衣葬罷急謀嫁，富翁立待封居屋。", "夫妻寒賤恩亦深，縗麻終制非無心。", "饑腸雷鳴無可奈，禮法雖存何足頼。"]'),
('19895c2a-0d93-49f4-8774-116a1c6c259d','教學歎','呂南公','宋','宋诗','song-poetry','','[]','卑卑窮生無令圖，偶開濁眼窺字書。',111,'全唐诗/poet.song.58000.json','["卑卑窮生無令圖，偶開濁眼窺字書。", "村田子弟念筆札，邀請稟訪同師儒。", "遠防鬭訟習詭訐，近就財利評侵漁。", "行身便事世所幸，先王教道徒迂疏。", "君不見官家設庠校，俊士羅冠裾。", "亦工細麗苟榮祿，誰復高遠稽墳謨。", "本期教學敦風俗，今如附子充饑腹。"]'),
('d544a136-f2a7-4127-aca3-0cdc5e58182c','勿願壽','呂南公','宋','宋诗','song-poetry','','[]','勿願壽，壽不利貧袛利富。',79,'全唐诗/poet.song.58000.json','["勿願壽，壽不利貧袛利富。", "君不見生平齷齪南鄰翁，綺紈合雜歌鼓雄。", "子孫奢華百事便，死後祭葬如王公。", "西家老人曉稼穡，白髮空多缺衣食。", "兒孱妻病盆甑乾，靜卧藜床冷無席。"]'),
('60b20ed3-e9ff-40d3-b02f-3cd1be9883d3','壯士膽歌','呂南公','宋','宋诗','song-poetry','','[]','非災非祥何所出，迴天轉地成慌惚。',96,'全唐诗/poet.song.58000.json','["非災非祥何所出，迴天轉地成慌惚。", "蓬萊金曜急食昴，矯矯霜虹橫貫日。", "帝尊萬乘勿致威，大兵如火無所施。", "擒龍扼虎無所尅，手引存亡纔頃刻。", "事無今古用則靈，用時天下毛髮驚。", "能將義勇發至誠，壯士之膽君勿輕。"]'),
('d22be1ad-b73e-4067-870a-2defa0516a3f','恩讎必報歌','呂南公','宋','宋诗','song-poetry','','[]','蘇相東歸施不妄，欒公得位言何壯。',64,'全唐诗/poet.song.58000.json','["蘇相東歸施不妄，欒公得位言何壯。", "恩讎必報真丈夫，不苟而已焉知餘。", "浮生百歲飄風速，胡爲顧慕甘侵辱。", "道之至實先吾身，紛紛毀譽何足聞。"]'),
('8b1e162d-c31b-4f31-8641-b129ed4ce881','西風','呂南公','宋','宋诗','song-poetry','','[]','西風一夜颼颼動，冷觸病身增疾痛。',128,'全唐诗/poet.song.58000.json','["西風一夜颼颼動，冷觸病身增疾痛。", "卧聽促織不成眠，起望明星還內訟。", "十年客路過秋色，五畝故園停歲種。", "學如觀海祗自奇，文似屠龍竟誰用。", "情知至足在飽煖，何事低心隨薦貢。", "桀溺從初豈有官，接輿却是能歌鳳。", "今雖未借邯鄲枕，昔曾屢歎南柯夢。", "哿矣歸哉有近期，會將物我分輕重。"]'),
('f7c54be0-8342-4c4f-980e-fd7b444f5372','渴虎','呂南公','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','九月十月霜漫漫，壙埌南野如羣邊。',224,'全唐诗/poet.song.58000.json','["九月十月霜漫漫，壙埌南野如羣邊。", "東風已作凍未解，日月曉望皆璚田。", "岡陵焦枯澗壑竭，草木性命俱沈綿。", "彪家於時若爲處，掩擁敗葉方閒眠。", "陽輝中天穴戶暖，起坐嘿毣喉方涎。", "虛腸未充多譖士，怒掌久斂悲盜泉。", "黄河泰山深且茂，恨不休止蘄安全。", "熬然宅此取饑渴，焉用武勇聲名傳。", "側聞近便長松塢，十頃池塘停滀古。", "不勝積潤在鱗蟲，浩有餘波沾畎畝。", "尾搖伊昔諱凶檻，腹滿願今同鼴鼠。", "世間遇合無必然，平行靜視皎日前。", "嗟來懇惻尚不就，避逐刺促渠爲賢。", "主人若不開文籞，歸卧幽林待天雨。"]'),
('c70ccf0e-4e71-4dda-b9c9-89fb8bf3d872','乞士歌','呂南公','宋','宋诗','song-poetry','','[]','天下大辱無過乞，忍能餓死不終日。',96,'全唐诗/poet.song.58000.json','["天下大辱無過乞，忍能餓死不終日。", "空瓢曲杖行復嗟，高楹厚壁他人家。", "風蓬蓬，雨臿臿，夜投野廟眠枯葉。", "世上艱難有此時，强顔豈是相師法。", "從來詬駡多言乞，僮客受之猶噎鬰。", "今日同行富者孫，末年禍福誰能必。"]'),
('7af362c1-081b-4db1-ba65-5464d4d5cfd4','關關春樹鶑','呂南公','宋','宋诗','song-poetry','','[]','關關春樹鶑，晨哢不知久。',155,'全唐诗/poet.song.58000.json','["關關春樹鶑，晨哢不知久。", "似欣融和景，樂得飛鳴友。", "可憐天性喜朋類，肯念同羣雜譽咎。", "年年日暖風暄時，園林無處無芳菲。", "高翔俛啄足自適，焉用戚促勤追隨。", "君不見花間柳下紛紜後，擘彈揮丸少年手。", "蒙籠枝上驚急來，不及吚嚶已分首。", "世間利害難預期，尠少德義多姦欺。", "雁奴傷損雉媒飽，儕輩豈不交傾危。", "古人惡熱曾吹虀，莫近王丹墓畔啼。"]'),
('dabef1c3-35cf-441a-bdc9-b73c0bbb7a73','讀文塚銘','呂南公','宋','宋诗','song-poetry','','[]','長沙進士何襟靈，辭源浩瀚如翻傾。',192,'全唐诗/poet.song.58000.json','["長沙進士何襟靈，辭源浩瀚如翻傾。", "十五年間聚文藁，得三千紙封爲塋。", "自憐意氣頗足惜，題作文塚仍鑱銘。", "富哉言章有如此，恨不盡見空傳名。", "吾聞人文乃儒效，用之佐治王化成。", "五帝三王實推濟，孔孟憂世存書經。", "真儒不作世已異，文士所說非所行。", "趨時治己兩不振，奮筆多是圖生榮。", "唐文舊錄二萬卷，于今大半歸漂零。", "昌黎河東幸存顯，自外寸片誰與稱。", "故知辭藻貴遭遇，身後紙札皆勞形。", "當年不用更埋聚，傷嗟此似秦儒坑。"]'),
('c7c00a9b-962d-4ba8-8f8a-7fc99a18d800','石井大雨','呂南公','宋','宋诗','song-poetry','','[]','雲垂四山潑墨濃，風怒發屋茅遮空。',64,'全唐诗/poet.song.58000.json','["雲垂四山潑墨濃，風怒發屋茅遮空。", "征人不安紙蓋下，猛雨迸射郵亭中。", "廄兵色動牽馬出，惟恐摧壓傷儀同。", "吾衣敝薄未免濕，今夜何處還張烘。"]'),
('cc6c22d4-d2e5-44ab-ac15-6bc0cd968284','古人','呂南公','宋','宋诗','song-poetry','','[]','古人已往知無奈，猶被後人興蠹纇。',64,'全唐诗/poet.song.58000.json','["古人已往知無奈，猶被後人興蠹纇。", "前亦人焉後亦人，患自口强心不逮。", "揚雄比孟必有辨，馬卿慕藺良足怪。", "未充志氣徒好名，醇醪豈不因糟胾。"]'),
('06c4b5e9-9070-4a49-bd3b-8d57b69b6786','君益惠竹杖','呂南公','宋','宋诗','song-poetry','','[]','衰來病衆難推盪，日覺筋骸非壯長。',384,'全唐诗/poet.song.58000.json','["衰來病衆難推盪，日覺筋骸非壯長。", "百畝鋤耘致苦辛，萬端應接皆牽强。", "稀曾起處鐘漏盡，多是歸時星月朗。", "滿腹經綸一意閒，墾田頭緒重新講。", "偶逢過客語文字，突兀破壞如夢想。", "太息諸書不救饑，幾曾貨利微能倣。", "故人憐我晚愁瘁，委曲相寬三復兩。", "卒歲嘗分蔽骭衣，方春又贈扶身杖。", "修飂一竹信瑰特，知自何山精産養。", "數節包絣鶴脛連，碎花黝糾彪皮爽。", "提携宛勝冰玉滑，頓卓便同金石響。", "野老生看每問名，耕兒熟見仍私奬。", "未諳黄鉞端許制，久慣青藜饒俗狀。", "靈壽杖堅負曳勞，朱藤飾僞功程枉。", "何如得此清峭幹，本與雪霜爭氣象。", "舊谷遺根未陸沉，末年遇主成真賞。", "已將蠟屐作游伴，更共文簦爲靜黨。", "測渡無憂石澗淹，助跳肯畏泥坑廣。", "時修疆畎便指畫，自牧雞豚誰放蕩。", "差可攓蓬訊髑髏，豈徒闢野披榛莽。", "傾危屢濟功轉積，安穩利征吾濫享。", "輒莫飛飛向葛陂，要當受侮敲原壤。", "古人五十徇鄉禮，我爲困窮聊早上。", "畫戟彤弓且勿思，蒼顔荷篠西村丈。"]'),
('b3b4753b-63c8-4dfc-91e5-4b36a29f6692','代木工言','呂南公','宋','宋诗','song-poetry','','[]','願君勿斲木工手，請斲財戶眼與心。',320,'全唐诗/poet.song.58000.json','["願君勿斲木工手，請斲財戶眼與心。", "時平力贍侈不徹，有見必欲相摹臨。", "試言賤工目所擊，竊竊富室清溪潯。", "偶來公府證訩訟，適見棟宇雄深沉。", "歸損多貲換堂室，唯恐壯麗微差參。", "逡巡子弟到京國，新值器服夸如今。", "買真購法不議價，持還逞詫爭歌吟。", "一家矜尚一鄉慕，自此籍籍師奢淫。", "當時溪西鄙樸老，頗出厲語聊譏侵。", "爲言人生倚衣食，繁手未必加淳音。", "百年榮落豈易保，身後志業須勝任。", "華榱不可孕金穀，盛服幾許忘釜鬵。", "不見聲容赫赫家，晚來衰謝無遺簪。", "乃公營求嗣孫毀，弓劍往往同芒針。", "人情護近不庇遠，厲語一出爭詬擒。", "况我孱微食技業，得不骩靡依餘陰。", "區區小材蓋如此，天下誰與制尺尋。", "安得高梯切閶闔，上叩帝膝敷誠忱。", "盡取人間富財戶，免使僭偪難𣂏斟。", "工手何辜可毋斲，自然風定無驚林。"]'),
('780b356a-fae0-4908-939d-1b29315c57c6','奉和內翰太中臘雪出郊長句','呂南公','宋','宋诗','song-poetry','','[]','冬風雖饕少霜霰，一雪偶嚴飄臘旦。',160,'全唐诗/poet.song.58000.json','["冬風雖饕少霜霰，一雪偶嚴飄臘旦。", "初驚雲物稍悽慘，更覺天威能變換。", "翰林太守方出郊，去指登高作榮觀。", "崩騰逼眼忽無盡，皎潔映懷成極絢。", "從前溫燠自迷舛，到此雱凉誰計算。", "下看平路尚稀微，遠望諸峰先片段。", "虎頭巖側山腰半，羃䍥薄烟占午爨。", "傳聲賓從暫紆餘，命酌聖賢同款緩。", "飛花滿席不須拂，小大入腸寧復亂。", "山陰安道今在否，更欲扁舟破瀰漫。"]'),
('13ff928c-17cc-4d90-a314-50e2676b617c','立春雪凍有懷道先賢良展誦臘除見寄長篇輒反其韵爲詩奉寄','呂南公','宋','宋诗','song-poetry','','[]','先春一雪何易消，南山驟見青岧嶢。',224,'全唐诗/poet.song.58000.json','["先春一雪何易消，南山驟見青岧嶢。", "餘寒忽作雨冰怪，似有陰沴相呼招。", "第堂晨興乍出戶，畏冷須鬢不敢撩。", "還歸書邊擁鑪坐，想像悠遠情慅忉。", "念君幽懷繞嵩少，如鏡對物皎莫逃。", "乘高北望三十六，只見衰朽連平皋。", "心隨歸雁身欲去，又寫佳句傳鳴嗸。", "縑圖遥遥郡閣迥，高詠盡日行周遭。", "無人屬和卷自滿，蚊蚋詎可冠靈鼇。", "自來耕野寄病叟，珠玉偶許麻囊韜。", "空山寂歷時一諷，爽爽不覺驚骨毛。", "當年只是說蘇李，後此豈復論劉曹。", "嗟乎步武已誤高，蹄涔不錄滄海濤。", "東風浩蕩官酎饒，不善酩酊虧二豪。"]'),
('a4b983fa-8c10-4a01-ba82-256abfe1b84b','和道先南城逢相工','呂南公','宋','宋诗','song-poetry','','[]','古人往矣說可傳，顯以悟者其爲賢。',96,'全唐诗/poet.song.58000.json','["古人往矣說可傳，顯以悟者其爲賢。", "周侯樹立囹圄餓，蔡澤飽足四十年。", "知之窮通信已妙，降此抵乞食與錢。", "貪諛末俗滿吻涎，一中百否紛可憐。", "吾徒自斷休問天，書冊讀盡頭蒼然。", "功名分比橐裏弦，且飲美酒飼豚肩。"]'),
('7871712d-08a5-4de5-8c87-4eacde9d9c57','和次道村田歌','呂南公','宋','宋诗','song-poetry','','[]','蠶蛾已撒明年卵，蠶婦乍閒嫌夜短。',160,'全唐诗/poet.song.58000.json','["蠶蛾已撒明年卵，蠶婦乍閒嫌夜短。", "圃柘無端長宿根，潭蘆不住抽新管。", "時哉樂矣犁鋤伴，箬笠團團麻袴軟。", "日出離家日入歸，豈論步武如輪轉。", "强丁屢歎牽車遠，稚子或訶鳴犢緩。", "暴雨晴雨忽蓊然，相驚不覺耕皋晚。", "老翁踞坐抵掌談，奬借專勤譏懶散。", "草衆當爭第一耘，塍高勿厭重新剗。", "中天節近香醅綻，篘面色如人面𧹞。", "里巷齊歌競渡聲，人人錢在雞巢滿。"]'),
('936786c1-c8d0-4e96-aa8c-3245d63bdf75','賣帚翁','呂南公','宋','宋诗','song-poetry','','[]','霜日倒芒梢，{篦刂}筠勞束勒。',55,'全唐诗/poet.song.58000.json','["霜日倒芒梢，{篦刂}筠勞束勒。", "斷送山野村，參陪塵土役。", "價卑徒易售，用貴安可得。", "人間糞穢日以多，翁負帚禿當奈何。"]'),
('5269cc1f-3453-4230-8a42-b14a01ed2f50','老樵','呂南公','宋','宋诗','song-poetry','','[]','何山老翁鬢垂雪，擔負樵蘇清曉發。',112,'全唐诗/poet.song.58000.json','["何山老翁鬢垂雪，擔負樵蘇清曉發。", "城門在望來路長，樵重身羸如跛鼈。", "皮枯亦復汗淋瀝，步强遥聞氣嗚咽。", "同行壯俊常後追，體倦心煩未容歇。", "街東少年殊傲岸，和袖高扉厲聲喚。", "低眉索價退聽言，移刻纔蒙酬與半。", "納樵收直不敢緩，病婦倚門待朝爨。"]'),
('acbd20ef-852d-46e9-9c26-56899e1ca2e9','山中即事寄上知縣宣德','呂南公','宋','宋诗','song-poetry','','[]','一錢重丘山，斗粟輕糞土。',276,'全唐诗/poet.song.58000.json','["一錢重丘山，斗粟輕糞土。", "昔聞豐年樂，今識豐年苦。", "東家米粒白如銀，西家稻束大於鼓。", "再三入市又負歸，慇懃減價無售主。", "刀機縱在屠伯瘦，盃勺長閒壚婦去。", "了無蹊徑近甘肥，只有呻吟厭寒暑。", "相傳城邑尚牢落，村野蕭然安足數。", "鄙夫自分爲儒生，坎壈薄佑來蠶耕。", "言章自昔枉用力，債簿幾許能除名。", "連旬暴露顔面黑，彌月菜茹腸肚青。", "原田常恐不遇歲，及此遇矣當何成。", "昨日鄰翁諮種播，相與竹下團團坐。", "共嗟衰暮值艱難，未覺豐登勝饑餓。", "望天窅邈叵致詰，得令賢明聊爾賀。", "不馳幹隸擾租輸，更秉公心憫鹽課。", "何鄉巨惡不手斂，有處宿姦皆膽破。", "且勿恤失得，且毋論福禍。", "但願令尹住三年，錢重物輕猶可過。"]'),
('a38031db-9bf0-4ac4-9b63-9813c38db76b','麻姑道中','呂南公','宋','宋诗','song-poetry','','[]','山翁種樹不差擇，桃李無窮雜松柏。',64,'全唐诗/poet.song.58000.json','["山翁種樹不差擇，桃李無窮雜松柏。", "風吹陽和入芳根，萬白千紅映蒼碧。", "猴藏鳥啄人恣窺，桃李實熟無完枝。", "由來未可論堅脆，松柏材成斧斤至。"]'),
('18334e7f-4530-43d9-a3e5-c721ef5a84ae','道先賢良寄示長篇輒此酬和略希一笑','呂南公','宋','宋诗','song-poetry','','[]','閉門却埽未足高，遇酒輒醉豈其豪。',224,'全唐诗/poet.song.58000.json','["閉門却埽未足高，遇酒輒醉豈其豪。", "窮山終歲擁書坐，澗谷曷日興雲濤。", "浮沉非工俗子惡，只與筆硯爲朋曹。", "流年侵尋路婉娩，鏡裏已復驚蒼毛。", "作爲文章世不用，似對婦女論鈐韜。", "欲陳肝膽自薦進，恐類衆蟻觀連鼇。", "嘗聞聲氣有求應，此日寂寞誰相遭。", "當歌無和亦已矣，豈意或有憐悲嗸。", "陳侯嵩丘降靈士，傳世事業師夔皋。", "有官未得斷國論，昭代尚把浮名逃。", "陔蘭芳香月桂老，靜卧感古成憂忉。", "題詩遠寄巧及我，稍比陳敵輕兵撩。", "龐涓疏軟孫臏銳，勝負不待明占招。", "惟當釋耒往共飲，不必皎潔分桀堯。"]'),
('f6db64d5-197c-4635-a957-c2ef3a507faa','夜聞','呂南公','宋','宋诗','song-poetry','','[]','夜聞黥徒歎行苦，傳檄馳符渺無數。',64,'全唐诗/poet.song.58000.json','["夜聞黥徒歎行苦，傳檄馳符渺無數。", "霜晨雨夕常疾驅，鬼魅豺虎何山無。", "寢興順時豈不欲，簡書可畏鞭刑毒。", "儒譏冗食知謂誰，我非浪費官家粟。"]'),
('1845271f-38ad-4b37-ace0-027db18e0e56','內翰太中以某伏謁郡齋特賜長句謹和拜酬','呂南公','宋','宋诗','song-poetry','','[]','寒人氣象寒於冰，聞有嘉運無由乘。',208,'全唐诗/poet.song.58000.json','["寒人氣象寒於冰，聞有嘉運無由乘。", "陽和吹噓品彙生，燕谷凍瘁漠未驚。", "年華四十盱畔城，慣處涸竭忘流盈。", "六張五角長合并，百慮一得嗟何曾。", "鳴悲自昔起不平，苦調往往抽毫成。", "窮衰到處難得朋，坐使見笑蒼蠅聲。", "心知俗譽不足榮，分死枯槁羞逢迎。", "由來極晦亦小明，不在壹鬰居蠻荆。", "翰林先生天下名，風裁如鑑初無情。", "偶然誤許筳與楹，重言既出衆懦興。", "譬彼卧蟄因雷醒，恩文撫接曲盡誠。", "更剡薦牘辨玖瓊，匹夫有獲萬口稱。", "此世不復投清泠，正恐疏闊如樊英。"]'),
('4ba44505-7728-4127-b700-cba6b5908764','送何齋郎赴選','呂南公','宋','宋诗','song-poetry','','[]','書堂四顧皆蒼山，禽魚樹石烟雲間。',164,'全唐诗/poet.song.58000.json','["書堂四顧皆蒼山，禽魚樹石烟雲間。", "紙編屢絕筆屢{髟/聞}，十載一瞬忘青綸。", "誰令忽憶南薰關，盡箠打馬鳴鑣鐶。", "春風桃李紛妖嫺，辭家大笑涕不潸。", "由來磊落羞窮跧，下位亦足惠寡鰥。", "乘田委吏不敢閒，以日自愛維孔顔。", "當今俊傑登朝班，拔擢杞梓披榛菅。", "君能忼慨露豹斑，豈比嘿嘿貪食孱。", "果哉往矣步勿䟂，仕以行義賢可攀。", "僕姑百中初滿彎，書堂靜坐尻狂癲。"]'),
('8f36cdaf-218f-4ed3-9a16-9c7253b4868a','過界山館','呂南公','宋','宋诗','song-poetry','','[]','界山館下平街路，行客無窮朝接暮。',288,'全唐诗/poet.song.58000.json','["界山館下平街路，行客無窮朝接暮。", "十年二十四迴過，每覺人烟不如故。", "初尋此地謁高士，廛里讙愉忘迫遽。", "固嫌餓子辱閭閻，乃有善人尸管庫。", "歌聲酒氣等閒滿，魚尾彘肩容易具。", "半無賓客味羣書，盈耳只聞論富庶。", "一來奔走繞淮汴，高士亦趨城市去。", "南蹄北轍不可留，雖有暫經難久住。", "前冬適自故園出，忽見瘡痍變其處。", "豈能糠粃保黄台，乃忍溝渠疊童孺。", "官條既改驛亭破，儒者不存書屋蠹。", "蕭然巷陌但荒埃，聽說流亡不知數。", "昨朝又自劍池返，遭值故人車馬駐。", "相看問訊十年間，涕淚沾襟如水注。", "當時飽腹今半殍，近歲朱顔多已腐。", "一盃雖舉屢噫鳴，永夜不眠猶恟懼。", "哀哉天運不易識，安得各齊金石固。", "凌晨復過高士門，迴首荆榛带霜露。"]'),
('40c62cab-222b-44df-bdc0-04f9ad45e70c','信眼','呂南公','宋','宋诗','song-poetry','','[]','信眼成吟步，虛廊遶幾回。',48,'全唐诗/poet.song.58000.json','["信眼成吟步，虛廊遶幾回。", "見雲侵月去，聞雨趁風來。", "羣動悄已息，煩襟相次開。", "慇懃謝凉氣，少爲挫蚊雷。"]'),
('7d85e12b-4bf8-40ec-a900-00ad1fcd9c30','急雨','呂南公','宋','宋诗','song-poetry','','[]','急雨拋砂響，驚風伐鼓過。',48,'全唐诗/poet.song.58000.json','["急雨拋砂響，驚風伐鼓過。", "漏從孤館永，愁入病身多。", "輾轉思鄉井，依稀夢薜蘿。", "得他莊叟罪，憂焰日焚和。"]'),
('e33c74e5-c730-4f1d-bf18-af42649a751a','平雲閣','呂南公','宋','宋诗','song-poetry','','[]','高閣與雲平，超如近玉京。',48,'全唐诗/poet.song.58000.json','["高閣與雲平，超如近玉京。", "未須論峻絕，聊用壓崢嶸。", "看雨諸村白，乘風百里清。", "途人豈知此，拍額望丹楹。"]'),
('c5e24260-5b34-44b1-8b54-359dfde3897a','寄微之','呂南公','宋','宋诗','song-poetry','','[]','末俗矜鄉舉，先生尚滯淹。',48,'全唐诗/poet.song.58000.json','["末俗矜鄉舉，先生尚滯淹。", "門人能頌述，羣小或憎嫌。", "舊學時方用，新書日以添。", "陰霾雖拍拍，會解見圓蟾。"]'),
('2dad4347-09d5-4283-8c96-e7eca9d60924','和酬道先雪中見寄','呂南公','宋','宋诗','song-poetry','','[]','空館雪霏霏，孤懷不可爲。',48,'全唐诗/poet.song.58000.json','["空館雪霏霏，孤懷不可爲。", "綈袍正藍縷，布褐强參隨。", "想望壚間酒，支持席上詩。", "念君將遠適，宛轉萬重思。"]'),
('16e875d5-dd17-4720-b332-d059914242bc','歲宴  其一','呂南公','宋','宋诗','song-poetry','','[]','歲宴仍遷徙，蕭然背客堂。',48,'全唐诗/poet.song.58000.json','["歲宴仍遷徙，蕭然背客堂。", "聽雞吹宿火，騎馬踏晨霜。", "世味寧皆惡，吾生有底忙。", "奴僮亦相笑，歸計只他鄉。"]'),
('c697f9e5-d995-4915-84b3-5ec34047a452','歲宴  其二','呂南公','宋','宋诗','song-poetry','','[]','歲宴知何事，低徊戀醉鄉。',48,'全唐诗/poet.song.58000.json','["歲宴知何事，低徊戀醉鄉。", "衰殘三十老，岑寂五更長。", "識字初無益，醫愁未有方。", "一盃寅卯舉，天下又兼忘。"]'),
('42e4faa4-9583-43ad-a1c1-86a32aee0e1b','小港書事三首  其一','呂南公','宋','宋诗','song-poetry','','[]','破屋照山坰，山民問筆耕。',48,'全唐诗/poet.song.58000.json','["破屋照山坰，山民問筆耕。", "日無賓接戲，夜厭鼠橫行。", "被服烟埃色，呻吟老病身。", "不知齊魯士，甘此欲何成。"]'),
('439093eb-a397-4529-a967-eee45911df1d','小港書事三首  其二','呂南公','宋','宋诗','song-poetry','','[]','溝澗橫三面，岡巒匝四隅。',48,'全唐诗/poet.song.58000.json','["溝澗橫三面，岡巒匝四隅。", "滿門牛宿留，刺耳鳥喧呼。", "造請難通謁，經過易失途。", "鋤犁有餘暇，歌鼓宴官奴。"]'),
('106629bd-9d54-4a0d-aa89-2f7c0f258f9c','小港書事三首  其三','呂南公','宋','宋诗','song-poetry','','[]','夢想驚冠蓋，糟糠繼祖孫。',48,'全唐诗/poet.song.58000.json','["夢想驚冠蓋，糟糠繼祖孫。", "多財新得友，善訟舊成婚。", "策士吞并說，門風楚撻痕。", "飲酣尤壯浪，潜聽亦消魂。"]'),
('55529f5b-97d3-4d10-850b-a8977a082be4','向火','呂南公','宋','宋诗','song-poetry','','[]','八月淮南地，輕寒已中人。',48,'全唐诗/poet.song.58000.json','["八月淮南地，輕寒已中人。", "病夫嫌冷褐，敲火乞烏薪。", "體暢寧須酒，神和不讓春。", "養生聊自適，何必問時辰。"]'),
('3820aec3-6990-4d16-a938-2f0364091b58','送及之丞公','呂南公','宋','宋诗','song-poetry','','[]','先朝賢御史，風彩九州欽。',48,'全唐诗/poet.song.58000.json','["先朝賢御史，風彩九州欽。", "嗣子傳家法，孤芳映士林。", "忠良常在我，便佞不關心。", "得慶宜蒙福，時清豈陸沉。"]'),
('1225c4aa-bb61-46d6-9727-6f6af2b74e29','金秀才歸','呂南公','宋','宋诗','song-poetry','','[]','書來動鄉思，歸興偶幡然。',48,'全唐诗/poet.song.58000.json','["書來動鄉思，歸興偶幡然。", "故國輕一別，綵衣閒八年。", "星霜親鬢上，文字客燈前。", "此意終難詰，西風滿耳蟬。"]'),
('c2889c08-c342-45cf-91d9-39e58d126e81','日日','呂南公','宋','宋诗','song-poetry','','[]','日日聽鐃鼓，坊衢送死頻。',48,'全唐诗/poet.song.58000.json','["日日聽鐃鼓，坊衢送死頻。", "豈能悲此事，爭願作歸人。", "邑屋兒孫衆，山墳草樹新。", "去來應迭代，渠獨淚沾巾。"]'),
('784d9162-c6e5-41da-9887-3b96d0541aa1','淵老','呂南公','宋','宋诗','song-poetry','','[]','淵老真高簡，能逃世外禪。',48,'全唐诗/poet.song.58000.json','["淵老真高簡，能逃世外禪。", "青山如故友，白髮任流年。", "邛竹五六節，梵文三四編。", "無人知此味，冷坐小窗前。"]'),
('a5b07b46-4219-45c5-8c14-d3172f08923b','鄰老  其一','呂南公','宋','宋诗','song-poetry','','[]','鄰老今亡矣，誰猶辨短長。',48,'全唐诗/poet.song.58000.json','["鄰老今亡矣，誰猶辨短長。", "隙駒沈迅影，石火掩孤光。", "錯寞悲新事，淒迷想舊狂。", "朔風原上草，歸夢見松霜。"]'),
('fd1b49e2-1afd-4337-b0ca-39c60afe39e6','鄰老  其二','呂南公','宋','宋诗','song-poetry','','[]','氣槩平生事，耝耰滯故林。',48,'全唐诗/poet.song.58000.json','["氣槩平生事，耝耰滯故林。", "得無尊道性，長有貴儒心。", "躁暴村田酒，粗疏欵乃吟。", "暮年乖此約，誰使永差參。"]'),
('9c1e4703-622a-4019-a922-c3aca9d770c2','送人遊邊二首  其一','呂南公','宋','宋诗','song-poetry','','[]','六月洮河上，驚飈雹似拳。',48,'全唐诗/poet.song.58000.json','["六月洮河上，驚飈雹似拳。", "遊人方仗策，元帥已開邊。", "京觀酋豪肉，軍儲府藏錢。", "參謀如有取，常武在周篇。"]'),
('02def341-ebff-450e-a20f-2b73f754349f','送人遊邊二首  其二','呂南公','宋','宋诗','song-poetry','','[]','我愛王忠嗣，兵威萬里橫。',48,'全唐诗/poet.song.58000.json','["我愛王忠嗣，兵威萬里橫。", "只知精士馬，不忍幸功名。", "四印無矜色，三邊有肅聲。", "未知誰願此，徒用送君行。"]'),
('4d806e64-1782-49fd-b85b-f27b8861bf5e','病起  其一','呂南公','宋','宋诗','song-poetry','','[]','病起興蕭蕭，餘魂次第招。',48,'全唐诗/poet.song.58000.json','["病起興蕭蕭，餘魂次第招。", "悽酸攻意氣，衰朽入風標。", "納带驚腰緩，移梳恨髮凋。", "何心希此世，只合順無聊。"]'),
('5a044f7d-f6b9-4ac5-a8d8-b2bf233920f3','病起  其二','呂南公','宋','宋诗','song-poetry','','[]','病起南榮下，初寒仰日溫。',48,'全唐诗/poet.song.58000.json','["病起南榮下，初寒仰日溫。", "坐頑知力困，視慢覺神昏。", "避俗無長策，沉思到故園。", "人生乃如此，微處共誰言。"]'),
('be5db48a-ddf6-4203-9d96-9cd03203e379','衰病','呂南公','宋','宋诗','song-poetry','','[]','衰病相侵卑，勞生得意遲。',48,'全唐诗/poet.song.58000.json','["衰病相侵卑，勞生得意遲。", "兩腓初瘦後，左耳半聾時。", "已取世上苦，强將天下知。", "只宜收散質，偷惰學支離。"]'),
('292f8253-c37f-4fc8-bda6-bf0509eedc43','贈白','呂南公','宋','宋诗','song-poetry','','[]','成童即學佛，五十始披緇。',48,'全唐诗/poet.song.58000.json','["成童即學佛，五十始披緇。", "去髮有先後，悟空無速遲。", "游雲經過雨，淙瀑到清漪。", "此意分明否，人間不可思。"]'),
('e0d1f796-ef0c-4ed1-94f3-0790c4221662','留題羅漢院愚軒','呂南公','宋','宋诗','song-poetry','','[]','紛紛僞飾日，愚者乃賢歟。',48,'全唐诗/poet.song.58000.json','["紛紛僞飾日，愚者乃賢歟。", "好醜知誰論，文章亦漫書。", "蟻來方棄智，匠去莫尋樗。", "秪有閒風月，經過未忍疏。"]'),
('95a9fefe-3f09-4f86-9ba1-f2e791c5b508','奉和內翰太中殘春口占二首  其一','呂南公','宋','宋诗','song-poetry','','[]','久次蕭條郡，高情奈樂何。',48,'全唐诗/poet.song.58000.json','["久次蕭條郡，高情奈樂何。", "鶑花三月促，風雨一春多。", "野寺携筇到，幽溪飲禊過。", "四郊田水暖，駐節問新禾。"]'),
('23654130-d0d9-4d02-8439-3ecb400fe4b7','奉和內翰太中殘春口占二首  其二','呂南公','宋','宋诗','song-poetry','','[]','綠陰槐柳院，白日靜寥寥。',48,'全唐诗/poet.song.58000.json','["綠陰槐柳院，白日靜寥寥。", "有句方高詠，無賓可屢邀。", "獨眠聞漏轉，縱步看絲飄。", "結束東州計，詩編問酒瓢。"]'),
('b63f21ec-4381-4a21-a947-d74203aac34d','曉作','呂南公','宋','宋诗','song-poetry','','[]','雨惡天光淡，風高晚氣清。',48,'全唐诗/poet.song.58000.json','["雨惡天光淡，風高晚氣清。", "四簷喧急溜，一枕厭寒聲。", "世慮漫沉想，此心還不平。", "搔撈下書榻，坐對紙窗明。"]'),
('69dc376f-8875-4e8f-b83f-1227a0fd040c','同俊和賦禪悅長老此君軒','呂南公','宋','宋诗','song-poetry','','[]','祇園無俗物，軒爲此君開。',48,'全唐诗/poet.song.58000.json','["祇園無俗物，軒爲此君開。", "但未爲龍去，何妨引鳳來。", "法中常住境，天下後凋材。", "豈復如遷客，慇懃到處栽。"]'),
('6e2c7c93-ff50-437a-b401-1161e0513a90','筍蕨','呂南公','宋','宋诗','song-poetry','','[]','筍蕨吾山味，風埃旅館心。',48,'全唐诗/poet.song.58000.json','["筍蕨吾山味，風埃旅館心。", "盃盤感時節，魂夢解參尋。", "爛漫銷青紫，橫斜破玉金。", "平生疏淡意，飽足望家林。"]'),
('bf255a1d-55ea-4f24-bf02-74096abb09e9','贈亨父次溫伯韵','呂南公','宋','宋诗','song-poetry','','[]','老未上青雲，誰論德行純。',48,'全唐诗/poet.song.58000.json','["老未上青雲，誰論德行純。", "有名傳郡國，無食給冬春。", "慣見官徵債，多應鬼笑貧。", "豈能逃俗口，坐作解嘲人。"]'),
('af35eeb9-aff5-4ae7-99e8-56f91f167fda','卧疾','呂南公','宋','宋诗','song-poetry','','[]','卧疾動淹旬，搔爬滿爪塵。',48,'全唐诗/poet.song.58000.json','["卧疾動淹旬，搔爬滿爪塵。", "已能忘飯食，聊復畏冠巾。", "風雨驚新歲，鶑花待早春。", "便無游覽分，樽酒幸相親。"]'),
('8a88ba95-43f0-4ce8-b9f3-25cb19f8bfb3','足疾','呂南公','宋','宋诗','song-poetry','','[]','足疾在中年，蕭衰只自憐。',48,'全唐诗/poet.song.58000.json','["足疾在中年，蕭衰只自憐。", "徐行如敬長，頑坐似逃禪。", "欲適求新履，相忘任故韉。", "思山徒有興，登頓豈能前。"]'),
('d5ddd226-448f-44b0-adb4-8daba1887081','亨父錄示山齋即事五篇索和遂次其韵  其一','呂南公','宋','宋诗','song-poetry','','[]','齋閣得山棲，蕭然萬慮遺。',48,'全唐诗/poet.song.58000.json','["齋閣得山棲，蕭然萬慮遺。", "此心終異俗，吾道更同誰。", "好意憑琴寫，衰顔取鏡窺。", "窮通殊未定，幽獨欲何之。"]'),
('e9a31b34-42c0-4f1c-a1a6-7a47de01787f','亨父錄示山齋即事五篇索和遂次其韵  其二','呂南公','宋','宋诗','song-poetry','','[]','有紅盃面酒，無白鬢間毛。',48,'全唐诗/poet.song.58000.json','["有紅盃面酒，無白鬢間毛。", "合世心雖淡，論文氣轉豪。", "迂疏憐野叟，蕭散敵兒曹。", "免被南華笑，憂時兩目蒿。"]'),
('2bd923c4-9109-4455-8dd1-2eecca6d8fa5','亨父錄示山齋即事五篇索和遂次其韵  其三','呂南公','宋','宋诗','song-poetry','','[]','榮利機關拙，雲泉興味多。',48,'全唐诗/poet.song.58000.json','["榮利機關拙，雲泉興味多。", "豈同愚士窘，自合聖人和。", "斂斂青氈舊，酣酣白石歌。", "故應消息有，貧獨奈余何。"]'),
('91f24150-c8fd-40c0-8ee7-4f46bf57ae7d','亨父錄示山齋即事五篇索和遂次其韵  其四','呂南公','宋','宋诗','song-poetry','','[]','嘯傲村田景，巾裾得所從。',48,'全唐诗/poet.song.58000.json','["嘯傲村田景，巾裾得所從。", "壯圖因酒動，睡思向書濃。", "坐見雲歸岫，吟聞雨濺篷。", "但無詩準備，何以謝情悰。"]'),
('2d3cde00-ba99-4b88-9425-405dcababb26','亨父錄示山齋即事五篇索和遂次其韵  其五','呂南公','宋','宋诗','song-poetry','','[]','榻爲庸兒挂，軒因好月開。',48,'全唐诗/poet.song.58000.json','["榻爲庸兒挂，軒因好月開。", "清風知曉暮，往事付塵埃。", "喜燕長褰幕，嫌蛙屢洒灰。", "山中樂如此，腸莫等閒迴。"]'),
('234deac5-d8e8-40de-8992-340dcf878a39','呈知府內翰即次原韵  其一','呂南公','宋','宋诗','song-poetry','','[]','山人何事忽伸眉，新得陳王七步詩。',64,'全唐诗/poet.song.58000.json','["山人何事忽伸眉，新得陳王七步詩。", "題是船齋高詠後，開當寒谷带經時。", "仁風坐使羣心動，健筆潜將暖律移。", "硯席久荒青案乏，報酬非稱更慚遲。"]'),
('3709d946-f4c7-41a1-9fd6-7a67c24be61e','呈知府內翰即次原韵  其二','呂南公','宋','宋诗','song-poetry','','[]','憂來無處寄深思，也擬春秋也作詩。',64,'全唐诗/poet.song.58000.json','["憂來無處寄深思，也擬春秋也作詩。", "空役肺腸添故紙，有何勳烈補明時。", "身唯蓬蓽行將老，志似嵩丘永不移。", "誰使翰林東道主，肯敷餘論憫衰遲。"]'),
('29f56925-8da2-4783-a01a-2243ed57e76c','重遊松溪偶題八句示升卿','呂南公','宋','宋诗','song-poetry','','[]','七年前已到松溪，不慮重經有此時。',64,'全唐诗/poet.song.58000.json','["七年前已到松溪，不慮重經有此時。", "寒苦慣爲窮進士，清高長羨病禪師。", "雲山契分輸今日，香火因緣歎夙期。", "庭栢森森秋實在，向來塵想誤多疑。"]'),
('20b96926-6a6e-423a-821a-00b5b4ff83c1','夢寐','呂南公','宋','宋诗','song-poetry','','[]','偶入重城坐客堂，年年風味只荒凉。',64,'全唐诗/poet.song.58000.json','["偶入重城坐客堂，年年風味只荒凉。", "春花秋月各無味，晚鼓曉鐘俱斷腸。", "別恨不堪詩控引，高情猶頼酒分張。", "著書耕釣平生事，夢寐西村五畝桑。"]'),
('3ad8b036-38ed-464c-b7bb-6558da6d1186','送傅濟道之漳浦尉','呂南公','宋','宋诗','song-poetry','','[]','河梁東度送征鞭，屈指閩荒路二千。',64,'全唐诗/poet.song.58000.json','["河梁東度送征鞭，屈指閩荒路二千。", "難向解携無一語，再思重見尚三年。", "高堂上壽今誰及，白屋青衫合自憐。", "努力官箴莫輕墮，清時無善不登延。"]'),
('15ff9894-a523-4838-a868-70db43425391','送劉賢甫之餘干尉','呂南公','宋','宋诗','song-poetry','','[]','太學諸生初入官，綠衣新尉古餘干。',64,'全唐诗/poet.song.58000.json','["太學諸生初入官，綠衣新尉古餘干。", "科場得志已容易，下邑徒勞不足難。", "萑澤察姦行繚繞，缿廳參論坐盤桓。", "羽儀更養文章去，他日雲天見孔鸞。"]'),
('0ae3dc1a-d626-48a4-af73-0ba7e62bcd6c','出蔡州','呂南公','宋','宋诗','song-poetry','','[]','奉天橋下水湯湯，橋上征人破曉光。',64,'全唐诗/poet.song.58000.json','["奉天橋下水湯湯，橋上征人破曉光。", "秋色稍能禁暑氣，客愁終欲害離腸。", "遭逢未入千年會，窮苦猶爲此日忙。", "笑殺壺公祠畔路，又隨塵土過仙鄉。"]'),
('110416f5-04d2-4549-8643-4d79fb871d8e','奉酬純父浚都病起見寄','呂南公','宋','宋诗','song-poetry','','[]','建康學士註魚蟲，枹罕兵官策守攻。',64,'全唐诗/poet.song.58000.json','["建康學士註魚蟲，枹罕兵官策守攻。", "此日精勤徒有得，異時榮盛各成空。", "吾能委曲謀田上，君乃呻吟厭旅中。", "故國他鄉俱未快，勞生何事不齊同。"]'),
('8a16a7a2-e458-4683-b4b9-fc8d13be2b8b','奉別道先','呂南公','宋','宋诗','song-poetry','','[]','邂逅過從兩載强，詩書存問滿藜床。',64,'全唐诗/poet.song.58000.json','["邂逅過從兩載强，詩書存問滿藜床。", "光榮得路誰非友，道義心知獨不忘。", "聖代君才多勉勉，中年吾髮已蒼蒼。", "牙弦自此聊停緩，萬里窮山隔帝鄉。"]'),
('413a7281-1523-4d43-a340-42c91ec3be46','桐城與曾唐傑話別','呂南公','宋','宋诗','song-poetry','','[]','事物無窮世路長，人生聚散亦堪傷。',64,'全唐诗/poet.song.58000.json','["事物無窮世路長，人生聚散亦堪傷。", "寒暄旦暮年年急，塵土風波處處忙。", "我馬欲衝梁苑雪，君帆先犯楚天霜。", "交情若是存悠久，定有音書入帝鄉。"]'),
('bba4e1b5-e8d1-46f5-8753-f7f93729bd3c','宿青綏鋪','呂南公','宋','宋诗','song-poetry','','[]','兩檻中間風脚橫，解衣鋪簟近南榮。',64,'全唐诗/poet.song.58000.json','["兩檻中間風脚橫，解衣鋪簟近南榮。", "曦光欲墮已睡熟，斗柄轉斜纔夢驚。", "方恨此時無月色，未知何處有蚊聲。", "塵埃惡熱明朝路，會爲今宵動旅情。"]'),
('a1df9d40-6a37-4ba0-8c47-5346cb347798','過洪州','呂南公','宋','宋诗','song-poetry','','[]','未定榮華與退休，三年四度過洪州。',64,'全唐诗/poet.song.58000.json','["未定榮華與退休，三年四度過洪州。", "紅塵白日知何得，西去東歸不自由。", "一带好山誰舊隠，百端閒事我新憂。", "可能石馬亭邊路，見客區區到白頭。"]'),
('ba853cc3-8477-42ca-80c1-87e5e3762360','道先游仙都至李尊師故居見余早歲題贈拙句存於屋壁輒寄四韵重相歎賞謹有賡酬','呂南公','宋','宋诗','song-poetry','','[]','仙李枝條萬國分，隴西舊望道家孫。',64,'全唐诗/poet.song.58000.json','["仙李枝條萬國分，隴西舊望道家孫。", "曾經二十載還往，忽過七千餘曉昏。", "人落九泉無可奈，詩存古壁更休論。", "困窮辭氣君偏愛，太息南征返北轅。"]'),
('6cdf4fc2-8b9c-452a-b073-6ba904e408a6','十月二十日過陳二表民追講昔年同學事迹慨然贈之以詩','呂南公','宋','宋诗','song-poetry','','[]','西齋共學昔辛勤，一別侵尋十四春。',64,'全唐诗/poet.song.58000.json','["西齋共學昔辛勤，一別侵尋十四春。", "此日科場還似夢，舊時書屋已成塵。", "文章不鬭錢財福，貧病長依寂寞濱。", "相值酒邊當取醉，大家忘却困窮身。"]'),
('2541122e-76e4-4921-bfc8-7c049ccfcdd7','百年','呂南公','宋','宋诗','song-poetry','','[]','百年長短有愁兼，世味如今豈足沾。',64,'全唐诗/poet.song.58000.json','["百年長短有愁兼，世味如今豈足沾。", "客路無聊貧苒苒，春風相值病厭厭。", "辭章漫與前賢並，氣調終遭俗士嫌。", "安得一廛閒散去，耕桑吟醉似陶潜。"]'),
('a3a3658c-0d2c-442e-9ecd-1821d35d9a26','曉陪內翰步至北園','呂南公','宋','宋诗','song-poetry','','[]','曉風吹雨北園開，追逐雙旌踏翠苔。',64,'全唐诗/poet.song.58000.json','["曉風吹雨北園開，追逐雙旌踏翠苔。", "芍藥一欄霞上錦，嫩荷千片玉流盃。", "多年架閣游春興，此日關防感物才。", "花不能言草成恨，故應知我偶然來。"]'),
('59db862a-5932-48b6-abf9-f59d1683b22c','次韵顯翁幽居即事','呂南公','宋','宋诗','song-poetry','','[]','文高只合論錢神，屈膝須防望貴塵。',64,'全唐诗/poet.song.58000.json','["文高只合論錢神，屈膝須防望貴塵。", "軒冕未來應有命，丘園隨分亦安身。", "山樵水釣心常逸，夜坐朝耕樂更均。", "嗟我久懷農圃計，何時操耒即相親。"]'),
('03f5be9e-6769-40f9-84ad-90ec16057094','送唐傑重過金陵','呂南公','宋','宋诗','song-poetry','','[]','金陵春水解歸舟，重到金陵恰仲秋。',64,'全唐诗/poet.song.58000.json','["金陵春水解歸舟，重到金陵恰仲秋。", "世路已銜奔走恨，風光更引別離愁。", "支持事變何由辦，歎息安閒不易求。", "衹有北山長好在，爲余頻上冶城頭。"]'),
('59d1ea5c-9f2f-4b07-9070-135e1eca8c19','寄贈張縣丞','呂南公','宋','宋诗','song-poetry','','[]','二年來往南豐路，飽聽鄉民說縣丞。',64,'全唐诗/poet.song.58000.json','["二年來往南豐路，飽聽鄉民說縣丞。", "剛果已如秋漢鶚，潔清仍似玉壺水。", "室無姦吏縱橫入，門有書生旦暮登。", "何事廉車帷幕厚，不將高位待賢能。"]'),
('5479997f-eb34-49a5-b1ae-d15630e2f354','熙寧五年歸至舊山傷己感時作詩奉呈升卿黄丈  其一','呂南公','宋','宋诗','song-poetry','','[]','幾年奔走背農桑，半世歸來只感傷。',64,'全唐诗/poet.song.58000.json','["幾年奔走背農桑，半世歸來只感傷。", "蛇足畫成曾失酒，古書看遍却亡羊。", "一廛席屨何從受，三徑園廬已就荒。", "猶頼比鄰賢父老，許同飛鸒賊餘糧。"]'),
('9c7c89cb-0bd5-4f92-b359-37a5f823ce5f','熙寧五年歸至舊山傷己感時作詩奉呈升卿黄丈  其二','呂南公','宋','宋诗','song-poetry','','[]','彬樹湖前流水遠，石城街左亂山蒼。',64,'全唐诗/poet.song.58000.json','["彬樹湖前流水遠，石城街左亂山蒼。", "灘深潭淺無由問，竹秀松枯不可常。", "物理自應隨變動，道心聊欲寄存亡。", "唯君坐占忘言境，珍重詩編與酒觴。"]'),
('b86fb4d5-bb9f-491f-93df-1dc79b9e6ee7','再和呈二首  其一','呂南公','宋','宋诗','song-poetry','','[]','五畝之園未種桑，自憐疏懶致財傷。',64,'全唐诗/poet.song.58000.json','["五畝之園未種桑，自憐疏懶致財傷。", "稻粱只是同鷄鶩，皮鞟徒勞勝犬羊。", "敢羨蘇秦終富貴，正憂郗鑒遇饑荒。", "遭承若值開元日，何卹東南萬里糧。"]'),
('3d53dca4-9d7e-4440-900a-20afc0cb5e6f','再和呈二首  其二','呂南公','宋','宋诗','song-poetry','','[]','茂林修竹舊時鄉，爭得安閒兩鬢蒼。',64,'全唐诗/poet.song.58000.json','["茂林修竹舊時鄉，爭得安閒兩鬢蒼。", "長憶樵漁有山澗，豈論勳業到旂常。", "兒童好在今初見，故舊尋來半已亡。", "此意不堪頻念慮，便傾襟抱付深觴。"]'),
('a418c7c5-715e-4193-84fe-c789c0844f37','再用前韵奉贈升卿三十一丈  其一','呂南公','宋','宋诗','song-poetry','','[]','百年此地有維桑，後慶唯公免物傷。',64,'全唐诗/poet.song.58000.json','["百年此地有維桑，後慶唯公免物傷。", "早歲懿文如鸑鷟，一生純德似羔羊。", "人推奧學追三篋，自許寬巾貯八荒。", "冷笑村田諸父老，滿胸茅塞只貲糧。"]'),
('23cd63a4-38ec-4e6b-aff3-a94675a37ee3','再用前韵奉贈升卿三十一丈  其二','呂南公','宋','宋诗','song-poetry','','[]','好德年高富且康，就中多福荷穹蒼。',64,'全唐诗/poet.song.58000.json','["好德年高富且康，就中多福荷穹蒼。", "吟哦有得能千首，議論無窮只五常。", "此日鄉閭獲矜式，異時風化免銷亡。", "嗟余欲買西鄰住，歲爲先生祝壽觴。"]'),
('d28023bc-e78c-4eb2-ab92-8c3fd214db89','金陵遞中示到亨父老丈去年秋初見寄詩書捧詠無窮之意不勝私感因成四韵奉呈','呂南公','宋','宋诗','song-poetry','','[]','郵籤初發去年書，嘆息貧窮未破除。',64,'全唐诗/poet.song.58000.json','["郵籤初發去年書，嘆息貧窮未破除。", "乞食君方如檻虎，賊糧我亦似卑居。", "有求自恨傷生酷，多難誰能慮事疏。", "同病相憂古來語，此情今日好欷歔。"]'),
('24b1c18a-c50d-4125-8b97-32ea33a86e73','九月一日口號奉呈顯翁文叔','呂南公','宋','宋诗','song-poetry','','[]','九秋未盡六秋窮，露冷風高爽氣雄。',64,'全唐诗/poet.song.58000.json','["九秋未盡六秋窮，露冷風高爽氣雄。", "無事日成多事過，故鄉身與異鄉同。", "心隨酒盞歸愁外，眼對時花到夢中。", "鴻雁已南吾漸北，自憐安穩愧龐公。"]'),
('14ce1707-d551-476b-894d-3351f36cd120','次韵酬朱推官','呂南公','宋','宋诗','song-poetry','','[]','上國輝光不許觀，故園岑寂且閒眠。',64,'全唐诗/poet.song.58000.json','["上國輝光不許觀，故園岑寂且閒眠。", "無心自可齊窮達，有口皆能論聖賢。", "百本柔桑繞茅屋，一陂清水灌沙田。", "餘生飽暖聊依此，豈有高風遠市廛。"]'),
('8e2edaea-9815-44a1-bd59-06b5fdc06a6f','寄酒伴唐彥君益','呂南公','宋','宋诗','song-poetry','','[]','門外水渠鳴漉漉，屋頭桐葉落翩翩。',64,'全唐诗/poet.song.58000.json','["門外水渠鳴漉漉，屋頭桐葉落翩翩。", "向來苦旱難尋井，及此愁霖易怨天。", "數盞舊藏真糯液，一盤初爛壯牛肩。", "故人忙迫城隍遠，獨息書床又醉眠。"]'),
('4a225479-fb35-4455-b729-c3db2b826341','得鄉信','呂南公','宋','宋诗','song-poetry','','[]','鄉信迢迢出舊山，琴心先落斷弦間。',64,'全唐诗/poet.song.58000.json','["鄉信迢迢出舊山，琴心先落斷弦間。", "數行文字傳新事，幾段悲歡破客顔。", "聞喜竹林經雪好，想憐溪水逐年閒。", "征衫有淚歸無計，一夜窮魂趁夢還。"]'),
('44b38a8d-7990-4b37-a8bf-7fb063c757dc','過聶彥倫故宅','呂南公','宋','宋诗','song-poetry','','[]','彥倫門外舊城牆，雉堞崩銷草木荒。',64,'全唐诗/poet.song.58000.json','["彥倫門外舊城牆，雉堞崩銷草木荒。", "人物已成塵土去，風烟猶與歲時長。", "綠衫科第何曾貴，白髮詩書不可常。", "平昔往還吾亦預，經過此日倍凄凉。"]'),
('adbc90f1-6448-4183-a79f-6076dc901d49','范十七司理見問歲除鰍蔬夜飲之約新春愆爽以八句答之','呂南公','宋','宋诗','song-poetry','','[]','田泥渙爛鰍懷子，圃壟肥腴菜長心。',64,'全唐诗/poet.song.58000.json','["田泥渙爛鰍懷子，圃壟肥腴菜長心。", "僧鑊縱然忘忌諱，書刀何忍屢殘淫。", "村漁不遜財難動，澍雨無端草易深。", "拘束學官懶復懶，坐愁佳約未能尋。"]'),
('8cf541f0-a5bd-4bd7-9abd-2265399116a8','出都','呂南公','宋','宋诗','song-poetry','','[]','霜風吹背出皇都，大笑回頭謝酒壚。',64,'全唐诗/poet.song.58000.json','["霜風吹背出皇都，大笑回頭謝酒壚。", "楚國但聞悲棄璞，魯門那復辨真儒。", "百年風槩文終在，一世光榮意已無。", "乞得耕桑了疏野，太平何害有潜夫。"]'),
('71e872d5-c9df-403a-9ea2-77a0573bc87a','稚女','呂南公','宋','宋诗','song-poetry','','[]','衣無羅綺且貧清，口有詩書亦性靈。',64,'全唐诗/poet.song.58000.json','["衣無羅綺且貧清，口有詩書亦性靈。", "論客鬚多如反寇，笑爺帽破似窮伶。", "園中果熟心先動，案上盃傳眼更青。", "釵擬荆枝裙擬布，暮年吾活正凋零。"]'),
('61f31256-ee6e-4bf3-933f-61e38db37a3f','寄李居士','呂南公','宋','宋诗','song-poetry','','[]','三月山城歎旅窮，冷看豪士振澆風。',64,'全唐诗/poet.song.58000.json','["三月山城歎旅窮，冷看豪士振澆風。", "送花盤上春情重，賣酒壚前醉魄雄。", "鐘鼓聒眠崇佛廟，綺羅爭路拜神宮。", "此懷若向林泉說，又落仙翁大笑中。"]'),
('201e2c25-bec3-42d1-bfa6-4148dda80336','奉答顧言見寄新句二首  其一','呂南公','宋','宋诗','song-poetry','','[]','早年辛苦待飛翻，翅折無因達九關。',64,'全唐诗/poet.song.58000.json','["早年辛苦待飛翻，翅折無因達九關。", "更使襟靈憎市井，足知緣分在雲山。", "誰憐古學長無用，自幸餘生且就閒。", "多謝鹿鳴筵上友，解傳詩句慰衰顔。"]'),
('b18b053c-998d-47ff-b20d-7fb6a1988d9b','奉答顧言見寄新句二首  其二','呂南公','宋','宋诗','song-poetry','','[]','羨君肝膽壯難攀，不厭長安出入關。',64,'全唐诗/poet.song.58000.json','["羨君肝膽壯難攀，不厭長安出入關。", "探穴定期收虎子，採薇寧暇顧西山。", "盱衡自慶千年運，冷笑人求一日閒。", "乃肯題詩寄空谷，的於游舊有溫顔。"]'),
('6f6700b4-d011-4dd3-9973-89389d22b168','和酬道先賢良見寄新句','呂南公','宋','宋诗','song-poetry','','[]','中林獨往寡襟期，祗與耕桑治町畦。',64,'全唐诗/poet.song.58000.json','["中林獨往寡襟期，祗與耕桑治町畦。", "遲晚識君真幸會，生平於世似分携。", "未能捧履師黄石，且欲同歌效紫溪。", "郡閣郊園遥百里，未妨懷寄屢封題。"]'),
('c15f7250-4bd1-454b-b768-800ec47bd932','池口阻風奉寄唐傑','呂南公','宋','宋诗','song-poetry','','[]','貴池亭下浪如山，觸撥愁根阻檝間。',64,'全唐诗/poet.song.58000.json','["貴池亭下浪如山，觸撥愁根阻檝間。", "眼爲故人成北望，夢知鄉路數東還。", "此生太半淪憂患，萬事何時脫險艱。", "不敢臨流更窺影，便疑秋鬢已斑斑。"]'),
('4fdfd227-f37f-441a-b828-98abc421d3ef','子發移令上高','呂南公','宋','宋诗','song-poetry','','[]','兩州三載屈參卿，百里初來福困甿。',64,'全唐诗/poet.song.58000.json','["兩州三載屈參卿，百里初來福困甿。", "無處不思逃濁暗，此邦何幸得賢明。", "後生智足科防密，凶歲財傷性命輕。", "能爲愛人忘富貴，豈徒循吏有佳聲。"]'),
('60642da1-c653-4067-8230-5ab634a407e3','有懷溪齋奉寄微之','呂南公','宋','宋诗','song-poetry','','[]','溪光清媚四山稠，十五年前記薄遊。',64,'全唐诗/poet.song.58000.json','["溪光清媚四山稠，十五年前記薄遊。", "茆屋讀書風滿座，野橋尋酒月當頭。", "身名不分輕如夢，甲歷誰令過若流。", "此地主人相問否，一廛今带百端憂。"]'),
('5f438dcf-7ff0-4d15-a47f-f9f1620e1c78','題陶集','呂南公','宋','宋诗','song-poetry','','[]','未讀陶詩已愛閒，自從能讀轉思山。',64,'全唐诗/poet.song.58000.json','["未讀陶詩已愛閒，自從能讀轉思山。", "烟霞合定徘徊分，塵土剛侵勉强顔。", "伊昔有人安白屋，祗今何事慕青綸。", "披簑戴笠終當去，更在規謀俛仰間。"]'),
('4d5ab76b-2561-45fc-8ec0-78fc31e204b7','豫章城','呂南公','宋','宋诗','song-poetry','','[]','西山東下古池隍，增飾依稀問晚唐。',64,'全唐诗/poet.song.58000.json','["西山東下古池隍，增飾依稀問晚唐。", "平世但嚴民筦鑰，亂時曾是賊金湯。", "春歸舊堞多芳草，鳥聚荒陴正夕陽。", "也欲登臨賦風物，自憐才筆厭憂傷。"]'),
('cc10cdf3-85e6-49db-bd28-5543673f1126','曉過城隍街馬上看木芙蓉','呂南公','宋','宋诗','song-poetry','','[]','秋來風味苦闌珊，偶爲繁紅略據鞍。',64,'全唐诗/poet.song.58000.json','["秋來風味苦闌珊，偶爲繁紅略據鞍。", "何處更期征雁過，祗今聊作故人看。", "三冬已至休爭氣，九月將殘未覺寒。", "自有榮華趁時節，免將憔悴惜幽蘭。"]'),
('9410b7cd-7c05-4f99-9ee6-39373e72a4f1','八月十四夜小雨','呂南公','宋','宋诗','song-poetry','','[]','小雨遮空意未迴，輕風迎夜勢初來。',64,'全唐诗/poet.song.58000.json','["小雨遮空意未迴，輕風迎夜勢初來。", "青樓月好人何在，錦帳燈寒扇自開。", "四七功名真土芥，一千期運亦烟埃。", "會須放縱雲雷手，不到人間有剩才。"]'),
('12fa0e05-3e92-40d2-adf9-84ab500f8e1d','高賦亭二首  其一','呂南公','宋','宋诗','song-poetry','','[]','耳外蜩螗響切纔，眼前岡麓秀環迴。',64,'全唐诗/poet.song.58000.json','["耳外蜩螗響切纔，眼前岡麓秀環迴。", "曦光墮地收風盡，雲脚遮山送雨來。", "長恐易成多事恨，可憐難見絕塵才。", "何由上得崑崙頂，試使煩襟磊落開。"]'),
('2b3c8b0b-0809-45e1-bb52-4252a87af9ec','高賦亭二首  其二','呂南公','宋','宋诗','song-poetry','','[]','事變紛紛不可防，祇應人世惡憂傷。',64,'全唐诗/poet.song.58000.json','["事變紛紛不可防，祇應人世惡憂傷。", "高情易與時風背，遠慮空爲智士忙。", "感古有懷成戚戚，就書圖活得遑遑。", "貧窮到處乖悰况，不但他鄉異故鄉。"]'),
('37b4a8a1-3abc-49ed-831b-65eac887aac3','將歸南城留別高賦亭二首  其一','呂南公','宋','宋诗','song-poetry','','[]','一上高亭一慘然，飄流無狀見風烟。',64,'全唐诗/poet.song.58000.json','["一上高亭一慘然，飄流無狀見風烟。", "林泉本是儂家分，衣食剛爲此世牽。", "流水嶺雲能自得，樵歌谷響遠相連。", "來時祇恐禽魚笑，掩斂南華第一篇。"]'),
('461e8651-8212-4935-b273-cb6525707d41','將歸南城留別高賦亭二首  其二','呂南公','宋','宋诗','song-poetry','','[]','寄食官齋過一期，登臨容易此階梯。',64,'全唐诗/poet.song.58000.json','["寄食官齋過一期，登臨容易此階梯。", "四時光景非無樂，千里憂傷却自迷。", "曠望可能舒感慨，幽吟長是寫酸嘶。", "從今風物多清暇，免被書生掩淚題。"]'),
('f29e3f25-22ea-4209-833b-eeafaaf8bc32','清明日再題高賦亭','呂南公','宋','宋诗','song-poetry','','[]','二年來作旅行人，節物相逢但感情。',64,'全唐诗/poet.song.58000.json','["二年來作旅行人，節物相逢但感情。", "彭蠡湖邊看競渡，摐陽山畔過清明。", "游神杳默皆愁意，傾耳尋常得恨聲。", "若有桑麻三畝地，肯將高跡學蓬萍。"]'),
('60b28e94-c3cc-40bc-934f-da900788dd1e','送子發赴江州司理','呂南公','宋','宋诗','song-poetry','','[]','湓江湛湛照闉闍，廬岳蟠蟠蔭郭郛。',64,'全唐诗/poet.song.58000.json','["湓江湛湛照闉闍，廬岳蟠蟠蔭郭郛。", "此地一官雖鬰屈，異人當日亦踟躕。", "元規樓下隨紅旆，居易祠前看白鬚。", "才調似君真不薄，有詩無吝寄雲夫。"]'),
('33554edf-d0d1-4efe-944c-855d64710a12','寄范司理','呂南公','宋','宋诗','song-poetry','','[]','郡南郡北叫呼間，硯席相望聚首難。',64,'全唐诗/poet.song.58000.json','["郡南郡北叫呼間，硯席相望聚首難。", "笑我性靈偏忍餓，憐君風韵似無官。", "儻來富貴能多與，不朽文章倍好看。", "莫怪參尋頗疏緩，鞋穿衣薄怯霜寒。"]'),
('f4cb980b-8afc-432a-baa0-f49ad32ed885','送張司理','呂南公','宋','宋诗','song-poetry','','[]','三年頻說獄空虛，歎息賢才治有餘。',64,'全唐诗/poet.song.58000.json','["三年頻說獄空虛，歎息賢才治有餘。", "曉踏府塵鈴窅眇，夜吟庭月樹扶疏。", "尚微官職人皆有，已大精神衆不如。", "努力無忘建功業，禿毫他日爲君書。"]'),
('1dba0da9-19e1-4b73-aaec-2ce4beef7c10','感懷奉呈純父','呂南公','宋','宋诗','song-poetry','','[]','去年三月出京關，汴水東奔不可寬。',64,'全唐诗/poet.song.58000.json','["去年三月出京關，汴水東奔不可寬。", "今歲此時還逆旅，牡丹開盡未曾看。", "春風祇管添鬚髮，世事爭來觸肺肝。", "傳語百憂休恣橫，已因泉石著南冠。"]'),
('cb7127e2-e613-4cdc-a025-46d3f8162301','次韵彥臣感懷','呂南公','宋','宋诗','song-poetry','','[]','不得經綸輔太平，枉於天地荷生成。',64,'全唐诗/poet.song.58000.json','["不得經綸輔太平，枉於天地荷生成。", "少如賈誼頻垂涕，老似樊須請學耕。", "醉舞或將猴共勢，饑吟時與蚓同聲。", "若教眼底不識字，應已脫除窮困名。"]'),
('d947c8ca-a45b-40d2-9544-74e4975186b4','過湖口','呂南公','宋','宋诗','song-poetry','','[]','野客西來意緒勞，爲停征棹到亭皋。',64,'全唐诗/poet.song.58000.json','["野客西來意緒勞，爲停征棹到亭皋。", "湖山氣象皆清曠，名利襟懷自鬰陶。", "曉市魚多腥萬鼻，晚波風健趁千艘。", "高情未有分張處，愁誦山移一兩遭。"]'),
('e1a0930e-e863-4bdd-abf7-f7d0b9d1927d','偶書所懷','呂南公','宋','宋诗','song-poetry','','[]','鳳凰亭上倚層軒，桃李分香到几筵。',64,'全唐诗/poet.song.58000.json','["鳳凰亭上倚層軒，桃李分香到几筵。", "曾與故人同一飲，試思前事已三年。", "歌懽舊興知何在，衰颯新愁祇自憐。", "縱使春風容病跡，亦貪窗下枕書眠。"]'),
('893f1f71-abdb-4f89-bd40-4acfc79b25d5','奉和內翰太中建昌三見梅花','呂南公','宋','宋诗','song-poetry','','[]','三見梅花似故人，楚鄉春是洛陽春。',64,'全唐诗/poet.song.58000.json','["三見梅花似故人，楚鄉春是洛陽春。", "蘸盃酒意枝枝重，入筆詩情處處新。", "南野幽林尋去遠，西園高樹繞來頻。", "無心草木窮山裏，還解遭逢侍從臣。"]'),
('522bc762-7b3f-4d88-badb-4bca54d3c68e','登滕王閣','呂南公','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','韋君德政滿洪州，去後無人更講求。',64,'全唐诗/poet.song.58000.json','["韋君德政滿洪州，去後無人更講求。", "帝子驕奢起高閣，到今連歲爲增修。", "座中簫鼓來無定，檻外帆檣過不休。", "惆悵幽懷誰與問，水長山遠總關愁。"]'),
('339ab946-5f14-4e5c-9b66-20866a8a7f34','書邊','呂南公','宋','宋诗','song-poetry','','[]','勞佚由來命不同，悠悠身事幾時窮。',64,'全唐诗/poet.song.58000.json','["勞佚由來命不同，悠悠身事幾時窮。", "學能愛日終無補，愁解迎春却有功。", "千慮漫游言語外，寸心常在苦辛中。", "故應樽酒憐顦顇，會借書邊醉頰紅。"]'),
('72a13e59-9897-42a8-aac7-265cc5c26650','風雨','呂南公','宋','宋诗','song-poetry','','[]','春來未苦狂風雨，初見雲雷氣象豪。',64,'全唐诗/poet.song.58000.json','["春來未苦狂風雨，初見雲雷氣象豪。", "合雜忽如喬岳倒，迷冥不辨九天高。", "林巒偃亞傳雄韵，溝澗蒼茫起怒濤。", "花卉一空何足問，且欣餘潤入耕皋。"]'),
('286efa80-7f58-43c0-9b98-fb1e9e85cceb','哭鄧氏女兄  其一','呂南公','宋','宋诗','song-poetry','','[]','東田嶂下古荒村，又向荆榛占一墳。',64,'全唐诗/poet.song.58000.json','["東田嶂下古荒村，又向荆榛占一墳。", "寒苦到今初是了，榮枯從此更休分。", "棺旁乳女隨遺褓，膝下亡男恨白雲。", "共係人間酸鼻事，欲言聊復淚紛紛。"]'),
('e21d9acc-8eb8-4bed-b5c1-ff2ae15e5e26','哭鄧氏女兄  其二','呂南公','宋','宋诗','song-poetry','','[]','凄凉三十六青春，歎息從人只累身。',64,'全唐诗/poet.song.58000.json','["凄凉三十六青春，歎息從人只累身。", "內外諸門方破碎，初終兩姓却沉淪。", "平生尚未諳奢泰，已病猶能强補紉。", "便向夜臺逢考妣，應傳同氣各邅迍。"]'),
('fb7ee59e-3d19-4024-9a6c-587b638b5802','答道先寄酒柴荆','呂南公','宋','宋诗','song-poetry','','[]','江州雙酎到籬東，快殺陶家寂寞翁。',64,'全唐诗/poet.song.58000.json','["江州雙酎到籬東，快殺陶家寂寞翁。", "田野放懷容易老，篇章寫意敢言工。", "漸生耳外燻烘熱，轉覺盃間瀲灧空。", "何必籃輿依五柳，久來身世醉鄉中。"]'),
('e0ce9309-cc1f-4310-b234-3e6643995817','己未上元宿崇相山寺','呂南公','宋','宋诗','song-poetry','','[]','七十年華已半除，新春猶復感窮途。',64,'全唐诗/poet.song.58000.json','["七十年華已半除，新春猶復感窮途。", "腸便酒味雖如舊，眼對花枝只似無。", "計畫但求閒次第，文章知是枉功夫。", "滿城燈火笙歌沸，獨訪東山宿佛圖。"]'),
('485749f4-9af1-4c7a-845f-b98e14b0ada8','陪道先兄游麻源輒賦二小詩  其一','呂南公','宋','宋诗','song-poetry','','[]','借得籃輿便出城，山光門外望西行。',64,'全唐诗/poet.song.58000.json','["借得籃輿便出城，山光門外望西行。", "昨宵偶雨路塵少，今日好風林靄輕。", "有竹人家庭院秀，避騶樵客面顔生。", "溪田橋北駝鞍嶺，猶記當年志未平。"]'),
('5d31576c-c0a5-4a4d-86f9-716bc207f838','陪道先兄游麻源輒賦二小詩  其二','呂南公','宋','宋诗','song-poetry','','[]','十五年前膽氣麤，擬將文字換金珠。',64,'全唐诗/poet.song.58000.json','["十五年前膽氣麤，擬將文字換金珠。", "科場委頓成何事，耕稼辛勤落晚途。", "累歲不曾言石磴，居山空道有茅廬。", "今朝碧澗潺湲響，若不因公得聽無。"]'),
('24f27215-6345-4691-aec2-1703ad6da305','永定東軒望浄土芭蕉','呂南公','宋','宋诗','song-poetry','','[]','高叢獵獵畫簷西，曾聽寒聲慘淡吹。',64,'全唐诗/poet.song.58000.json','["高叢獵獵畫簷西，曾聽寒聲慘淡吹。", "午枕有懷疏雨後，夜燈無語惡風時。", "二年成別應多恨，此日凭高動所思。", "人世不堪謀慮遠，眼前容易得傷悲。"]'),
('1a58b06f-bfeb-460a-ada4-482e3825525b','過游源驛','呂南公','宋','宋诗','song-poetry','','[]','游源驛裏壁間詩，去歲經過一覽時。',64,'全唐诗/poet.song.58000.json','["游源驛裏壁間詩，去歲經過一覽時。", "客子面皮真鐵鑄，閒人公論是靈旂。", "有誰謔浪慵開口，只我哀憐爲斂眉。", "多謝縣侯新蕩滌，從今莫恨放行遲。"]'),
('c728558f-d220-4bba-b5e3-64d60d8a210a','池塘','呂南公','宋','宋诗','song-poetry','','[]','池塘春草夏仍多，更照層林發翠波。',64,'全唐诗/poet.song.58000.json','["池塘春草夏仍多，更照層林發翠波。", "到處風光長好在，座中愁客奈情何。", "眼隨高鳥尋鄉思，手把閒書養睡魔。", "誰使早蟬能觸撥，新聲來與斷腸和。"]'),
('f46f8157-c6f5-4a74-8689-10d5c5180935','次韵濟道見寄  其一','呂南公','宋','宋诗','song-poetry','','[]','君作王官傚衆儒，尚逢廊廟有爲初。',64,'全唐诗/poet.song.58000.json','["君作王官傚衆儒，尚逢廊廟有爲初。", "塵中白日雖牽逼，筆下清風肯破除。", "欲去定成賢者隠，未歸嘗與俗流疏。", "人生到處隨榮願，何必江湖勝漆沮。"]'),
('5fe5bb1c-1c11-4018-88ed-b86478a9b96c','次韵濟道見寄  其二','呂南公','宋','宋诗','song-poetry','','[]','追送城東但立談，當時惜別恨騑驂。',64,'全唐诗/poet.song.58000.json','["追送城東但立談，當時惜別恨騑驂。", "一封消息難頻到，千里傾思只坐諳。", "知有才謀當奮發，豈於州縣却悲慚。", "爲文尚喜多餘暇，寄我新詩似渭南。"]'),
('a0698873-f8fa-470d-b281-96adff6bfd2a','過莊子祠堂','呂南公','宋','宋诗','song-poetry','','[]','客過蒙城日欲曛，更尋祠館拜遺真。',64,'全唐诗/poet.song.58000.json','["客過蒙城日欲曛，更尋祠館拜遺真。", "文章昔已悲衰世，香火今誰望俗人。", "諸子異端爭土苴，千秋餘亂見緣因。", "祗應叔夜輕狂輩，未是先生入室賓。"]'),
('4b6a6353-9889-4c69-82c4-33eaab499e3d','奉寄蕪湖征局都曹','呂南公','宋','宋诗','song-poetry','','[]','不見銅陵唱和翁，相望三度歎秋風。',64,'全唐诗/poet.song.58000.json','["不見銅陵唱和翁，相望三度歎秋風。", "商量難得樽罍共，存問空煩簡札通。", "馿上閬仙邀苦思，草中田子建微功。", "明年官滿當携手，未定韓郎耳便聾。"]'),
('d40767c4-bf4d-4e42-b509-94f7b7f8058a','梳頭見白髮','呂南公','宋','宋诗','song-poetry','','[]','未老先斑豈自由，可憐蒲柳易驚秋。',64,'全唐诗/poet.song.58000.json','["未老先斑豈自由，可憐蒲柳易驚秋。", "不緣遷染應非俗，若有梯媒必是愁。", "老蝨縱嫌相間別，素絲何害共風流。", "塵勞興味吾諳盡，肯似豪人諱白頭。"]'),
('5a6ac645-77e9-4d05-8b31-0762f29368f3','黄九游河州','呂南公','宋','宋诗','song-poetry','','[]','黄河東背賀蘭山，迴望塵沙萬里寬。',64,'全唐诗/poet.song.58000.json','["黄河東背賀蘭山，迴望塵沙萬里寬。", "土地久傳戎種姓，人民還笑漢衣冠。", "軍中意氣誰先得，史上功名我慣看。", "何日歸來談將略，轉吾愁面入忻懽。"]'),
('bd3b5b51-d268-4fb1-9fc0-14bb4b6b6341','六月二十七日醉書普安院壁','呂南公','宋','宋诗','song-poetry','','[]','酉尋行甫戌已見，夜候顯翁朝乃來。',64,'全唐诗/poet.song.58000.json','["酉尋行甫戌已見，夜候顯翁朝乃來。", "隔樹鳴蟬休聒耳，滿樽浮蟻且銜盃。", "多憂莫道無由解，一醉從初不用催。", "傳語羣書未乖間，只今相憶尚須迴。"]'),
('91b2b5ad-b46f-43ad-ac97-7ebe5f9f854e','題河源諸兄壁','呂南公','宋','宋诗','song-poetry','','[]','不見諸兄十載稀，重來問事只傷悲。',64,'全唐诗/poet.song.58000.json','["不見諸兄十載稀，重來問事只傷悲。", "一家未有中興地，兩地皆成永感時。", "道在莫虧清白業，力微空賦鶺鴒詩。", "吾門舊慶天如報，會向層霄得桂枝。"]'),
('831235fc-3bb0-472c-b1b4-53408c4956cd','將離東洲書社留題屋壁','呂南公','宋','宋诗','song-poetry','','[]','偶向林間寄病軀，七看圓缺印蟾蜍。',64,'全唐诗/poet.song.58000.json','["偶向林間寄病軀，七看圓缺印蟾蜍。", "何言霧隠南山豹，只得人憐涸轍魚。", "衮衮光陰添一夢，勞勞精幹落羣書。", "揚雄若有閒名在，此地曾經寂寞居。"]'),
('4f81b354-8a13-469e-98d4-91de4a3964eb','將歸南城書內樂堂壁','呂南公','宋','宋诗','song-poetry','','[]','野客辭鄉道轉孤，祗於愁上進工夫。',64,'全唐诗/poet.song.58000.json','["野客辭鄉道轉孤，祗於愁上進工夫。", "乞衣借食虧豪氣，弄筆翻書滯壯圖。", "三徑未成真隠約，五窮爭現主人迂。", "南歸漫過庚桑國，不得留參鞅掌徒。"]'),
('60c158ac-2f67-4e25-9d76-413c29186f4c','己酉歲歸省松楸過武陵翁所居留書屋壁','呂南公','宋','宋诗','song-poetry','','[]','千里歸來儘苦辛，見君依舊自由身。',64,'全唐诗/poet.song.58000.json','["千里歸來儘苦辛，見君依舊自由身。", "始知絕學無文者，勝却翻書弄筆人。", "案上方經閒白日，門前車馬漫紅塵。", "半軒風竹一樽酒，冷笑世途爭富貧。"]'),
('72b0e365-61e7-400c-af08-345f87f23db2','憶西村','呂南公','宋','宋诗','song-poetry','','[]','東岡西下古墩頭，草木風烟事事幽。',64,'全唐诗/poet.song.58000.json','["東岡西下古墩頭，草木風烟事事幽。", "畦壠彎環延果菜，笭箵參互獻魚鰍。", "常開夜戶誇無寇，競撥香醅賀有秋。", "願定此居猶未得，豈堪僥倖望公侯。"]'),
('9748f6a3-a739-4a9d-a33b-2387a56e19b2','鍾南平祠像','呂南公','宋','宋诗','song-poetry','','[]','天祿空虛土運崩，匹夫徒手起欃槍。',64,'全唐诗/poet.song.58000.json','["天祿空虛土運崩，匹夫徒手起欃槍。", "還將有限驍雄力，換得無窮跋扈名。", "已是用心貪禍亂，尚何顔面見昇平。", "丹青此日凝埃色，尚似憂慚問罪兵。"]'),
('9ba74907-0067-44fe-be5f-00db8368d7a0','寄黄夢授機宜','呂南公','宋','宋诗','song-poetry','','[]','少年秋賦險橫飛，晚去從軍脫布衣。',64,'全唐诗/poet.song.58000.json','["少年秋賦險橫飛，晚去從軍脫布衣。", "只見鄉評推孝行，豈知俗效在兵機。", "黄雲古渭邊烽斷，春草臨洮戰馬肥。", "了取功名上麟閣，莫因晝錦苦思歸。"]'),
('cb966c81-c156-41d4-aea2-bd4b832ed7dc','得唐彥迴篇再寄','呂南公','宋','宋诗','song-poetry','','[]','手把封題又慘然，坐驚新句俊翩翩。',64,'全唐诗/poet.song.58000.json','["手把封題又慘然，坐驚新句俊翩翩。", "窮通可是俱關命，聚散由來亦繫天。", "此日未逃衰俗口，幾時真及古人肩。", "一樽酩酊難頻共，况望青綾被底眠。"]'),
('f4628804-2425-4dc2-9602-334c7350e682','聞唐彥君益作計相過先以此寄用前韵','呂南公','宋','宋诗','song-poetry','','[]','見說東征計决然，夢魂迎馬去翩翩。',64,'全唐诗/poet.song.58000.json','["見說東征計决然，夢魂迎馬去翩翩。", "遥憐迢遞荒村路，幸對溫和此日天。", "意厚但青貧友眼，裝輕肯赤僕夫肩。", "書編酒盞蒲團坐，預擬中宵未放眠。"]'),
('3b14c4f2-b2fa-424a-b903-88287a63337f','緘題道先詩句尚多未和酬者因書短律奉寄','呂南公','宋','宋诗','song-poetry','','[]','已作醉鄉貧戶限，更逢詩匠惡穿裁。',64,'全唐诗/poet.song.58000.json','["已作醉鄉貧戶限，更逢詩匠惡穿裁。", "王弘一酎何曾送，崔立千篇不住來。", "枕上精神難託夢，床頭卷軸易成堆。", "賀蘭溪上如歸去，省得衰翁合勺才。"]'),
('a7f74607-d866-485a-9e54-a800c9c3e30b','寄鄧師厚二首  其一','呂南公','宋','宋诗','song-poetry','','[]','茅屋分携但偶然，蟾光今已十回圓。',64,'全唐诗/poet.song.58000.json','["茅屋分携但偶然，蟾光今已十回圓。", "自存交分長長在，不用音書疊疊傳。", "無術入時猶是命，有身多病豈非天。", "倦遊已作南歸計，只待槐梢沸早蟬。"]'),
('cdc86e13-3010-441b-bc4f-ceb8b901e11d','寄鄧師厚二首  其二','呂南公','宋','宋诗','song-poetry','','[]','庾嶺前頭梅散漫，灊山東下水漼溰。',64,'全唐诗/poet.song.58000.json','["庾嶺前頭梅散漫，灊山東下水漼溰。", "二年時節俱爲客，千里家山各未歸。", "俛睫游從真醜謬，方頭言論易乖違。", "人間勝事知多少，專把凄凉屬布衣。"]'),
('1fcfc80b-c23f-4686-8694-c02fd667cfd6','金陵寄示亨父','呂南公','宋','宋诗','song-poetry','','[]','東游西上但差參，寒餓催軀失本心。',64,'全唐诗/poet.song.58000.json','["東游西上但差參，寒餓催軀失本心。", "多難有言悲運命，厭貧無意惜光陰。", "窮通未定功名主，疾病能將少壯侵。", "故國漁樵應可入，寄聲先爲問雲林。"]'),
('2c347098-be19-4efc-9a61-7146b4ed50d7','寄亨父','呂南公','宋','宋诗','song-poetry','','[]','當年勇慕古人風，坎壈無由到澤宮。',64,'全唐诗/poet.song.58000.json','["當年勇慕古人風，坎壈無由到澤宮。", "力命不容相鬭競，光陰從此便和同。", "身如孟氏兼三樂，家似昌黎厭五窮。", "莫爲明時頗惆悵，著書亦是濟時功。"]'),
('2a3edc14-d6f7-4ecd-b329-8f49924318e1','再寄亨父','呂南公','宋','宋诗','song-poetry','','[]','匹馬辭家臘雪初，二年名姓入銓書。',64,'全唐诗/poet.song.58000.json','["匹馬辭家臘雪初，二年名姓入銓書。", "熊羆帥府招韓愈，邑里經筵失仲舒。", "穩把聲榮收雨露，冷看交舊厭溝渠。", "藍衣定有誇鄉日，爲到耕村問溺沮。"]'),
('5cd358cc-c656-4b8a-ab2c-f8a3166b3bc9','奉寄子發  其一','呂南公','宋','宋诗','song-poetry','','[]','春雷動地竹牙生，社雨淋岡蕨臂擎。',64,'全唐诗/poet.song.58000.json','["春雷動地竹牙生，社雨淋岡蕨臂擎。", "田野盃盤容我飽，牛羊鼎俎爲誰榮。", "能無智慮隨天轉，未有工夫與俗爭。", "苦憶南園江健令，解於忙處用閒情。"]'),
('6dc8d54a-0c69-41fa-a139-fcbd9ed926c3','奉寄子發  其二','呂南公','宋','宋诗','song-poetry','','[]','解於忙處用閒情，絕口多財與美名。',64,'全唐诗/poet.song.58000.json','["解於忙處用閒情，絕口多財與美名。", "剝啄至門方就枕，畢逋歸樹却催耕。", "燒香事佛人俱佞，曳屣歌詩我亦清。", "笋蕨又芳春酒冽，相思何計可同傾。"]'),
('800125ee-f284-4d11-bfa6-e0947f228f1e','戲題白鶴觀','呂南公','宋','宋诗','song-poetry','','[]','遼海沈沈信息稀，蒼松枯盡草侵扉。',64,'全唐诗/poet.song.58000.json','["遼海沈沈信息稀，蒼松枯盡草侵扉。", "樓臺有字知年歲，城郭無人辨是非。", "像座風輕蛛作網，醮壇春老蘚成圍。", "道翁久蓄瑶琴意，莫爲閒名取次揮。"]'),
('44ce9baa-0d24-4730-b9dd-ec644c5c77bf','南豐道中口占','呂南公','宋','宋诗','song-poetry','','[]','冷雨迷濛懶舉頭，望中恐得故鄉愁。',64,'全唐诗/poet.song.58000.json','["冷雨迷濛懶舉頭，望中恐得故鄉愁。", "梅經舊臘香猶在，水被東風凍已收。", "鳥喜春和紛格磔，馬嫌泥滑轉夷猶。", "人生祇有安居好，可奈安居不易求。"]'),
('abe85ffe-bd9c-46d2-962b-ae25e610d62a','野菜','呂南公','宋','宋诗','song-poetry','','[]','采采新英出遠岡，生香不斷冷垂漿。',64,'全唐诗/poet.song.58000.json','["采采新英出遠岡，生香不斷冷垂漿。", "地神手老皮先紫，山鬼腸饑色更蒼。", "野饌自宜清品味，世情誰識淡馨香。", "舊林春草盤飧慣，憶共鄰翁踞坐嘗。"]'),
('065a962c-0eec-4d71-9ff1-43f03df0194e','秋堂','呂南公','宋','宋诗','song-poetry','','[]','秋堂燈燭夜輝輝，照我書邊淚濕衣。',64,'全唐诗/poet.song.58000.json','["秋堂燈燭夜輝輝，照我書邊淚濕衣。", "何術更堪圖愜快，平生已是足乖違。", "悠悠客路和愁往，杳杳青山借夢歸。", "蟲響風鳴俱有恨，驚殘二十七年非。"]'),
('9b910f96-d742-4110-ae5e-6111faed94f2','過列岫軒輒題小詩','呂南公','宋','宋诗','song-poetry','','[]','檻前清沼一奩披，牆外橫山百馬肥。',64,'全唐诗/poet.song.58000.json','["檻前清沼一奩披，牆外橫山百馬肥。", "長使座中知爽氣，豈煩天際問脩眉。", "留賓出酒人皆喜，不語看雲衆未知。", "饒借俗儒譚爾雅，主公偏重謝家詩。"]'),
('5bce4d19-60c3-48c0-b3e0-79e7b08c4576','贈叔憲','呂南公','宋','宋诗','song-poetry','','[]','軒昂不肯事雕鎪，放却名韁已十秋。',64,'全唐诗/poet.song.58000.json','["軒昂不肯事雕鎪，放却名韁已十秋。", "舉世有爲皆負累，百年無悶更何求。", "長驅好意歸吟筆，笑領真風貯酒甌。", "嫌我生涯非濩落，紙編寒夜困燈油。"]'),
('86bb1d88-6c3e-41bb-a77f-03b79926cf57','贈王九','呂南公','宋','宋诗','song-poetry','','[]','李杜是非張相國，曹劉忌憚呂將軍。',64,'全唐诗/poet.song.58000.json','["李杜是非張相國，曹劉忌憚呂將軍。", "異時各有凌人氣，此日何妨負我文。", "議諭當如山頂石，光榮會似雨餘雲。", "恨君不悔邯鄲步，希世功夫枉十分。"]'),
('d13290cf-27f6-4b4a-acc1-86a2824edba0','塵土','呂南公','宋','宋诗','song-poetry','','[]','塵土營營自滿城，此間賞望四時清。',64,'全唐诗/poet.song.58000.json','["塵土營營自滿城，此間賞望四時清。", "朝看雲樹吟天末，夜對溪光醉月明。", "只見漁樵真氣象，豈知廛市細紛爭。", "座中更挂庸兒榻，未識冰壺有舊名。"]'),
('6e5d26fd-30f7-4694-afdf-1ff296dcca13','道卿上人新作塔亭准擬壽終乞余題詩','呂南公','宋','宋诗','song-poetry','','[]','道人八十轉康寧，却傚浮屠起竁亭。',64,'全唐诗/poet.song.58000.json','["道人八十轉康寧，却傚浮屠起竁亭。", "日月無窮終繫數，乾坤有壞亦因形。", "未張雲鶴蕭蕭影，先養松楸鬰鬰青。", "究竟會應逢逸少，爲師重勒雁門銘。"]'),
('de847703-7443-448c-90d1-065ca62c8e1a','寄觀上人','呂南公','宋','宋诗','song-poetry','','[]','袈裟初带帝城塵，便詠南陔望白雲。',64,'全唐诗/poet.song.58000.json','["袈裟初带帝城塵，便詠南陔望白雲。", "賈島未爲窮主簿，湯休何事小參軍。", "古書似我閒千卷，山酒從誰盡十分。", "正是諸生薄韓柳，勸師絕口莫言文。"]'),
('74deeb2f-2c22-4345-8a76-912ec51b1b8e','寄上山陽太守屯田','呂南公','宋','宋诗','song-poetry','','[]','故國無田只一瓢，儒冠相誤感萍漂。',64,'全唐诗/poet.song.58000.json','["故國無田只一瓢，儒冠相誤感萍漂。", "虞翻骨相終迍滯，許劭題評漫借饒。", "已養道心忘貴賤，故應榮分任漁樵。", "文章解頌賢人業，更坐看君立九霄。"]'),
('fd9dcd8a-5ae5-4ab8-bbee-c8d815780606','獻翰林太守','呂南公','宋','宋诗','song-poetry','','[]','欲辭鈴閣重徘徊，世路無人計實材。',64,'全唐诗/poet.song.58000.json','["欲辭鈴閣重徘徊，世路無人計實材。", "賓榻少因高士下，醴樽多向俗儒開。", "孤蹤此日叨餘論，直筆他年倚上台。", "召節不遲天陛遠，輟耕朝夕爲公來。"]'),
('59fc9130-dc59-4e42-8b82-2191a02eaac7','和酬道先高秋見寄之句','呂南公','宋','宋诗','song-poetry','','[]','眼看金菊木芙蓉，想見嚴城此景同。',64,'全唐诗/poet.song.58000.json','["眼看金菊木芙蓉，想見嚴城此景同。", "儒術凋零歸故紙，歲華催趁入衰翁。", "千秋治亂三鍾酒，萬里關河一畝宮。", "南鷂北鷹方得志，更誰迂闊問哀鴻。"]'),
('72bc39fa-7d8e-4995-9b60-c16bd76815dc','晚出壽春','呂南公','宋','宋诗','song-poetry','','[]','馬足遲遲破曉霜，朔風迎袖過川梁。',64,'全唐诗/poet.song.58000.json','["馬足遲遲破曉霜，朔風迎袖過川梁。", "簾櫳幾處迷醒魄，烟靄滿空含曙光。", "已是途程規進取，可能懷抱似鴻荒。", "平沙莽莽兵戈地，却爲千秋起弔傷。"]'),
('c15e93bd-42cb-4b0a-92e8-9c13a17ae65c','書齋春日','呂南公','宋','宋诗','song-poetry','','[]','花困蜂鶑柳困風，年年春恨渺無窮。',64,'全唐诗/poet.song.58000.json','["花困蜂鶑柳困風，年年春恨渺無窮。", "已添病格憂詩債，未破愁城憶酒功。", "日月正居勞苦上，山川長在夢魂中。", "游鞍賞席今多少，想見濃陰替亂紅。"]'),
('3686100f-4fe8-4af7-9089-73ffab95ca6b','和酬李宣德二首  其一','呂南公','宋','宋诗','song-poetry','','[]','銷閒堂上日何思，或弄鳴琴或賦詩。',64,'全唐诗/poet.song.58000.json','["銷閒堂上日何思，或弄鳴琴或賦詩。", "聲正只傳心靜處，篇成不待燭殘時。", "隆中有客吟梁甫，洛下無人說克兒。", "此日餘音到逋客，定如醫藥蓄青芝。"]'),
('dd072d85-657f-4d66-a951-5be65707c710','和酬李宣德二首  其二','呂南公','宋','宋诗','song-poetry','','[]','臨邛大邑少鴻生，初敬多辭馬長卿。',64,'全唐诗/poet.song.58000.json','["臨邛大邑少鴻生，初敬多辭馬長卿。", "幾許分財來滌器，不如收迹去躬耕。", "生前遇主無高位，死後遺文有盛名。", "畢竟負他賢令意，被人傳說是閑情。"]'),
('e8c3675a-b214-471e-bb7d-4dedb7c89f5b','次韵輝卿感春  其一','呂南公','宋','宋诗','song-poetry','','[]','日日春陰共慘然，愁懷不稱艷陽天。',64,'全唐诗/poet.song.58000.json','["日日春陰共慘然，愁懷不稱艷陽天。", "已從魯酒迷醒枕，更向瑶琴怯武弦。", "往事自驚千里夢，勝游誰犯五更烟。", "因君解道花如錦，始爲芳菲憶去年。"]');
